        function recordApiHealth(serviceId, status, message, details) {
            var health = getApiHealth();
            health[serviceId] = {
                status: status,
                message: message || '',
                details: details || null,
                timestamp: new Date().toISOString(),
                ttl: status === 'ok' ? 3600000 : 300000 // ok: 1hr, errors: 5min (check again sooner)
            };
            saveApiHealth(health);
        }
        
        function getServiceStatus(serviceId) {
            var health = getApiHealth();
            var entry = health[serviceId];
            if (!entry) return { status: 'unknown', message: 'No data yet', stale: false };
            var age = Date.now() - new Date(entry.timestamp).getTime();
            return {
                status: entry.status,
                message: entry.message,
                details: entry.details,
                timestamp: entry.timestamp,
                stale: age > (entry.ttl || 3600000)
            };
        }
        
        // ===== INCIDENT LOG =====
