        function logIncident(severity, feature, message, details) {
            var log = getIncidentLog();
            log.unshift({
                id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6),
                severity: severity, // 'critical' | 'warning' | 'info'
                feature: feature,   // e.g. 'linkedin-skill-infer', 'purpose-regen', 'firestore-save'
                message: message,
                details: details || null,
                timestamp: new Date().toISOString(),
                resolved: false
            });
            // Cap at max
            if (log.length > INCIDENT_MAX) log = log.slice(0, INCIDENT_MAX);
            saveIncidentLog(log);
            
            // Console output for visibility
            var prefix = severity === 'critical' ? '\u274C' : severity === 'warning' ? '\u26A0\uFE0F' : '\u2139\uFE0F';
            console.log(prefix + ' Incident [' + severity + '] ' + feature + ': ' + message);
        }
        
        function resolveIncidents(feature) {
            var log = getIncidentLog();
            var changed = false;
            log.forEach(function(inc) {
                if (inc.feature === feature && !inc.resolved) {
                    inc.resolved = true;
                    inc.resolvedAt = new Date().toISOString();
                    changed = true;
                }
            });
            if (changed) saveIncidentLog(log);
        }
        
