        async function callAnthropicAPI(requestBody, userApiKey, featureTag) {
            trackAICall(featureTag);
            var idToken = null;
            if (typeof firebase !== 'undefined' && firebase.auth && firebase.auth().currentUser) {
                try { idToken = await firebase.auth().currentUser.getIdToken(); } catch (e) { console.warn('Failed to get Firebase ID token:', e.message); }
            }
            if (idToken && AI_PROXY_AVAILABLE !== false) {
                var proxyApiError = null;
                try {
                    var proxyRes = await fetch(AI_PROXY_URL, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + idToken },
                        body: JSON.stringify(requestBody)
                    });
                    if (proxyRes.ok) {
                        AI_PROXY_AVAILABLE = true;
                        recordApiHealth('anthropic-proxy', 'ok', 'Operational');
                        return await proxyRes.json();
                    }
                    if (proxyRes.status === 429) {
                        AI_PROXY_AVAILABLE = true;
                        recordApiHealth('anthropic-proxy', 'degraded', 'Rate limited', { status: 429 });
                        throw new Error('Rate limit exceeded. Please wait a moment.');
                    }
                    // Capture actual error from proxy/Anthropic for 4xx errors
                    if (proxyRes.status >= 400 && proxyRes.status < 500) {
                        AI_PROXY_AVAILABLE = true;
                        var errBody = {}; try { errBody = await proxyRes.json(); } catch(e) {}
                        var errMsg = (errBody.error && typeof errBody.error === 'object' ? errBody.error.message : errBody.error) || 'AI request failed (status ' + proxyRes.status + ')';
                        console.error('AI Proxy ' + proxyRes.status + ':', errMsg, errBody);
                        var healthStatus = errMsg.includes('credit balance') ? 'down' : 'degraded';
                        var healthMsg = errMsg.includes('credit balance') ? 'Credits depleted' : 'Error: ' + errMsg;
                        recordApiHealth('anthropic-proxy', healthStatus, healthMsg, { status: proxyRes.status, error: errMsg });
                        if (errMsg.includes('credit balance')) {
                            logIncident('critical', 'anthropic-credits', 'API credits depleted. All AI features disabled until top-up.', { manageUrl: 'https://console.anthropic.com/settings/billing' });
                        }
                        proxyApiError = new Error(errMsg);
                    }
                    if (proxyRes.status >= 500) {
                        AI_PROXY_AVAILABLE = false;
                        recordApiHealth('anthropic-proxy', 'down', 'Server error', { status: proxyRes.status });
                        logIncident('critical', 'anthropic-proxy', 'AI proxy server error (HTTP ' + proxyRes.status + ')', { status: proxyRes.status });
                    }
                } catch (e) {
                    if (e.message.includes('Rate limit')) throw e;
                    if (AI_PROXY_AVAILABLE === null) {
                        AI_PROXY_AVAILABLE = false;
                        recordApiHealth('anthropic-proxy', 'down', 'Unreachable', { error: e.message });
                    }
                }
                // Throw 4xx errors after catch so they propagate to the caller
                if (proxyApiError) throw proxyApiError;
            }
            if (!userApiKey) throw new Error('AI features require sign-in or an API key in Settings.');
            var directRes = await fetch('https://api.anthropic.com/v1/messages', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'x-api-key': userApiKey, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true' },
                body: JSON.stringify(requestBody)
            });
            if (!directRes.ok) {
                var errData = {}; try { errData = await directRes.json(); } catch(e) {}
                if (directRes.status === 401) {
                    recordApiHealth('anthropic-direct', 'down', 'Invalid API key', { status: 401 });
                    throw new Error('Invalid API key. Check your key at console.anthropic.com.');
                }
                var directErr = (errData.error && errData.error.message) || 'AI request failed (status ' + directRes.status + ')';
                recordApiHealth('anthropic-direct', 'down', directErr, { status: directRes.status });
                throw new Error(directErr);
            }
            recordApiHealth('anthropic-direct', 'ok', 'Operational');
            return await directRes.json();
        }

        // Safe localStorage wrapper (handles private browsing, quota exceeded)
        function safeGet(key, fallback) {
            try { return localStorage.getItem(key); } catch(e) { return fallback || null; }
        }
        function safeSet(key, val) {
            try {
                localStorage.setItem(key, val);
                // Periodic quota check (~5% of writes)
                if (Math.random() < 0.05) {
                    var total = 0;
                    for (var i = 0; i < localStorage.length; i++) {
                        var k = localStorage.key(i);
                        total += (k.length + (localStorage.getItem(k) || '').length) * 2;
                    }
                    if (total > 4000000) { // 4MB warning (limit is ~5MB)
                        console.warn('localStorage usage high:', Math.round(total / 1024) + 'KB');
                        if (typeof logIncident === 'function') logIncident('warning', 'storage-quota', 'localStorage at ' + Math.round(total / 1048576 * 100) + '% capacity');
                    }
                }
                return true;
            } catch(e) {
                if (typeof logIncident === 'function') logIncident('warning', 'storage-quota', 'localStorage write failed for ' + key + ': ' + e.message);
                return false;
            }
        }
        function safeRemove(key) {
            try { localStorage.removeItem(key); } catch(e) {}
        }

        // ===== SECURITY: HTML SANITIZATION =====
        function escapeHtml(str) {
            if (str === null || str === undefined) return '';
            var div = document.createElement('div');
            div.appendChild(document.createTextNode(String(str)));
            return div.innerHTML;
        }

        function decodeHtmlEntities(str) {
            if (!str || typeof str !== 'string') return str || '';
            var decoded = str
                .replace(/&amp;/g, '&')
                .replace(/&lt;/g, '<')
                .replace(/&gt;/g, '>')
                .replace(/&quot;/g, '"')
                .replace(/&apos;/g, "'")
                .replace(/&ndash;/g, '\u2013')
                .replace(/&mdash;/g, '\u2014')
                .replace(/&nbsp;/g, ' ')
                .replace(/&#(\d+);/g, function(m, code) { return String.fromCharCode(parseInt(code, 10)); })
                .replace(/&#x([0-9a-fA-F]+);/g, function(m, code) { return String.fromCharCode(parseInt(code, 16)); });
            return decoded;
        }

        // Safe avatar image setter — uses DOM API to avoid innerHTML/template literal context bugs
        function safeSetAvatar(el, url, rounded) {
            if (!el) return;
            if (url) {
                var img = document.createElement('img');
                img.src = url;
                img.alt = '';
                img.style.cssText = 'width:100%;height:100%;object-fit:cover;' + (rounded ? 'border-radius:50%;' : '');
                el.innerHTML = '';
                el.appendChild(img);
            }
        }

        // ===== SECURITY: SAFE JSON PARSE =====
        function safeParse(str, fallback) {
            if (!str) return fallback !== undefined ? fallback : null;
            try { return JSON.parse(str); } catch(e) { return fallback !== undefined ? fallback : null; }
        }

        // ===== SECURITY: URL SANITIZER (M1) =====
        function sanitizeUrl(url) {
            if (!url || typeof url !== 'string') return '#';
            var trimmed = url.trim();
            if (/^https?:\/\//i.test(trimmed)) return trimmed;
            if (/^mailto:/i.test(trimmed)) return trimmed;
            return '#';
        }

        // ===== SECURITY: IMPORT VALIDATOR (C2) =====
        function sanitizeImport(raw) {
            if (!raw || typeof raw !== 'object') throw new Error('Invalid import: not an object');
            var allowed = ['profile','skills','roles','values','purpose','outcomes','preferences',
                'applications','workHistory','education','certifications','verifications',
                'savedJobs','initialized','templateId'];
            var clean = {};
            allowed.forEach(function(key) {
                if (raw[key] !== undefined) clean[key] = raw[key];
            });
            // Strip privileged fields
            delete clean.role;
            delete clean.isAdmin;
            // Sanitize profile strings
            if (clean.profile && typeof clean.profile === 'object') {
                Object.keys(clean.profile).forEach(function(k) {
                    if (typeof clean.profile[k] === 'string') {
                        clean.profile[k] = clean.profile[k].slice(0, 2000);
                    }
                });
            }
            // Sanitize skill names
            if (Array.isArray(clean.skills)) {
                clean.skills = clean.skills.filter(function(s) { return s && typeof s === 'object'; });
                clean.skills.forEach(function(s) {
                    if (typeof s.name === 'string') s.name = s.name.slice(0, 200);
                    if (typeof s.level === 'string') s.level = s.level.slice(0, 50);
                    if (typeof s.category === 'string') s.category = s.category.slice(0, 100);
                });
            }
            // Sanitize roles
            if (Array.isArray(clean.roles)) {
                clean.roles = clean.roles.filter(function(r) { return r && typeof r === 'object'; });
                clean.roles.forEach(function(r) {
                    if (typeof r.name === 'string') r.name = r.name.slice(0, 200);
                    if (typeof r.company === 'string') r.company = r.company.slice(0, 200);
                });
            }
            // Sanitize savedJobs URLs
            if (Array.isArray(clean.savedJobs)) {
                clean.savedJobs.forEach(function(j) {
                    if (j && j.sourceUrl) j.sourceUrl = sanitizeUrl(j.sourceUrl);
                });
            }
            return clean;
        }

        // ===== SECURITY: GLOBAL ERROR HANDLERS (H5, H4) =====
        window.onerror = function(msg, url, line, col, error) {
            try {
                if (typeof logIncident === 'function') {
                    logIncident('error', 'runtime', String(msg).slice(0, 200) + ' at line ' + line, { col: col, stack: error && error.stack ? error.stack.slice(0, 500) : '' });
                }
            } catch(e) {}
            return false;
        };
        window.addEventListener('unhandledrejection', function(event) {
            try {
                var reason = event.reason;
                var msg = (reason && reason.message) ? reason.message : String(reason);
                if (typeof logIncident === 'function') {
                    logIncident('warning', 'unhandled-promise', String(msg).slice(0, 200));
                }
            } catch(e) {}
        });

        // ===== STABILITY: SAVE DEBOUNCE (H3) =====
        var _saveDebounceTimer = null;
        function debouncedSave(delay) {
            if (_saveDebounceTimer) clearTimeout(_saveDebounceTimer);
            _saveDebounceTimer = setTimeout(function() {
                _saveDebounceTimer = null;
                saveToFirestore();
            }, delay || 2000);
        }

        // ===== SITE ANALYTICS TRACKER =====
        var bpTracker = {
            sid: null, vid: null, sessStart: null, curView: null, viewStart: null,
            viewTimes: {}, hbInterval: null, isNew: false,
            
            init: function() {
                this.vid = safeGet('bpVisitorId');
                if (!this.vid) {
                    this.vid = 'v_' + Date.now().toString(36) + '_' + Math.random().toString(36).substr(2, 6);
                    safeSet('bpVisitorId', this.vid);
                    this.isNew = true;
                }
                this.sid = 's_' + Date.now().toString(36) + '_' + Math.random().toString(36).substr(2, 4);
                this.sessStart = Date.now();
                
                this.log('session_start', { referrer: document.referrer || 'direct', isNew: this.isNew });
                this.log('device_info', { screenW: screen.width, screenH: screen.height,
                    vpW: window.innerWidth, vpH: window.innerHeight,
                    mobile: window.innerWidth <= 768,
                    dark: document.body?.classList?.contains('dark-theme') || window.matchMedia('(prefers-color-scheme: dark)').matches,
                    lang: navigator.language });
                
                var self = this;
                this.hbInterval = setInterval(function() { self.flush(); }, 30000);
                window.addEventListener('beforeunload', function() { self.end(); });
                document.addEventListener('visibilitychange', function() {
                    document.hidden ? self.pauseView() : self.resumeView();
                });
                
                var visits = parseInt(safeGet('bpVisitCount') || '0') + 1;
                safeSet('bpVisitCount', String(visits));
                safeSet('bpLastVisit', new Date().toISOString());
                if (!safeGet('bpFirstVisit')) safeSet('bpFirstVisit', new Date().toISOString());
            },
            
            trackView: function(v) {
                if (!v) return;
                if (this.curView && this.viewStart) {
                    var el = Math.round((Date.now() - this.viewStart) / 1000);
                    if (el > 0 && el < 3600) this.viewTimes[this.curView] = (this.viewTimes[this.curView] || 0) + el;
                }
                this.curView = v; this.viewStart = Date.now();
                this.log('page_view', { view: v });
            },
            
            pauseView: function() {
                if (this.curView && this.viewStart) {
                    var el = Math.round((Date.now() - this.viewStart) / 1000);
                    if (el > 0 && el < 3600) this.viewTimes[this.curView] = (this.viewTimes[this.curView] || 0) + el;
                    this.viewStart = null;
                }
            },
            resumeView: function() { if (this.curView) this.viewStart = Date.now(); },
            
            trackFeature: function(name, extra) { this.log('feature_use', Object.assign({ feature: name }, extra || {})); },
            
            trackFunnel: function(step) {
                this.log('funnel', { step: step });
                var order = ['visit','signup','profile_created','skills_added','first_job','report_generated'];
                var cur = safeGet('bpFunnelStep') || 'visit';
                if (order.indexOf(step) > order.indexOf(cur)) safeSet('bpFunnelStep', step);
            },
            
            flush: function() {
                var dur = Math.round((Date.now() - this.sessStart) / 1000);
                var d = this.getData(); var today = new Date().toISOString().slice(0, 10);
                if (!d.sessions[today]) d.sessions[today] = [];
                var found = false;
                for (var i = 0; i < d.sessions[today].length; i++) {
                    if (d.sessions[today][i].sid === this.sid) { d.sessions[today][i].dur = dur; d.sessions[today][i].vt = Object.assign({}, this.viewTimes); found = true; break; }
                }
                if (!found) d.sessions[today].push({ sid: this.sid, vid: this.vid, start: this.sessStart, dur: dur, vt: Object.assign({}, this.viewTimes), isNew: this.isNew });
                this.saveData(d);
            },
            
            end: function() { clearInterval(this.hbInterval); this.pauseView(); this.flush();
                var dur = Math.round((Date.now() - this.sessStart) / 1000);
                var pvCount = 0; var d = this.getData(); var today = new Date().toISOString().slice(0,10);
                var dpv = d.pageViews[today] || {}; Object.values(dpv).forEach(function(v){pvCount+=v;});
                this.log('session_end', { duration: dur, pvCount: pvCount });
            },
            
            log: function(type, evData) {
                var d = this.getData(); var today = new Date().toISOString().slice(0, 10);
                if (type === 'page_view') {
                    if (!d.pageViews[today]) d.pageViews[today] = {};
                    var vw = evData.view || 'unknown';
                    d.pageViews[today][vw] = (d.pageViews[today][vw] || 0) + 1;
                    d.totalPV = (d.totalPV || 0) + 1;
                }
                if (type === 'feature_use') {
                    if (!d.features[today]) d.features[today] = {};
                    d.features[today][evData.feature] = (d.features[today][evData.feature] || 0) + 1;
                }
                if (type === 'device_info') {
                    if (!d.devices) d.devices = { mobile: 0, desktop: 0, dark: 0, light: 0, sizes: {} };
                    evData.mobile ? d.devices.mobile++ : d.devices.desktop++;
                    evData.dark ? d.devices.dark++ : d.devices.light++;
                    var sk = evData.screenW + 'x' + evData.screenH;
                    d.devices.sizes[sk] = (d.devices.sizes[sk] || 0) + 1;
                }
                if (type === 'session_start') {
                    if (!d.dailySess) d.dailySess = {};
                    d.dailySess[today] = (d.dailySess[today] || 0) + 1;
                    d.totalSess = (d.totalSess || 0) + 1;
                    if (evData.isNew) { if (!d.newVis) d.newVis = {}; d.newVis[today] = (d.newVis[today] || 0) + 1; }
                }
                if (type === 'funnel') { if (!d.funnel) d.funnel = {}; d.funnel[evData.step] = (d.funnel[evData.step] || 0) + 1; }
                if (type === 'session_end' && evData.pvCount <= 1) { if (!d.bounces) d.bounces = {}; d.bounces[today] = (d.bounces[today] || 0) + 1; }
                this.saveData(d);
                
                // Firestore (non-blocking)
                if (type !== 'device_info' && fbDb && fbUser) {
                    try { fbDb.collection('site_analytics').add({ type: type, data: evData || {}, uid: fbUser.uid, vid: this.vid, sid: this.sid, ts: firebase.firestore.FieldValue.serverTimestamp(), date: today }); } catch(e) {}
                }
            },
            
            getData: function() {
                return safeParse(safeGet('bpSiteAnalytics'), { pageViews:{}, sessions:{}, dailySess:{}, features:{}, devices:{mobile:0,desktop:0,dark:0,light:0,sizes:{}}, funnel:{}, bounces:{}, newVis:{}, totalPV:0, totalSess:0 });
            },
            saveData: function(d) { safeSet('bpSiteAnalytics', JSON.stringify(d)); },
            
            getStats: function(days) {
                var d = this.getData(); var dates = []; var now = new Date();
                for (var i = 0; i < days; i++) { var dt = new Date(now); dt.setDate(dt.getDate()-i); dates.push(dt.toISOString().slice(0,10)); }
                var sess=0, pv=0, bnc=0, nv=0, viewCts={}, featCts={}, dailyPV=[], dailySess=[], totDur=0, sessCt=0, viewDurs={};
                dates.forEach(function(date) {
                    var ds = d.dailySess[date]||0; sess+=ds; dailySess.push({date:date,count:ds});
                    bnc += d.bounces[date]||0; nv += d.newVis[date]||0;
                    var dpv = d.pageViews[date]||{}; var dt=0;
                    Object.keys(dpv).forEach(function(v){viewCts[v]=(viewCts[v]||0)+dpv[v]; dt+=dpv[v];});
                    pv+=dt; dailyPV.push({date:date,count:dt});
                    var df = d.features[date]||{};
                    Object.keys(df).forEach(function(f){featCts[f]=(featCts[f]||0)+df[f];});
                    (d.sessions[date]||[]).forEach(function(s){
                        if(s.dur>0){totDur+=s.dur;sessCt++;}
                        if(s.vt) Object.keys(s.vt).forEach(function(v){viewDurs[v]=(viewDurs[v]||0)+s.vt[v];});
                    });
                });
                return {
                    sessions:sess, pageViews:pv, bounceRate: sess>0?Math.round(bnc/sess*100):0,
                    newVisitors:nv, returning: sess-nv,
                    avgDuration: sessCt>0?Math.round(totDur/sessCt):0, totalDuration:totDur,
                    viewsPerSession: sess>0?(pv/sess).toFixed(1):'0',
                    viewCounts:viewCts, viewDurations:viewDurs, featureCounts:featCts,
                    dailyPV:dailyPV.reverse(), dailySessions:dailySess.reverse(),
                    devices: d.devices||{}, funnel: d.funnel||{}
                };
            }
        };

        // Samples default to Network view + scroll-to-top on all view switches
        // ============================================================
        console.log('%c==============================================', 'color: #60a5fa; font-weight: bold; font-size: 14px;');
        console.log('%c   BLUEPRINT ' + BP_VERSION + '                    ', 'color: #60a5fa; font-weight: bold; font-size: 14px;');
        console.log('%c   Build: 20260305-mobile-admin                 ', 'color: #60a5fa; font-weight: bold; font-size: 14px;');
        console.log('%c   Everyone Has Premium Value!              ', 'color: #60a5fa; font-weight: bold; font-size: 14px;');
        console.log('%c==============================================', 'color: #60a5fa; font-weight: bold; font-size: 14px;');


        // ===== DATE FORMATTING UTILITY =====
        // Converts ISO-style dates (e.g. "1994-03", "2009-10") to readable format ("Mar 1994", "Oct 2009")
        // Passes through already-formatted strings (e.g. "Jan 2020", "Present") unchanged
        function formatWorkDate(dateStr) {
            if (!dateStr) return '';
            var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
            // Match YYYY-MM or YYYY-MM-DD patterns
            var isoMatch = dateStr.match(/^(\d{4})-(\d{1,2})(?:-\d{1,2})?$/);
            if (isoMatch) {
                var monthIdx = parseInt(isoMatch[2], 10) - 1;
                if (monthIdx >= 0 && monthIdx < 12) {
                    return months[monthIdx] + ' ' + isoMatch[1];
                }
                return isoMatch[1]; // fallback to just the year
            }
            // Match bare year "1994"
            if (/^\d{4}$/.test(dateStr)) return dateStr;
            // Already formatted or other string — pass through
            return dateStr;
        }

