        function loadAdminJobsSyncStatus() {
            var el = document.getElementById('adminJobsSyncContent');
            if (!el || !fbDb) return;
            
            fbDb.collection('meta').doc('jobsSync').get().then(function(doc) {
                if (!doc.exists) {
                    el.innerHTML = '<p style="color:var(--text-muted);">No sync data yet. The cron will run every 6 hours, or trigger manually.</p>';
                    return;
                }
                var m = doc.data();
                var ago = formatTimeAgo(m.lastSync);
                var src = m.sourceCounts || {};
                
                // Sort sources by count descending
                var srcEntries = Object.keys(src).filter(function(k) { return k !== 'jooble'; }).map(function(k) { return { name: k, count: src[k] || 0 }; });
                srcEntries.sort(function(a, b) { return b.count - a.count; });
                var maxCount = srcEntries.length > 0 ? srcEntries[0].count : 1;
                
                var sourceColors = {
                    jsearch: '#60a5fa', remotive: '#10b981', usajobs: '#8b5cf6',
                    himalayas: '#f59e0b', adzuna: '#fb923c', themuse: '#06b6d4',
                    jobicy: '#ec4899'
                };
                
                var srcHtml = srcEntries.map(function(entry) {
                    var color = sourceColors[entry.name] || '#94a3b8';
                    var pct = maxCount > 0 ? Math.max((entry.count / maxCount) * 100, 2) : 0;
                    var isZero = entry.count === 0;
                    return '<div style="display:flex; align-items:center; gap:10px; margin-bottom:6px;">'
                        + '<div style="width:72px; font-size:0.78em; color:' + (isZero ? 'var(--text-muted)' : 'var(--text-secondary)') + '; font-weight:500; text-align:right; flex-shrink:0;">' + entry.name + '</div>'
                        + '<div style="flex:1; height:22px; background:var(--c-surface-4b); border-radius:4px; overflow:hidden; position:relative;">'
                        + '<div style="height:100%; width:' + pct + '%; background:' + (isZero ? 'transparent' : 'linear-gradient(90deg, ' + color + '22, ' + color + '66)') + '; border-radius:4px; transition:width 0.3s;"></div>'
                        + '</div>'
                        + '<div style="width:48px; font-size:0.82em; font-weight:700; color:' + (isZero ? 'var(--text-muted)' : color) + '; text-align:right; flex-shrink:0;">' + entry.count.toLocaleString() + '</div>'
                        + '</div>';
                }).join('');
                
                var errCount = (m.errors || []).length;
                var errHtml = errCount > 0
                    ? '<details style="margin-top:12px;">'
                    + '<summary style="font-size:0.75em; color:var(--text-muted); cursor:pointer; display:inline-flex; align-items:center; gap:4px;">'
                    + '<span style="display:inline-block; width:7px; height:7px; border-radius:50%; background:#ef4444;"></span> '
                    + errCount + ' error' + (errCount > 1 ? 's' : '') + '</summary>'
                    + '<div style="font-size:0.72em; color:#ef4444; margin-top:8px; padding:8px; background:rgba(239,68,68,0.06); border-radius:6px; max-height:120px; overflow-y:auto; font-family:monospace;">'
                    + m.errors.map(function(e) { return '<div style="padding:2px 0; border-bottom:1px solid rgba(239,68,68,0.1);">' + escapeHtml(e) + '</div>'; }).join('') + '</div></details>' : '';
                
                el.innerHTML = '<div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(120px, 1fr)); gap:10px; margin-bottom:18px;">'
                    + '<div style="padding:12px; background:var(--c-surface-4b); border-radius:8px; text-align:center;">'
                    + '<div style="font-size:1.4em; font-weight:800; color:var(--accent);">' + (m.totalJobs || 0).toLocaleString() + '</div>'
                    + '<div style="font-size:0.68em; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.04em;">Total Jobs</div></div>'
                    + '<div style="padding:12px; background:var(--c-surface-4b); border-radius:8px; text-align:center;">'
                    + '<div style="font-size:1.4em; font-weight:800; color:#10b981;">' + (m.jobsSynced || 0).toLocaleString() + '</div>'
                    + '<div style="font-size:0.68em; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.04em;">Last Sync</div></div>'
                    + '<div style="padding:12px; background:var(--c-surface-4b); border-radius:8px; text-align:center;">'
                    + '<div style="font-size:1.4em; font-weight:800; color:var(--text-primary);">' + ago + '</div>'
                    + '<div style="font-size:0.68em; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.04em;">Synced</div></div>'
                    + '<div style="padding:12px; background:var(--c-surface-4b); border-radius:8px; text-align:center;">'
                    + '<div style="font-size:1.4em; font-weight:800; color:var(--text-muted);">' + ((m.duration || 0) / 1000).toFixed(1) + 's</div>'
                    + '<div style="font-size:0.68em; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.04em;">Duration</div></div>'
                    + '</div>'
                    + '<div style="font-size:0.72em; font-weight:600; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.06em; margin-bottom:8px;">Sources</div>'
                    + srcHtml
                    + errHtml;
            }).catch(function(e) {
                el.innerHTML = '<p style="color:var(--text-muted);">Could not load sync status: ' + escapeHtml(e.message) + '</p>';
            });
        }
        
        // ===== ADMIN: PURGE DUPLICATE JOBS FROM FIRESTORE =====
        async function purgeJobDuplicates() {
            if (!fbDb || !fbUser) { showToast('Not signed in.', 'error'); return; }
            if (!confirm('Scan all cached jobs for duplicates (same title+company) and remove the older copies?')) return;
            
            showToast('Scanning for duplicates...', 'info', 3000);
            try {
                var snapshot = await fbDb.collection('jobs').orderBy('syncedAt', 'desc').get();
                var seen = {};
                var dupeRefs = [];
                
                snapshot.forEach(function(doc) {
                    var d = doc.data();
                    var key = ((d.title || '') + '|' + (d.company || '')).toLowerCase().trim();
                    if (seen[key]) {
                        dupeRefs.push(doc.ref); // older duplicate — delete it
                    } else {
                        seen[key] = true;
                    }
                });
                
                if (dupeRefs.length === 0) {
                    showToast('No duplicates found in ' + snapshot.size + ' jobs.', 'success');
                    return;
                }
                
                // Batch delete in groups of 500 (Firestore limit)
                var deleted = 0;
                for (var i = 0; i < dupeRefs.length; i += 450) {
                    var batch = fbDb.batch();
                    var chunk = dupeRefs.slice(i, i + 450);
                    chunk.forEach(function(ref) { batch.delete(ref); });
                    await batch.commit();
                    deleted += chunk.length;
                }
                
                showToast('Purged ' + deleted + ' duplicate jobs. ' + (snapshot.size - deleted) + ' unique remain.', 'success');
                console.log('Job dedup: removed ' + deleted + ' of ' + snapshot.size + ' (' + Object.keys(seen).length + ' unique)');
                loadJobsFromCache(); // Reload
                loadAdminJobsSyncStatus();
            } catch(e) {
                showToast('Purge failed: ' + e.message, 'error');
                console.error('Job purge error:', e);
            }
        }
        window.purgeJobDuplicates = purgeJobDuplicates;
        
        // ===== SITE TRAFFIC DASHBOARD =====
        var trafficRange = 30;
        function setTrafficRange(d) { trafficRange = d; renderTrafficDashboard(d); }
        window.setTrafficRange = setTrafficRange;
        
        function renderTrafficDashboard(days) {
            var container = document.getElementById('trafficTiles');
            var btnContainer = document.getElementById('trafficRangeBtns');
            if (!container) return;
            
            // Range buttons
            if (btnContainer) {
                var bhtml = '';
                [7,14,30,60,90].forEach(function(d) {
                    var active = days === d;
                    bhtml += '<button onclick="setTrafficRange(' + d + ')" style="padding:4px 12px; border-radius:16px; font-size:0.72em; font-weight:600; cursor:pointer; border:1px solid ' + (active ? 'var(--accent)' : 'var(--border)') + '; background:' + (active ? 'var(--accent)' : 'transparent') + '; color:' + (active ? '#fff' : 'var(--text-muted)') + ';">' + d + 'd</button>';
                });
                btnContainer.innerHTML = bhtml;
            }
            
            var s = bpTracker.getStats(days);
            var html = '';
            
            function fmt(sec) { if (sec < 60) return sec + 's'; if (sec < 3600) return Math.floor(sec/60) + 'm ' + (sec%60) + 's'; return Math.floor(sec/3600) + 'h ' + Math.floor((sec%3600)/60) + 'm'; }
            function tile(label, value, color, sub) {
                return '<div style="padding:14px; background:linear-gradient(135deg, ' + color + '11, ' + color + '08); border:1px solid ' + color + '33; border-radius:10px; text-align:center;">'
                    + '<div style="font-size:1.8em; font-weight:800; color:' + color + ';">' + value + '</div>'
                    + '<div style="font-size:0.7em; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.06em;">' + label + '</div>'
                    + (sub ? '<div style="font-size:0.65em; color:var(--text-muted); margin-top:2px;">' + sub + '</div>' : '') + '</div>';
            }
            
            // ===== ROW 1: Core Traffic Metrics =====
            html += '<div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(120px, 1fr)); gap:10px; margin-bottom:16px;">';
            html += tile('Sessions', s.sessions, '#60a5fa', 'Last ' + days + ' days');
            html += tile('Page Views', s.pageViews, '#8b5cf6', s.viewsPerSession + ' per session');
            html += tile('Bounce Rate', s.bounceRate + '%', s.bounceRate > 60 ? '#ef4444' : s.bounceRate > 40 ? '#f59e0b' : '#10b981', 'Single-view sessions');
            html += tile('Avg Session', fmt(s.avgDuration), '#10b981', 'Time on site');
            html += tile('New Visitors', s.newVisitors, '#fbbf24', s.returning + ' returning');
            html += tile('Total Time', fmt(s.totalDuration), '#ec4899', 'All sessions combined');
            html += '</div>';
            
            // ===== ROW 2: Sparklines (Sessions + Page Views) =====
            html += '<div style="display:grid; grid-template-columns:1fr 1fr; gap:12px; margin-bottom:16px;">';
            
            // Sessions sparkline
            var sMax = Math.max.apply(null, s.dailySessions.map(function(d){return d.count;})) || 1;
            html += '<div style="padding:14px; background:var(--c-surface-4b); border-radius:10px;">'
                + '<div style="font-size:0.75em; font-weight:600; color:var(--text-muted); margin-bottom:8px;">Daily Sessions</div>'
                + '<div style="display:flex; align-items:flex-end; gap:2px; height:50px;">';
            s.dailySessions.slice(-Math.min(days, 30)).forEach(function(d) {
                var h = Math.max((d.count / sMax) * 100, 3);
                html += '<div title="' + escapeHtml(d.date) + ': ' + d.count + '" style="flex:1; height:' + h + '%; background:rgba(96,165,250,0.5); border-radius:2px 2px 0 0; min-width:4px;"></div>';
            });
            html += '</div></div>';
            
            // Page views sparkline
            var pvMax = Math.max.apply(null, s.dailyPV.map(function(d){return d.count;})) || 1;
            html += '<div style="padding:14px; background:var(--c-surface-4b); border-radius:10px;">'
                + '<div style="font-size:0.75em; font-weight:600; color:var(--text-muted); margin-bottom:8px;">Daily Page Views</div>'
                + '<div style="display:flex; align-items:flex-end; gap:2px; height:50px;">';
            s.dailyPV.slice(-Math.min(days, 30)).forEach(function(d) {
                var h = Math.max((d.count / pvMax) * 100, 3);
                html += '<div title="' + escapeHtml(d.date) + ': ' + d.count + '" style="flex:1; height:' + h + '%; background:rgba(139,92,246,0.5); border-radius:2px 2px 0 0; min-width:4px;"></div>';
            });
            html += '</div></div>';
            html += '</div>';
            
            // ===== ROW 3: Page Views by Section + Time per Section =====
            html += '<div style="display:grid; grid-template-columns:1fr 1fr; gap:12px; margin-bottom:16px;">';
            
            // Views by section
            var viewLabels = { network:'Map', card:'Card View', opportunities:'Jobs', blueprint:'Blueprint', reports:'Reports', settings:'Settings', welcome:'Welcome', admin:'Admin' };
            var viewColors = { network:'#60a5fa', card:'#818cf8', opportunities:'#f59e0b', blueprint:'#10b981', reports:'#ec4899', settings:'#6b7280', welcome:'#a78bfa', admin:'#fbbf24' };
            var sortedViews = Object.entries(s.viewCounts).sort(function(a,b){return b[1]-a[1];});
            var maxView = sortedViews.length > 0 ? sortedViews[0][1] : 1;
            
            html += '<div style="padding:14px; background:var(--c-surface-4b); border-radius:10px;">'
                + '<div style="font-size:0.75em; font-weight:600; color:var(--text-muted); margin-bottom:10px;">Views by Section</div>';
            if (sortedViews.length === 0) { html += '<div style="font-size:0.82em; color:var(--text-muted);">No data yet</div>'; }
            sortedViews.forEach(function(entry) {
                var view = entry[0], count = entry[1];
                var pct = Math.max((count / maxView) * 100, 2);
                var color = viewColors[view] || '#6b7280';
                html += '<div style="margin-bottom:6px;">'
                    + '<div style="display:flex; justify-content:space-between; font-size:0.78em; margin-bottom:2px;">'
                    + '<span style="color:var(--text-secondary);">' + (viewLabels[view] || view) + '</span>'
                    + '<span style="color:var(--text-muted);">' + count + '</span></div>'
                    + '<div style="height:4px; background:var(--c-surface-3a); border-radius:2px; overflow:hidden;">'
                    + '<div style="height:100%; width:' + pct + '%; background:' + color + '; border-radius:2px;"></div></div></div>';
            });
            html += '</div>';
            
            // Time per section
            var sortedDurs = Object.entries(s.viewDurations).sort(function(a,b){return b[1]-a[1];});
            var maxDur = sortedDurs.length > 0 ? sortedDurs[0][1] : 1;
            
            html += '<div style="padding:14px; background:var(--c-surface-4b); border-radius:10px;">'
                + '<div style="font-size:0.75em; font-weight:600; color:var(--text-muted); margin-bottom:10px;">Time per Section</div>';
            if (sortedDurs.length === 0) { html += '<div style="font-size:0.82em; color:var(--text-muted);">No data yet</div>'; }
            sortedDurs.forEach(function(entry) {
                var view = entry[0], dur = entry[1];
                var pct = Math.max((dur / maxDur) * 100, 2);
                var color = viewColors[view] || '#6b7280';
                html += '<div style="margin-bottom:6px;">'
                    + '<div style="display:flex; justify-content:space-between; font-size:0.78em; margin-bottom:2px;">'
                    + '<span style="color:var(--text-secondary);">' + (viewLabels[view] || view) + '</span>'
                    + '<span style="color:var(--text-muted);">' + fmt(dur) + '</span></div>'
                    + '<div style="height:4px; background:var(--c-surface-3a); border-radius:2px; overflow:hidden;">'
                    + '<div style="height:100%; width:' + pct + '%; background:' + color + '; border-radius:2px;"></div></div></div>';
            });
            html += '</div>';
            html += '</div>';
            
            // ===== ROW 4: Feature Usage + Device/Context =====
            html += '<div style="display:grid; grid-template-columns:1fr 1fr; gap:12px; margin-bottom:16px;">';
            
            // Feature usage
            var featLabels = { resume_parse:'Resume Parse', scouting_report:'Scouting Report', export_pdf:'PDF Export', export_html:'Executive Blueprint', export_resume_html:'HTML Resume', export_json:'JSON Export', cover_letter:'Cover Letter', interview_prep:'Interview Prep', linkedin_profile:'LinkedIn Profile', job_analysis:'JD Analysis', negotiation_guide:'Negotiation Guide', scouting_report_html:'Report (HTML)', wb_created:'WB Created', wb_edited:'WB Edited', wb_deleted:'WB Deleted', wb_exported_pdf:'WB Export PDF', wb_exported_word:'WB Export Word', wb_exported_json:'WB Export JSON', wb_wizard_complete:'WB Wizard Complete', wb_converted:'WB JD Converted', showcase_visit:'Showcase Visit', linkedin_zip_import:'LinkedIn ZIP Import', linkedin_merge:'LinkedIn Merge', wb_cloned:'WB Cloned' };
            var sortedFeats = Object.entries(s.featureCounts).sort(function(a,b){return b[1]-a[1];});
            var maxFeat = sortedFeats.length > 0 ? sortedFeats[0][1] : 1;
            
            html += '<div style="padding:14px; background:var(--c-surface-4b); border-radius:10px;">'
                + '<div style="font-size:0.75em; font-weight:600; color:var(--text-muted); margin-bottom:10px;">Feature Usage</div>';
            if (sortedFeats.length === 0) { html += '<div style="font-size:0.82em; color:var(--text-muted);">No feature usage yet</div>'; }
            sortedFeats.slice(0, 12).forEach(function(entry) {
                var feat = entry[0], count = entry[1];
                var pct = Math.max(Math.round((count / maxFeat) * 100), 6);
                html += '<div style="margin-bottom:8px;">'
                    + '<div style="display:flex; justify-content:space-between; align-items:center; font-size:0.78em; margin-bottom:3px;">'
                    + '<span style="color:var(--text-secondary);">' + (featLabels[feat] || feat) + '</span>'
                    + '<span style="font-weight:700; color:var(--accent); min-width:24px; text-align:right;">' + count + '</span></div>'
                    + '<div style="height:10px; border-radius:5px; background:rgba(255,255,255,0.04); overflow:hidden; border:1px solid rgba(255,255,255,0.03);">'
                    + '<div style="width:' + pct + '%; height:100%; border-radius:5px; background:linear-gradient(90deg, rgba(96,165,250,0.5), rgba(96,165,250,0.85));"></div>'
                    + '</div></div>';
            });
            html += '</div>';
            
            // Device & context
            var dev = s.devices;
            var totalDev = (dev.mobile || 0) + (dev.desktop || 0);
            var mobilePct = totalDev > 0 ? Math.round((dev.mobile || 0) / totalDev * 100) : 0;
            var darkPct = totalDev > 0 ? Math.round((dev.dark || 0) / totalDev * 100) : 0;
            
            html += '<div style="padding:14px; background:var(--c-surface-4b); border-radius:10px;">'
                + '<div style="font-size:0.75em; font-weight:600; color:var(--text-muted); margin-bottom:10px;">Device & Context</div>';
            
            // Mobile vs desktop bar
            html += '<div style="margin-bottom:12px;">'
                + '<div style="display:flex; justify-content:space-between; font-size:0.78em; margin-bottom:4px;">'
                + '<span style="color:var(--text-secondary);">Mobile</span>'
                + '<span style="color:var(--text-secondary);">Desktop</span></div>'
                + '<div style="display:flex; height:8px; border-radius:4px; overflow:hidden; background:var(--c-surface-3a);">'
                + '<div style="width:' + mobilePct + '%; background:#f59e0b;"></div>'
                + '<div style="width:' + (100-mobilePct) + '%; background:#60a5fa;"></div></div>'
                + '<div style="display:flex; justify-content:space-between; font-size:0.7em; color:var(--text-muted); margin-top:2px;">'
                + '<span>' + mobilePct + '% (' + (dev.mobile||0) + ')</span><span>' + (100-mobilePct) + '% (' + (dev.desktop||0) + ')</span></div></div>';
            
            // Dark vs light bar
            html += '<div style="margin-bottom:12px;">'
                + '<div style="display:flex; justify-content:space-between; font-size:0.78em; margin-bottom:4px;">'
                + '<span style="color:var(--text-secondary);">Dark Mode</span>'
                + '<span style="color:var(--text-secondary);">Light Mode</span></div>'
                + '<div style="display:flex; height:8px; border-radius:4px; overflow:hidden; background:var(--c-surface-3a);">'
                + '<div style="width:' + darkPct + '%; background:#8b5cf6;"></div>'
                + '<div style="width:' + (100-darkPct) + '%; background:#fbbf24;"></div></div>'
                + '<div style="display:flex; justify-content:space-between; font-size:0.7em; color:var(--text-muted); margin-top:2px;">'
                + '<span>' + darkPct + '%</span><span>' + (100-darkPct) + '%</span></div></div>';
            
            // Screen sizes
            var sizes = dev.sizes || {};
            var sortedSizes = Object.entries(sizes).sort(function(a,b){return b[1]-a[1];}).slice(0, 5);
            if (sortedSizes.length > 0) {
                html += '<div style="font-size:0.72em; color:var(--text-muted); margin-top:8px;">Top screen sizes:</div>';
                sortedSizes.forEach(function(e) {
                    html += '<div style="font-size:0.72em; color:var(--text-secondary); padding:1px 0;">' + escapeHtml(e[0]) + ' <span style="color:var(--text-muted);">(' + e[1] + ')</span></div>';
                });
            }
            html += '</div>';
            html += '</div>';
            
            // ===== ROW 4b: Work Blueprint Metrics =====
            var wbKeys = ['wb_created','wb_edited','wb_deleted','wb_exported_pdf','wb_exported_word','wb_exported_json','wb_wizard_complete','wb_converted'];
            var wbTotal = 0; wbKeys.forEach(function(k){ wbTotal += (s.featureCounts[k] || 0); });
            if (wbTotal > 0) {
                html += '<div style="padding:14px; background:var(--c-surface-4b); border:1px solid var(--border); border-radius:10px; margin-bottom:16px;">'
                    + '<div style="display:flex; align-items:center; gap:6px; margin-bottom:10px;">'
                    + '<span style="font-size:0.8em; font-weight:700; color:var(--c-heading-bold);">' + bpIcon('briefcase',14) + ' Work Blueprint Activity</span>'
                    + '<span style="font-size:0.65em; color:var(--text-muted);">Last ' + days + ' days</span></div>'
                    + '<div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(90px, 1fr)); gap:8px;">';
                var wbTiles = [
                    { k:'wb_created', l:'Created', c:'#10b981' },
                    { k:'wb_edited', l:'Edited', c:'#60a5fa' },
                    { k:'wb_converted', l:'Converted', c:'#8b5cf6' },
                    { k:'wb_wizard_complete', l:'Wizard', c:'#a78bfa' },
                    { k:'wb_exported_pdf', l:'PDF', c:'#ef4444' },
                    { k:'wb_exported_word', l:'Word', c:'#2563eb' },
                    { k:'wb_exported_json', l:'JSON', c:'#f59e0b' },
                    { k:'wb_deleted', l:'Deleted', c:'#6b7280' }
                ];
                wbTiles.forEach(function(t) {
                    var cnt = s.featureCounts[t.k] || 0;
                    if (cnt > 0) html += '<div style="text-align:center; padding:8px; background:' + t.c + '11; border-radius:8px;">'
                        + '<div style="font-size:1.4em; font-weight:800; color:' + t.c + ';">' + cnt + '</div>'
                        + '<div style="font-size:0.65em; color:var(--text-muted); text-transform:uppercase;">' + t.l + '</div></div>';
                });
                html += '</div></div>';
            }

            // ===== ROW 5: Conversion Funnel =====
            var funnelSteps = [
                { key: 'visit', label: 'Visited', icon: 'eye', color: '#60a5fa' },
                { key: 'signup', label: 'Signed Up', icon: 'lock', color: '#8b5cf6' },
                { key: 'profile_created', label: 'Profile Created', icon: 'edit', color: '#a78bfa' },
                { key: 'skills_added', label: 'Skills Added', icon: 'skills', color: '#10b981' },
                { key: 'first_job', label: 'First Job Added', icon: 'target', color: '#f59e0b' },
                { key: 'report_generated', label: 'Report Generated', icon: 'bar-chart', color: '#ec4899' }
            ];
            var funnelMax = Math.max.apply(null, funnelSteps.map(function(f) { return s.funnel[f.key] || 0; })) || 1;
            
            html += '<div style="padding:14px; background:var(--c-surface-4b); border-radius:10px;">'
                + '<div style="font-size:0.75em; font-weight:600; color:var(--text-muted); margin-bottom:12px;">Conversion Funnel</div>'
                + '<div style="display:flex; align-items:flex-end; gap:6px; height:80px; margin-bottom:8px;">';
            
            funnelSteps.forEach(function(step) {
                var count = s.funnel[step.key] || 0;
                var h = Math.max((count / funnelMax) * 100, 4);
                html += '<div style="flex:1; display:flex; flex-direction:column; align-items:center; gap:4px;">'
                    + '<div style="font-size:0.72em; font-weight:700; color:' + step.color + ';">' + count + '</div>'
                    + '<div style="width:100%; height:' + h + '%; background:' + step.color + '; border-radius:4px 4px 0 0; min-height:3px;"></div>'
                    + '</div>';
            });
            html += '</div><div style="display:flex; gap:6px;">';
            funnelSteps.forEach(function(step) {
                html += '<div style="flex:1; text-align:center; font-size:0.65em; color:var(--text-muted); line-height:1.3;">'
                    + '<span style="color:' + step.color + ';">' + bpIcon(step.icon, 14) + '</span><br>' + step.label + '</div>';
            });
            html += '</div></div>';
            
            // ===== ROW 6: Data source note =====
            html += '<div style="font-size:0.72em; color:var(--text-muted); margin-top:12px; line-height:1.5;">'
                + '' + bpIcon('bar-chart', 12) + ' Local data (this browser). Firestore aggregation available in Platform Analytics below for cross-user totals. '
                + 'Visit count: ' + (safeGet('bpVisitCount') || '0') + ' | First seen: ' + (safeGet('bpFirstVisit') || 'N/A').slice(0, 10)
                + ' | <a href="#" onclick="if(confirm(\'Clear all local traffic data?\')){localStorage.removeItem(\'bpSiteAnalytics\');renderTrafficDashboard(' + days + ');showToast(\'Traffic data cleared.\',\'info\');} return false;" style="color:var(--accent);">Clear local data</a>'
                + '</div>';
            
            container.innerHTML = html;
        }
        
        // ===== PLATFORM ANALYTICS (Tier 1: from user docs + Tier 2: from events) =====
        function loadAiroiAnalytics() {
            var container = document.getElementById('adminAiroiContent');
            if (!container || !fbDb) return;

            fbDb.collection('analytics').doc('airoi').get().then(function(snap) {
                if (!snap.exists) {
                    container.innerHTML = '<div style="color:var(--text-muted); font-size:0.85em;">No hits recorded yet. Deploy airoi.html with the tracker and visit the page.</div>';
                    return;
                }
                var data = snap.data();

                // Last 24h: sum hour buckets from past 24 hours
                var hours = data.hours || {};
                var cutoff = new Date(Date.now() - 24 * 3600 * 1000).toISOString().slice(0, 13);
                var last24 = 0;
                Object.entries(hours).forEach(function(e) {
                    if (e[0] >= cutoff) last24 += e[1];
                });

                // Avg time on page
                var samples = data.durationSamples || 0;
                var totalDur = data.totalDuration || 0;
                var avgSec = samples > 0 ? Math.round(totalDur / samples) : 0;
                var avgStr = avgSec > 0 ? (avgSec >= 60 ? Math.floor(avgSec/60) + 'm ' + (avgSec%60) + 's' : avgSec + 's') : '—';

                // Last seen
                var lastSeenStr = '—';
                if (data.lastSeen && data.lastSeen.toDate) {
                    var ls = data.lastSeen.toDate();
                    lastSeenStr = ls.toLocaleDateString('en-US', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });
                }

                // Stat tiles
                var html = '<div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(110px, 1fr)); gap:10px; margin-bottom:16px;">';
                [
                    { label: 'All-Time Hits', value: (data.total || 0).toLocaleString(),  color: '#10b981' },
                    { label: 'Avg Time',      value: avgStr,                               color: '#38bdf8' },
                    { label: 'Exports',       value: (data.exports || 0).toLocaleString(), color: '#f59e0b' },
                    { label: 'Last Seen',     value: lastSeenStr,                          color: '#94a3b8', small: true }
                ].forEach(function(c) {
                    html += '<div style="padding:12px; background:var(--c-surface-4b); border-radius:8px; text-align:center;">'
                        + '<div style="font-size:' + (c.small ? '0.88' : '1.5') + 'em; font-weight:700; color:' + c.color + '; line-height:1.2;">' + c.value + '</div>'
                        + '<div style="font-size:0.68em; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.05em; margin-top:3px;">' + c.label + '</div>'
                        + '</div>';
                });
                html += '</div>';
                container.innerHTML = html;
            }).catch(function(err) {
                container.innerHTML = '<div style="color:#ef4444; font-size:0.82em;">Failed to load: ' + escapeHtml(err.message) + '</div>';
            });
        }

        function loadPlatformAnalytics() {
            var container = document.getElementById('adminAnalytics');
            if (!container || !fbDb) return;
            
            var now = new Date();
            var sevenDaysAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
            var thirtyDaysAgo = new Date(now - 30 * 24 * 60 * 60 * 1000);
            
            // Load users and events in parallel
            Promise.all([
                fbDb.collection('users').get(),
                fbDb.collection('analytics_events').orderBy('timestamp', 'desc').limit(500).get().catch(function() { return { docs: [], size: 0 }; })
            ]).then(function(results) {
                var usersSnap = results[0];
                var eventsSnap = results[1];
                
                // ===== Tier 1: Aggregate user data =====
                var totalUsers = usersSnap.size;
                var activeWeek = 0, activeMonth = 0, newWeek = 0;
                var totalSkills = 0, totalOutcomes = 0, totalJobs = 0, totalApps = 0;
                var skillCategories = {};
                var topSkills = {};
                var usersWithSkills = 0;
                
                usersSnap.forEach(function(doc) {
                    var d = doc.data();
                    var lastLogin = d.lastLogin ? new Date(d.lastLogin.seconds * 1000) : null;
                    var created = d.createdAt ? new Date(d.createdAt.seconds * 1000) : null;
                    
                    if (lastLogin && lastLogin > sevenDaysAgo) activeWeek++;
                    if (lastLogin && lastLogin > thirtyDaysAgo) activeMonth++;
                    if (created && created > sevenDaysAgo) newWeek++;
                    
                    var skills = d.skills || [];
                    var outcomes = d.values || [];
                    var jobs = d.savedJobs || [];
                    var apps = d.applications || [];
                    
                    if (skills.length > 0) usersWithSkills++;
                    totalSkills += skills.length;
                    totalOutcomes += outcomes.length;
                    totalJobs += jobs.length;
                    totalApps += apps.length;
                    
                    skills.forEach(function(s) {
                        var cat = s.category || 'skill';
                        skillCategories[cat] = (skillCategories[cat] || 0) + 1;
                        var name = s.name || 'Unknown';
                        topSkills[name] = (topSkills[name] || 0) + 1;
                    });
                });
                
                var avgSkills = totalUsers > 0 ? Math.round(totalSkills / totalUsers) : 0;
                var avgOutcomes = totalUsers > 0 ? Math.round(totalOutcomes / totalUsers) : 0;
                
                // ===== Tier 2: Event analytics =====
                var eventCounts = {};
                var eventsThisWeek = 0;
                var eventsThisMonth = 0;
                
                if (eventsSnap.docs) {
                    eventsSnap.docs.forEach(function(doc) {
                        var d = doc.data();
                        var type = d.type || 'unknown';
                        eventCounts[type] = (eventCounts[type] || 0) + 1;
                        var ts = d.timestamp ? new Date(d.timestamp.seconds * 1000) : null;
                        if (ts && ts > sevenDaysAgo) eventsThisWeek++;
                        if (ts && ts > thirtyDaysAgo) eventsThisMonth++;
                    });
                }
                
                // ===== Render analytics =====
                var html = '<h3 style="font-family:Outfit,sans-serif; font-weight:700; color:var(--text-primary); margin:0 0 20px; font-size:1em; letter-spacing:0.06em; text-transform:uppercase;">Platform Analytics</h3>';
                
                // User metrics row
                html += '<div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(140px, 1fr)); gap:12px; margin-bottom:24px;">';
                [
                    { label: 'Total Users', value: totalUsers, color: '#60a5fa' },
                    { label: 'Active (7d)', value: activeWeek, color: '#10b981' },
                    { label: 'Active (30d)', value: activeMonth, color: '#10b981' },
                    { label: 'New This Week', value: newWeek, color: '#fbbf24' },
                    { label: 'With Skills', value: usersWithSkills, color: '#8b5cf6' }
                ].forEach(function(c) {
                    html += '<div style="padding:14px; background:var(--c-surface-4b); border-radius:8px; text-align:center;">'
                        + '<div style="font-size:1.6em; font-weight:700; color:' + c.color + ';">' + c.value + '</div>'
                        + '<div style="font-size:0.72em; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.05em;">' + c.label + '</div></div>';
                });
                html += '</div>';
                
                // Content volume
                html += '<div style="display:grid; grid-template-columns:1fr 1fr; gap:20px; margin-bottom:24px;">';
                
                // Left: content totals
                html += '<div>'
                    + '<div style="font-weight:600; color:var(--text-secondary); font-size:0.88em; margin-bottom:12px;">Content Volume</div>';
                [
                    { label: 'Total Skills', value: totalSkills, avg: avgSkills + '/user' },
                    { label: 'Total Outcomes', value: totalOutcomes, avg: avgOutcomes + '/user' },
                    { label: 'Saved Jobs', value: totalJobs },
                    { label: 'Applications', value: totalApps }
                ].forEach(function(row) {
                    html += '<div style="display:flex; justify-content:space-between; padding:6px 0; border-bottom:1px solid var(--c-surface-3a); font-size:0.88em;">'
                        + '<span style="color:var(--text-secondary);">' + row.label + '</span>'
                        + '<span style="color:var(--text-primary); font-weight:600;">' + row.value.toLocaleString()
                        + (row.avg ? ' <span style="color:var(--text-muted); font-weight:400; font-size:0.82em;">(' + row.avg + ')</span>' : '')
                        + '</span></div>';
                });
                html += '</div>';
                
                // Right: skills by category
                html += '<div>'
                    + '<div style="font-weight:600; color:var(--text-secondary); font-size:0.88em; margin-bottom:12px;">Skills by Category</div>';
                var catColors = { skill: '#60a5fa', ability: '#a78bfa', workstyle: '#f59e0b', knowledge: '#10b981', workactivity: '#ec4899', unique: '#fbbf24', trade: '#f97316' };
                var catLabels = { skill: 'O*NET Skills', ability: 'Abilities', workstyle: 'Work Styles', knowledge: 'Knowledge', workactivity: 'Work Activities', unique: 'Custom/Unique', trade: 'Trades & Creative' };
                
                var sortedCats = Object.entries(skillCategories).sort(function(a, b) { return b[1] - a[1]; });
                if (sortedCats.length === 0) {
                    html += '<div style="color:var(--text-muted); font-size:0.85em; padding:8px 0;">No skill data yet</div>';
                }
                sortedCats.forEach(function(entry) {
                    var cat = entry[0], count = entry[1];
                    var pct = totalSkills > 0 ? Math.round(count / totalSkills * 100) : 0;
                    var color = catColors[cat] || '#6b7280';
                    html += '<div style="margin-bottom:8px;">'
                        + '<div style="display:flex; justify-content:space-between; font-size:0.82em; margin-bottom:3px;">'
                        + '<span style="color:var(--text-secondary);">' + (catLabels[cat] || cat) + '</span>'
                        + '<span style="color:var(--text-muted);">' + count + ' (' + pct + '%)</span>'
                        + '</div>'
                        + '<div style="height:6px; background:var(--c-surface-4); border-radius:3px; overflow:hidden;">'
                        + '<div style="height:100%; width:' + pct + '%; background:' + color + '; border-radius:3px;"></div>'
                        + '</div></div>';
                });
                html += '</div></div>';
                
                // Export / generation events
                html += '<div style="margin-bottom:20px;">'
                    + '<div style="font-weight:600; color:var(--text-secondary); font-size:0.88em; margin-bottom:12px;">Generation & Export Activity</div>';
                
                var eventLabels = {
                    'export_pdf': 'PDF Summaries',
                    'export_html': 'Executive Blueprints',
                    'export_json': 'JSON Exports',
                    'export_resume_html': 'HTML Resumes',
                    'scouting_report': 'Scouting Reports',
                    'negotiation_guide': 'Negotiation Guides',
                    'cover_letter': 'Cover Letters (AI)',
                    'interview_prep': 'Interview Prep (AI)',
                    'linkedin_profile': 'LinkedIn Profiles (AI)',
                    'resume_parse': 'Resume Parses (AI)',
                    'job_analysis': 'Job Analyses (AI)'
                };
                var eventKeys = ['export_pdf', 'export_html', 'export_resume_html', 'export_json', 'scouting_report', 'negotiation_guide', 'cover_letter', 'interview_prep', 'linkedin_profile', 'resume_parse', 'job_analysis'];
                var hasEvents = eventKeys.some(function(k) { return eventCounts[k]; });
                
                if (hasEvents) {
                    html += '<div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(180px, 1fr)); gap:10px;">';
                    eventKeys.forEach(function(key) {
                        var count = eventCounts[key] || 0;
                        if (count === 0) return;
                        html += '<div style="display:flex; justify-content:space-between; align-items:center; padding:10px 14px; background:var(--c-surface-4b); border-radius:8px; font-size:0.85em;">'
                            + '<span style="color:var(--text-secondary);">' + (eventLabels[key] || key) + '</span>'
                            + '<span style="font-weight:700; color:var(--text-primary);">' + count + '</span>'
                            + '</div>';
                    });
                    html += '</div>';
                    html += '<div style="font-size:0.78em; color:var(--text-muted); margin-top:10px;">' + eventsThisWeek + ' events this week \u00B7 ' + eventsThisMonth + ' this month \u00B7 ' + (eventsSnap.docs ? eventsSnap.docs.length : 0) + ' total tracked</div>';
                } else {
                    html += '<div style="color:var(--text-muted); font-size:0.85em; padding:12px; background:var(--c-surface-2); border-radius:8px;">'
                        + 'No export events tracked yet. Events will appear here as users generate PDFs, scouting reports, and other deliverables.</div>';
                }
                html += '</div>';
                
                // Top skills
                if (Object.keys(topSkills).length > 0) {
                    html += '<div>'
                        + '<div style="font-weight:600; color:var(--text-secondary); font-size:0.88em; margin-bottom:12px;">Top 10 Skills Across All Users</div>'
                        + '<div style="display:flex; flex-wrap:wrap; gap:6px;">';
                    Object.entries(topSkills).sort(function(a,b) { return b[1]-a[1]; }).slice(0, 10).forEach(function(entry) {
                        html += '<span style="padding:5px 12px; background:var(--c-accent-bg-5b); border-radius:16px; font-size:0.82em; color:var(--text-secondary);">'
                            + escapeHtml(entry[0]) + ' <strong style="color:var(--accent);">' + entry[1] + '</strong></span>';
                    });
                    html += '</div></div>';
                }
                
                container.innerHTML = html;
            }).catch(function(err) {
                container.innerHTML = '<div style="color:#ef4444; padding:12px;">Analytics load error: ' + escapeHtml(err.message) + '</div>';
            });
        }
        
        function renderAdminUsers(el) {
            // v4.44.36: Showcase mode — show structure without PII
            if (showcaseMode) {
                el.innerHTML = '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:20px;">'
                    + '<div>'
                    + '<h3 style="font-family:Outfit,sans-serif; font-weight:700; color:var(--text-primary); margin:0; font-size:1.1em; letter-spacing:0.06em; text-transform:uppercase;">Registered Users</h3>'
                    + '<p style="color:var(--text-muted); font-size:0.85em; margin-top:4px;">User management with Firebase Authentication</p>'
                    + '</div></div>'
                    + '<div style="padding:32px; text-align:center; background:var(--c-surface-2); border:1px dashed var(--c-surface-5); border-radius:12px;">'
                    + '<div style="font-size:2em; margin-bottom:8px;">🔒</div>'
                    + '<div style="color:var(--text-secondary); font-weight:600; margin-bottom:4px;">User Data Redacted</div>'
                    + '<div style="color:var(--text-muted); font-size:0.85em;">Email addresses, login timestamps, and account details are hidden in showcase mode to protect user privacy.</div>'
                    + '</div>';
                return;
            }
            if (!fbDb) { el.innerHTML = '<div style="color:#ef4444;">Firebase not connected.</div>'; return; }
            
            el.innerHTML = '<div style="text-align:center; padding:40px; color:var(--text-muted);">Loading users...</div>';
            
            fbDb.collection('users').orderBy('lastLogin', 'desc').get()
                .then(function(snapshot) {
                    var html = '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:20px;">'
                        + '<div>'
                        + '<h3 style="font-family:Outfit,sans-serif; font-weight:700; color:var(--text-primary); margin:0; font-size:1.1em; letter-spacing:0.06em; text-transform:uppercase;">Registered Users</h3>'
                        + '<p style="color:var(--text-muted); font-size:0.85em; margin-top:4px;">' + snapshot.size + ' total accounts</p>'
                        + '</div>'
                        + '</div>';
                    
                    html += '<div style="display:grid; gap:10px;">';
                    snapshot.forEach(function(doc) {
                        var d = doc.data();
                        var skillCount = d.skills ? d.skills.length : 0;
                        var outcomeCount = d.values ? d.values.length : 0;
                        var jobCount = d.savedJobs ? d.savedJobs.length : 0;
                        var lastLogin = d.lastLogin ? new Date(d.lastLogin.seconds * 1000).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : 'Never';
                        var created = d.createdAt ? new Date(d.createdAt.seconds * 1000).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : '?';
                        var isAdmin = d.role === 'admin';
                        var isCurrentUser = fbUser && doc.id === fbUser.uid;
                        
                        html += '<div style="padding:16px; background:var(--c-surface-2); '
                            + 'border:1px solid ' + (isCurrentUser ? 'var(--accent)' : 'var(--c-surface-5)') + '; border-radius:10px;'
                            + (isCurrentUser ? ' box-shadow:0 0 0 1px var(--accent);' : '') + '">'
                            + '<div style="display:flex; justify-content:space-between; align-items:flex-start; gap:16px; flex-wrap:wrap;">'
                            + '<div style="flex:1; min-width:200px;">'
                            + '<div style="display:flex; align-items:center; gap:8px;">'
                            + '<strong style="color:var(--text-primary); font-size:1.05em;">' + escapeHtml(d.displayName || d.email || doc.id) + '</strong>'
                            + (isAdmin ? ' <span style="font-size:0.7em; padding:2px 8px; border-radius:10px; background:rgba(251,191,36,0.15); color:#fbbf24; font-weight:700;">ADMIN</span>' : '')
                            + (isCurrentUser ? ' <span style="font-size:0.7em; padding:2px 8px; border-radius:10px; background:rgba(96,165,250,0.15); color:#60a5fa; font-weight:600;">YOU</span>' : '')
                            + '</div>'
                            + '<div style="font-size:0.82em; color:var(--text-muted); margin-top:2px;">' + escapeHtml(d.email || '') + '</div>'
                            + '<div style="font-size:0.78em; color:var(--text-muted); margin-top:4px;">Joined ' + created + '</div>'
                            + '</div>'
                            + '<div style="display:flex; gap:20px; font-size:0.85em; color:var(--text-muted);">'
                            + '<div style="text-align:center;"><div style="font-weight:700; color:var(--text-primary); font-size:1.2em;">' + skillCount + '</div>skills</div>'
                            + '<div style="text-align:center;"><div style="font-weight:700; color:var(--text-primary); font-size:1.2em;">' + outcomeCount + '</div>outcomes</div>'
                            + '<div style="text-align:center;"><div style="font-weight:700; color:var(--text-primary); font-size:1.2em;">' + jobCount + '</div>jobs</div>'
                            + '<div style="text-align:center;"><div style="font-size:0.82em;">Last login</div><div style="font-weight:600; color:var(--text-secondary);">' + lastLogin + '</div></div>'
                            + '</div>'
                            + '</div></div>';
                    });
                    html += '</div>';
                    
                    el.innerHTML = html;
                })
                .catch(function(err) {
                    el.innerHTML = '<div style="color:#ef4444;">Error loading users: ' + escapeHtml(err.message) + '</div>';
                });
        }
        
        function renderAdminSamples(el) {
            var manifest = window.profilesManifest;
            var profiles = manifest && manifest.profiles ? manifest.profiles : [];
            
            var html = '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:20px;">'
                + '<div>'
                + '<h3 style="font-family:Outfit,sans-serif; font-weight:700; color:var(--text-primary); margin:0; font-size:1.1em; letter-spacing:0.06em; text-transform:uppercase;">Sample Profiles</h3>'
                + '<p style="color:var(--text-muted); font-size:0.85em; margin-top:4px;">' + profiles.length + ' profiles in manifest</p>'
                + '</div>'
                + '</div>';
            
            html += '<div style="display:grid; gap:12px;">';
            profiles.forEach(function(p) {
                var template = templates[p.id];
                var skillCount = template && template.skills ? template.skills.length : '?';
                var outcomeCount = template && template.values ? template.values.length : '?';
                var initials = p.name.split(' ').map(function(w) { return w[0]; }).join('').slice(0, 2).toUpperCase();
                
                html += '<div style="padding:18px; background:var(--c-surface-2); '
                    + 'border:1px solid var(--c-surface-5); border-radius:10px;'
                    + (!p.enabled ? ' opacity:0.5;' : '') + '">'
                    + '<div style="display:flex; justify-content:space-between; align-items:flex-start; gap:16px; flex-wrap:wrap;">'
                    + '<div style="display:flex; align-items:center; gap:14px; flex:1;">'
                    + '<div style="width:44px; height:44px; border-radius:50%; background:var(--accent); color:#fff; '
                    + 'display:flex; align-items:center; justify-content:center; font-weight:700; font-size:1em; flex-shrink:0;">'
                    + initials + '</div>'
                    + '<div>'
                    + '<div style="font-weight:700; color:var(--text-primary); font-size:1.05em;">' + p.name + '</div>'
                    + '<div style="font-size:0.85em; color:var(--text-muted);">' + (p.title || 'No title') + '</div>'
                    + '<div style="font-size:0.78em; color:var(--text-muted); margin-top:3px;">' + (p.description || '') + '</div>'
                    + '</div></div>'
                    + '<div style="display:flex; gap:16px; align-items:center; flex-wrap:wrap;">'
                    + '<div style="display:flex; gap:16px; font-size:0.85em; color:var(--text-muted);">'
                    + '<span>' + skillCount + ' skills</span>'
                    + '<span>' + outcomeCount + ' outcomes</span>'
                    + '</div>'
                    + '<div style="display:flex; gap:6px;">'
                    + (showcaseMode ? '' : '<button onclick="editSampleProfile(\'' + p.id + '\');" style="padding:6px 14px; background:var(--c-surface-5); color:var(--text-secondary); border:1px solid var(--border); border-radius:6px; cursor:pointer; font-size:0.82em; font-weight:600;">Edit</button>')
                    + '<button onclick="switchProfile(\'' + p.id + '\'); switchView(\'blueprint\');" style="padding:6px 14px; background:var(--accent); color:#fff; border:none; border-radius:6px; cursor:pointer; font-size:0.82em; font-weight:600;">View</button>'
                    + '<span style="padding:6px 12px; border-radius:6px; font-size:0.78em; font-weight:600; '
                    + 'background:' + (p.enabled ? 'rgba(16,185,129,0.15)' : 'rgba(239,68,68,0.15)') + '; '
                    + 'color:' + (p.enabled ? '#10b981' : '#ef4444') + ';">' + (p.enabled ? 'Enabled' : 'Disabled') + '</span>'
                    + '</div>'
                    + '</div></div>'
                    + '</div>';
            });
            html += '</div>';
            
            el.innerHTML = html;
        }
        
        // ===== EDIT SAMPLE PROFILE =====
        function editSampleProfile(profileId) {
            if (showcaseMode) { showToast('Editing disabled in showcase mode', 'info'); return; }
            var manifest = window.profilesManifest;
            var meta = manifest && manifest.profiles ? manifest.profiles.find(function(p) { return p.id === profileId; }) : null;
            var template = templates[profileId];
            if (!meta || !template) { showToast('Profile not found', 'error'); return; }
            
            var modal = document.getElementById('exportModal');
            var modalContent = modal.querySelector('.modal-content');
            
            var skillCount = template.skills ? template.skills.length : 0;
            var roleCount = template.roles ? template.roles.length : 0;
            var outcomeCount = template.values ? template.values.length : 0;
            
            modalContent.innerHTML = '<div class="modal-header">'
                + '<div class="modal-header-left"><h2 class="modal-title">' + bpIcon('skills',18) + ' Edit Sample Profile</h2>'
                + '<p style="color:var(--text-muted); margin-top:4px; font-size:0.88em;">Changes apply to in-memory template. Export JSON to persist.</p></div>'
                + '<button class="modal-close" aria-label="Close dialog" onclick="closeExportModal()">\u00D7</button></div>'
                + '<div class="modal-body" style="padding:24px; max-height:70vh; overflow-y:auto;">'
                + '<div style="display:grid; gap:16px;">'
                + '<div><label style="font-weight:600; color:var(--text-secondary); font-size:0.85em; display:block; margin-bottom:6px;">Name</label>'
                + '<input type="text" id="editSampleName" class="settings-input" value="' + escapeHtml(template.profile.name || '') + '"></div>'
                + '<div><label style="font-weight:600; color:var(--text-secondary); font-size:0.85em; display:block; margin-bottom:6px;">Title</label>'
                + '<input type="text" id="editSampleTitle" class="settings-input" value="' + escapeHtml(template.profile.currentTitle || '') + '"></div>'
                + '<div><label style="font-weight:600; color:var(--text-secondary); font-size:0.85em; display:block; margin-bottom:6px;">Description</label>'
                + '<textarea id="editSampleDesc" class="settings-input" rows="3" style="resize:vertical;">' + escapeHtml(meta.description || '') + '</textarea></div>'
                + '<div style="display:grid; grid-template-columns:1fr 1fr; gap:12px;">'
                + '<div><label style="font-weight:600; color:var(--text-secondary); font-size:0.85em; display:block; margin-bottom:6px;">Location</label>'
                + '<input type="text" id="editSampleLocation" class="settings-input" value="' + escapeHtml(template.profile.location || '') + '"></div>'
                + '<div><label style="font-weight:600; color:var(--text-secondary); font-size:0.85em; display:block; margin-bottom:6px;">Role Level</label>'
                + '<input type="text" id="editSampleLevel" class="settings-input" value="' + escapeHtml(template.profile.roleLevel || '') + '"></div>'
                + '</div>'
                + '<div style="padding:14px; background:var(--c-surface-2); border-radius:8px; font-size:0.85em; color:var(--text-muted);">'
                + '<strong style="color:var(--text-secondary);">Profile Contents:</strong> ' + skillCount + ' skills \u00B7 ' + roleCount + ' roles \u00B7 ' + outcomeCount + ' outcomes'
                + '</div>'
                + '<div style="display:flex; gap:10px; justify-content:flex-end; margin-top:8px;">'
                + '<button onclick="exportSampleJSON(\'' + profileId + '\')" style="padding:10px 20px; background:var(--c-surface-5); border:1px solid var(--border); color:var(--text-secondary); border-radius:8px; cursor:pointer; font-weight:600; font-size:0.88em;">' + bpIcon('export',14) + ' Export JSON</button>'
                + '<button onclick="saveSampleEdits(\'' + profileId + '\')" style="padding:10px 20px; background:var(--accent); color:#fff; border:none; border-radius:8px; cursor:pointer; font-weight:600; font-size:0.88em;">' + bpIcon('check',14) + ' Save Changes</button>'
                + '</div></div></div>';
            
            modal.classList.add('active');
        }
        window.editSampleProfile = editSampleProfile;
        
        function saveSampleEdits(profileId) {
            var template = templates[profileId];
            var manifest = window.profilesManifest;
            var meta = manifest && manifest.profiles ? manifest.profiles.find(function(p) { return p.id === profileId; }) : null;
            if (!template) return;
            
            var newName = document.getElementById('editSampleName').value.trim();
            var newTitle = document.getElementById('editSampleTitle').value.trim();
            var newDesc = document.getElementById('editSampleDesc').value.trim();
            var newLocation = document.getElementById('editSampleLocation').value.trim();
            var newLevel = document.getElementById('editSampleLevel').value.trim();
            
            if (newName) template.profile.name = newName;
            if (newTitle) template.profile.currentTitle = newTitle;
            if (newLocation) template.profile.location = newLocation;
            if (newLevel) template.profile.roleLevel = newLevel;
            if (meta) {
                meta.name = newName || meta.name;
                meta.title = newTitle || meta.title;
                meta.description = newDesc;
            }
            
            // Also update templateName if it exists
            if (template.templateName) template.templateName = newName + ' - ' + newTitle;
            
            closeExportModal();
            showToast('Profile updated in memory. Export JSON to save permanently.', 'success');
            renderAdminTabContent();
        }
        window.saveSampleEdits = saveSampleEdits;
        
        function exportSampleJSON(profileId) {
            if (showcaseMode) { showToast('Exports disabled in showcase mode', 'info'); return; }
            var template = templates[profileId];
            if (!template) return;
            var json = JSON.stringify(template, null, 2);
            var blob = new Blob([json], { type: 'application/json' });
            var url = URL.createObjectURL(blob);
            var a = document.createElement('a');
            a.href = url;
            a.download = profileId + '.json';
            a.click();
            URL.revokeObjectURL(url);
            showToast('Exported ' + profileId + '.json', 'success');
        }
        window.exportSampleJSON = exportSampleJSON;
        
        function renderAdminWaitlist(el) {
            // v4.44.36: Showcase mode — show structure without PII
            if (showcaseMode) {
                el.innerHTML = '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:20px;">'
                    + '<div>'
                    + '<h3 style="font-family:Outfit,sans-serif; font-weight:700; color:var(--text-primary); margin:0; font-size:1.1em; letter-spacing:0.06em; text-transform:uppercase;">Waitlist Management</h3>'
                    + '<p style="color:var(--text-muted); font-size:0.85em; margin-top:4px;">Invite-gated access with position tracking</p>'
                    + '</div></div>'
                    + '<div style="padding:32px; text-align:center; background:var(--c-surface-2); border:1px dashed var(--c-surface-5); border-radius:12px;">'
                    + '<div style="font-size:2em; margin-bottom:8px;">🔒</div>'
                    + '<div style="color:var(--text-secondary); font-weight:600; margin-bottom:4px;">Waitlist Data Redacted</div>'
                    + '<div style="color:var(--text-muted); font-size:0.85em;">Names, emails, and invitation status are hidden in showcase mode. The waitlist system supports position tracking, batch invites, and status management.</div>'
                    + '</div>';
                return;
            }
            if (!fbDb) { el.innerHTML = '<div style="color:#ef4444;">Firebase not connected.</div>'; return; }
            
            el.innerHTML = '<div style="text-align:center; padding:40px; color:var(--text-muted);">Loading waitlist...</div>';
            
            fbDb.collection('waitlist').orderBy('createdAt', 'desc').get().then(function(snapshot) {
                var waiting = [];
                var invited = [];
                
                snapshot.forEach(function(doc) {
                    var d = doc.data();
                    d._id = doc.id;
                    if (d.status === 'invited') invited.push(d);
                    else waiting.push(d);
                });
                
                var html = '';
                
                // Summary cards
                html += '<div style="display:grid; grid-template-columns:repeat(3, 1fr); gap:16px; margin-bottom:24px;">';
                html += '<div style="padding:18px; background:var(--c-accent-bg-4b); border-radius:10px; text-align:center;">'
                    + '<div style="font-size:1.8em; font-weight:700; color:#60a5fa;">' + (waiting.length + invited.length) + '</div>'
                    + '<div style="font-size:0.82em; color:var(--text-muted);">Total</div></div>';
                html += '<div style="padding:18px; background:var(--c-amber-bg-3a); border-radius:10px; text-align:center;">'
                    + '<div style="font-size:1.8em; font-weight:700; color:#fbbf24;">' + waiting.length + '</div>'
                    + '<div style="font-size:0.82em; color:var(--text-muted);">Waiting</div></div>';
                html += '<div style="padding:18px; background:var(--c-green-bg-3a); border-radius:10px; text-align:center;">'
                    + '<div style="font-size:1.8em; font-weight:700; color:#10b981;">' + invited.length + '</div>'
                    + '<div style="font-size:0.82em; color:var(--text-muted);">Invited</div></div>';
                html += '</div>';
                
                // Waiting list
                if (waiting.length > 0) {
                    html += '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:12px;">'
                        + '<h3 style="font-family:Outfit,sans-serif; font-weight:700; color:var(--text-primary); margin:0; font-size:1em;">Waiting (' + waiting.length + ')</h3>'
                        + '<button onclick="bulkInviteWaitlist()" style="padding:8px 18px; background:#10b981; color:#fff; border:none; border-radius:8px; cursor:pointer; font-weight:600; font-size:0.85em;">Invite All</button>'
                        + '</div>';
                    
                    html += '<div style="display:grid; gap:8px; margin-bottom:24px;">';
                    waiting.forEach(function(user) {
                        var created = user.createdAt ? new Date(user.createdAt.seconds * 1000).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) : '?';
                        html += '<div style="padding:14px 16px; background:var(--c-surface-2); '
                            + 'border:1px solid var(--c-surface-5); border-radius:8px; display:flex; justify-content:space-between; align-items:center;">'
                            + '<div>'
                            + '<strong style="color:var(--text-primary);">' + escapeHtml(user.name || 'Anonymous') + '</strong>'
                            + ' <span style="font-size:0.72em; padding:2px 8px; border-radius:10px; background:var(--c-amber-bg-5a); color:#fbbf24;">' + escapeHtml(user.type || 'individual') + '</span>'
                            + '<div style="font-size:0.82em; color:var(--text-muted); margin-top:2px;">' + escapeHtml(user.email || '') + ' \u00B7 #' + (user.position || '?') + ' \u00B7 ' + created + '</div>'
                            + '</div>'
                            + '<button onclick="inviteWaitlistUser(\'' + escapeHtml(user._id) + '\', \'' + escapeHtml((user.name || '').replace(/'/g,"\\'")) + '\'); setTimeout(function(){renderAdminWaitlist(document.getElementById(\'adminTabContent\'));}, 500);" '
                            + 'style="padding:8px 16px; background:linear-gradient(135deg,#3b82f6,#1d4ed8); color:#fff; border:none; border-radius:6px; cursor:pointer; font-weight:600; font-size:0.85em; white-space:nowrap;">Invite</button>'
                            + '</div>';
                    });
                    html += '</div>';
                }
                
                // Invited list
                if (invited.length > 0) {
                    html += '<h3 style="font-family:Outfit,sans-serif; font-weight:700; color:var(--text-primary); margin:0 0 12px; font-size:1em;">Invited (' + invited.length + ')</h3>';
                    html += '<div style="display:grid; gap:6px;">';
                    invited.forEach(function(user) {
                        html += '<div style="padding:12px 16px; background:var(--c-green-bg-1b); '
                            + 'border:1px solid var(--c-green-bg-5b); border-radius:8px; display:flex; justify-content:space-between; align-items:center;">'
                            + '<div>'
                            + '<strong style="color:var(--text-primary);">' + escapeHtml(user.name || 'Anonymous') + '</strong>'
                            + ' <span style="font-size:0.72em; color:#10b981; font-weight:600;">\u2714 Invited</span>'
                            + '<div style="font-size:0.82em; color:var(--text-muted); margin-top:2px;">' + escapeHtml(user.email || '') + '</div>'
                            + '</div></div>';
                    });
                    html += '</div>';
                }
                
                if (waiting.length === 0 && invited.length === 0) {
                    html += '<div style="text-align:center; padding:40px; color:var(--text-muted);">No waitlist entries yet.</div>';
                }
                
                el.innerHTML = html;
            }).catch(function(err) {
                el.innerHTML = '<div style="color:#ef4444;">Error: ' + escapeHtml(err.message) + '</div>';
            });
        }
        
