        async function jdcAIFillValueDescs() {
            _jdcSyncFormToState();
            if (!_jdcResult || !_jdcResult.values || _jdcResult.values.length === 0) {
                showToast('No values to generate descriptions for.', 'warning');
                return;
            }
            var missing = [];
            _jdcResult.values.forEach(function(v, i) {
                var name = typeof v === 'string' ? v : (v.name || '');
                var desc = typeof v === 'object' ? (v.description || '') : '';
                if (name && !desc.trim()) missing.push({ index: i, name: name });
            });
            if (missing.length === 0) {
                showToast('All values already have descriptions.', 'info');
                return;
            }
            showToast('Generating descriptions for ' + missing.length + ' value(s)...', 'info');
            try {
                var roleCtx = (_jdcResult.title || 'professional') + ' at ' + (_jdcResult.company || 'a company');
                var valueNames = missing.map(function(m) { return m.name; }).join(', ');
                var requestBody = {
                    model: 'claude-haiku-4-5-20251001',
                    max_tokens: 1024,
                    messages: [{ role: 'user', content: 'For the role of "' + roleCtx + '", write a concise one-sentence professional description for each of these workplace values. Each description should explain what the value means in this professional context and how it manifests in day-to-day work. Return ONLY a JSON array of objects with "name" and "description" fields, no other text.\n\nValues: ' + valueNames }]
                };
                var resp = await callAnthropicAPI(requestBody, null, 'wb-value-desc-bulk');
                var text = (resp.content && resp.content[0] && resp.content[0].text) || '';
                var jsonMatch = text.match(/\[[\s\S]*\]/);
                if (!jsonMatch) throw new Error('Could not parse AI response');
                var descs = JSON.parse(jsonMatch[0]);
                var descMap = {};
                descs.forEach(function(d) { descMap[d.name.toLowerCase()] = d.description; });
                missing.forEach(function(m) {
                    var generated = descMap[m.name.toLowerCase()];
                    if (generated && _jdcResult.values[m.index]) {
                        if (typeof _jdcResult.values[m.index] === 'string') {
                            _jdcResult.values[m.index] = { name: _jdcResult.values[m.index], description: generated };
                        } else {
                            _jdcResult.values[m.index].description = generated;
                        }
                    }
                });
                renderAdminJDConverter(document.getElementById('adminTabContent'));
                showToast('AI descriptions generated for ' + missing.length + ' value(s).', 'success');
            } catch (err) {
                console.warn('AI value description error:', err);
                showToast('AI description failed: ' + err.message, 'error');
            }
        }
        window.jdcAIFillValueDescs = jdcAIFillValueDescs;

