        async function jdcAIFillDemonstrated() {
            if (!_jdcResult) return;
            _jdcSyncFormToState();
            var d = _jdcResult;
            var skills = (d.skills || []).slice(0, 10).map(function(s) { return s.name + ' (' + (s.blueprintLevel || 'Proficient') + ')'; }).join(', ');
            var valNames = (d.values || []).slice(0, 6).map(function(v) { return v.name || v; }).join(', ');
            var context = 'Role: ' + (d.title || 'Unknown Role');
            if (d.company) context += '\nCompany: ' + d.company;
            if (d.industry) context += '\nIndustry: ' + d.industry;
            if (d.location) context += '\nLocation: ' + d.location;
            if (d.seniority) context += '\nSeniority: ' + d.seniority.charAt(0).toUpperCase() + d.seniority.slice(1);
            if (d.department) context += '\nDepartment: ' + d.department;
            if (skills) context += '\nKey Skills: ' + skills;
            if (valNames) context += '\nValues: ' + valNames;
            if (d.summary) context += '\nWork Summary: ' + d.summary.substring(0, 300);

            var prompt = 'You are a career intelligence expert writing demonstrated experience evidence for a Work Blueprint.\n\n'
                + context + '\n\n'
                + 'Generate 5-7 specific, industry-verticalized demonstrated experience evidence statements for this role. '
                + 'Each statement should describe what a strong candidate in THIS SPECIFIC industry and role would have demonstrably accomplished. '
                + 'Be specific to the industry — a Strategist in HR Tech is very different from a Strategist in Healthcare or Finance. '
                + 'Use seniority-appropriate action verbs (entry: Contributed, Assisted; mid: Delivered, Executed; senior: Led, Architected; director: Directed, Scaled; executive: Set strategy for, Championed). '
                + 'Each statement should reference specific skills from the list and describe measurable or observable outcomes. '
                + 'DO NOT be generic. Ground each statement in the specific industry context, tools, workflows, and stakeholders typical of this vertical.\n\n'
                + 'Also generate a brief "Artifacts" line describing the types of tangible work products this role would produce in this industry.\n\n'
                + 'Return valid JSON: {"evidence": ["statement 1", "statement 2", ...], "artifacts": "Relevant artifacts: ..."}';

            showToast('Generating demonstrated experience...', 'info', 6000);
            try {
                var resp = await callAnthropicAPI({
                    model: 'claude-haiku-4-5-20251001',
                    max_tokens: 1200,
                    messages: [{ role: 'user', content: prompt }]
                }, null, 'wb-demonstrated');
                var text = (resp.content && resp.content[0] && resp.content[0].text) || '';
                var jsonMatch = text.match(/\{[\s\S]*\}/);
                if (jsonMatch) {
                    var result = JSON.parse(jsonMatch[0]);
                    if (result.evidence && Array.isArray(result.evidence)) {
                        var cleanEvidence = result.evidence.filter(function(e) { return typeof e === 'string' && e.trim(); }).map(function(e) { return e.trim(); }).slice(0, 10);
                        var oldArtifacts = (d.demonstrated && d.demonstrated.artifacts) || '';
                        d.demonstrated = {
                            evidence: cleanEvidence,
                            artifacts: result.artifacts || oldArtifacts
                        };
                        showToast('Demonstrated experience generated (' + result.evidence.length + ' items).', 'success');
                        var editPanel = document.getElementById('wbRepoEditOverlay');
                        if (editPanel) { _wbRepoRenderEditModal(); } else {
                            renderAdminJDConverter(document.getElementById('adminTabContent'));
                        }
                    } else {
                        showToast('AI returned unexpected format.', 'warning');
                    }
                } else {
                    showToast('AI returned no usable data.', 'warning');
                }
            } catch (err) {
                console.warn('AI demonstrated experience error:', err);
                showToast('AI failed: ' + err.message, 'error');
            }
        }
        window.jdcAIFillDemonstrated = jdcAIFillDemonstrated;

        function jdcSearchCerts(query) {
            var dropdown = document.getElementById('jdcEditCertDropdown');
            if (!dropdown) return;
            if (!query || query.length < 2) { dropdown.style.display = 'none'; return; }
            var q = query.toLowerCase();
            var lib = _wbwCertLibrary || [];
            var existing = (_jdcResult && _jdcResult.certifications || []).map(function(c) { return c.toLowerCase(); });
            var matches = lib.filter(function(c) {
                return (c.name.toLowerCase().indexOf(q) !== -1 || (c.abbr && c.abbr.toLowerCase().indexOf(q) !== -1))
                    && existing.indexOf(c.name.toLowerCase()) === -1;
            }).slice(0, 12);
            var html = '';
            matches.forEach(function(c) {
                var displayName = escapeHtml(c.name) + (c.abbr ? ' <span style="color:var(--c-muted); font-size:0.85em;">(' + escapeHtml(c.abbr) + ')</span>' : '');
                html += '<div onclick="jdcAddCert(\'' + escapeHtml(c.name).replace(/'/g, "\\'") + '\')" style="padding:8px 12px; cursor:pointer; font-size:0.88em; border-bottom:1px solid var(--c-surface-3); color:var(--c-heading);" onmouseover="this.style.background=\'var(--c-surface-3)\'" onmouseout="this.style.background=\'transparent\'">'
                    + displayName + '<span style="float:right; font-size:0.75em; color:var(--c-muted);">' + escapeHtml(c.category) + '</span></div>';
            });
            if (matches.length === 0 && query.length >= 2) {
                html += '<div onclick="jdcAddCert(\'' + escapeHtml(query).replace(/'/g, "\\'") + '\')" style="padding:8px 12px; cursor:pointer; font-size:0.88em; color:var(--accent);" onmouseover="this.style.background=\'var(--c-surface-3)\'" onmouseout="this.style.background=\'transparent\'">'
                    + bpIcon('plus',12) + ' Add "' + escapeHtml(query) + '" as custom</div>';
            }
            dropdown.innerHTML = html;
            dropdown.style.display = html ? 'block' : 'none';
        }
        window.jdcSearchCerts = jdcSearchCerts;

