        var _jdcSaving = false;
        function jdcSaveToRepository() {
            if (!_jdcResult) { showToast('No blueprint to save.', 'warning'); return; }
            if (!fbUser) { showToast('Sign in to save blueprints.', 'warning'); return; }
            if (_jdcSaving) { return; }
            _jdcSaving = true;
            var d = _jdcPrepareExport();
            d.savedAt = firebase.firestore.FieldValue.serverTimestamp();
            d.savedBy = fbUser.uid;
            d.id = d.id || ('wb_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6));
            _jdcResult.id = d.id;
            fbDb.collection('users').doc(fbUser.uid).collection('work_blueprints').doc(d.id).set(d, { merge: true })
                .then(function() {
                    _jdcSaving = false;
                    _jdcSavedState = true;
                    showToast('Work Blueprint saved.', 'success');
                    logAnalyticsEvent(_jdcFromRepo ? 'wb_edited' : 'wb_created', { title: d.title || '', company: d.company || '' });
                    _jdcRepoCache = null;
                    _wbRepoCache = null;
                    if (_jdcFromRepo) {
                        _jdcFromRepo = false;
                        _jdcResult = null;
                        _jdcEditMode = false;
                        adminSubTab = 'wbrepo';
                        renderAdminTabContent();
                    } else {
                        _jdcFromRepo = true;
                        _jdcEditMode = false;
                        renderAdminJDConverter(document.getElementById('adminTabContent'));
                    }
                })
                .catch(function(err) {
                    _jdcSaving = false;
                    console.warn('Save blueprint error:', err);
                    showToast('Failed to save: ' + err.message, 'error');
                });
        }
        window.jdcSaveToRepository = jdcSaveToRepository;

        var _jdcRepoCache = null;
        function jdcLoadRepository() {
            adminSubTab = 'wbrepo';
            renderAdminTabContent();
        }
        window.jdcLoadRepository = jdcLoadRepository;

