        function _wbRepoLoadData() {
            fbDb.collection('users').doc(fbUser.uid).collection('work_blueprints').orderBy('savedAt', 'desc').get()
                .then(function(snapshot) {
                    _wbRepoCache = [];
                    snapshot.forEach(function(doc) {
                        var data = doc.data();
                        data.id = doc.id;
                        _wbRepoCache.push(data);
                    });
                    renderAdminWBRepo(document.getElementById('adminTabContent'));
                })
                .catch(function(err) {
                    console.warn('Load repository error:', err);
                    showToast('Failed to load repository: ' + err.message, 'error');
                    _wbRepoCache = [];
                    renderAdminWBRepo(document.getElementById('adminTabContent'));
                });
        }

