        function wbRepoDelete(id) {
            if (!fbUser) { showToast('You must be signed in to delete blueprints.', 'warning'); return; }
            if (!id) { showToast('Blueprint ID missing — cannot delete.', 'error'); return; }
            if (!fbDb) { showToast('Database not available. Try refreshing.', 'error'); return; }
            if (!confirm('Delete this Work Blueprint from your repository? This cannot be undone.')) return;
            showToast('Deleting blueprint...', 'info', 2000);
            try {
                fbDb.collection('users').doc(fbUser.uid).collection('work_blueprints').doc(id).delete()
                    .then(function() {
                        showToast('Blueprint deleted successfully.', 'success');
                        logAnalyticsEvent('wb_deleted', { id: id });
                        _wbRepoCache = null;
                        _wbRepoViewIdx = -1;
                        renderAdminWBRepo(document.getElementById('adminTabContent'));
                    })
                    .catch(function(err) {
                        console.error('WB Repository delete error:', err);
                        var msg = err.message || '';
                        if (err.code === 'permission-denied' || msg.indexOf('permission') !== -1 || msg.indexOf('PERMISSION_DENIED') !== -1) {
                            showToast('Permission denied. Firestore rules may need to be deployed. Contact admin.', 'error', 8000);
                        } else {
                            showToast('Delete failed: ' + (msg || 'Unknown error. Check your connection.'), 'error', 6000);
                        }
                    });
            } catch(e) {
                console.error('WB delete exception:', e);
                showToast('Delete error: ' + e.message, 'error', 6000);
            }
        }
        window.wbRepoDelete = wbRepoDelete;

        function wbRepoClone(idx) {
            if (!fbUser) { showToast('You must be signed in to clone blueprints.', 'warning'); return; }
            if (!fbDb) { showToast('Database not available. Try refreshing.', 'error'); return; }
            if (!_wbRepoCache || !_wbRepoCache[idx]) { showToast('Blueprint not found.', 'error'); return; }
            var src = _wbRepoCache[idx];
            var clone = JSON.parse(JSON.stringify(src));
            delete clone.id;
            clone.title = (clone.title || 'Untitled') + ' (Copy)';
            clone.createdAt = new Date().toISOString();
            clone.clonedFrom = src.id || null;
            showToast('Cloning blueprint...', 'info', 2000);
            try {
                fbDb.collection('users').doc(fbUser.uid).collection('work_blueprints').add(Object.assign({}, clone, { savedAt: firebase.firestore.FieldValue.serverTimestamp() }))
                    .then(function(docRef) {
                        showToast('Blueprint cloned successfully.', 'success');
                        logAnalyticsEvent('wb_cloned', { sourceId: src.id || '', newId: docRef.id, title: clone.title });
                        _wbRepoCache = null;
                        _wbRepoViewIdx = -1;
                        renderAdminWBRepo(document.getElementById('adminTabContent'));
                    })
                    .catch(function(err) {
                        console.error('WB Repository clone error:', err);
                        var msg = err.message || '';
                        if (err.code === 'permission-denied' || msg.indexOf('permission') !== -1 || msg.indexOf('PERMISSION_DENIED') !== -1) {
                            showToast('Permission denied. Firestore rules may need to be deployed. Contact admin.', 'error', 8000);
                        } else {
                            showToast('Clone failed: ' + (msg || 'Unknown error. Check your connection.'), 'error', 6000);
                        }
                    });
            } catch(e) {
                console.error('WB clone exception:', e);
                showToast('Clone error: ' + e.message, 'error', 6000);
            }
        }
