        var _wbCompareCandidate = null;
        function _wbLoadCompareCandidate() {
            if (_wbCompareCandidate) return Promise.resolve(_wbCompareCandidate);
            return fetch('profiles/demo/comparison-candidate.json?v=' + Date.now()).then(function(r) { return r.json(); }).then(function(data) {
                _wbCompareCandidate = data;
                return data;
            });
        }

        function _wbCompareFuzzyValues(candidateValues, companyValObj) {
            if (!companyValObj || !candidateValues || candidateValues.length === 0) return null;
            var userSelected = candidateValues.filter(function(v) { return v && v.selected; }).map(function(v) { return (v.name || '').toLowerCase().trim(); });
            if (userSelected.length === 0) return null;
            var companyAll = (companyValObj.primary || []).concat(companyValObj.secondary || []);
            if (companyAll.length === 0) return null;
            var companyPrimary = new Set((companyValObj.primary || []).map(function(v) { return v.toLowerCase().trim(); }));
            var companyLower = companyAll.map(function(v) { return v.toLowerCase().trim(); });

            // Value synonym clusters — maps conceptually equivalent values
            var VALUE_SYNONYMS = {
                'trust': ['integrity', 'honesty', 'transparency', 'ethics', 'reliability', 'trustworthiness', 'ethical behavior'],
                'integrity': ['trust', 'honesty', 'transparency', 'ethics', 'ethical behavior', 'trustworthiness'],
                'transparency': ['trust', 'honesty', 'openness', 'integrity', 'candor'],
                'honesty': ['trust', 'integrity', 'transparency', 'ethics', 'candor'],
                'customer success': ['customer focus', 'customer first', 'client focus', 'customer obsession', 'customer satisfaction', 'customer centricity', 'service excellence'],
                'customer focus': ['customer success', 'customer first', 'client focus', 'customer obsession', 'customer centricity'],
                'customer obsession': ['customer focus', 'customer success', 'customer first'],
                'innovation': ['creativity', 'continuous improvement', 'ingenuity', 'inventiveness', 'forward thinking', 'bold thinking', 'experimentation'],
                'creativity': ['innovation', 'creative thinking', 'ingenuity', 'inventiveness'],
                'continuous improvement': ['innovation', 'kaizen', 'growth mindset', 'learning'],
                'equality': ['diversity', 'inclusion', 'equity', 'fairness', 'belonging', 'equal opportunity', 'diversity and inclusion', 'deib'],
                'diversity': ['equality', 'inclusion', 'equity', 'belonging', 'diversity and inclusion'],
                'inclusion': ['equality', 'diversity', 'belonging', 'equity', 'accessibility'],
                'equity': ['equality', 'fairness', 'inclusion', 'diversity'],
                'sustainability': ['social responsibility', 'environmental responsibility', 'corporate responsibility', 'stewardship', 'impact', 'giving back', 'community'],
                'social responsibility': ['sustainability', 'community', 'giving back', 'corporate responsibility', 'impact'],
                'community': ['sustainability', 'social responsibility', 'giving back', 'belonging'],
                'collaboration': ['teamwork', 'partnership', 'together', 'team spirit', 'ohana', 'family'],
                'teamwork': ['collaboration', 'partnership', 'together', 'cooperation'],
                'excellence': ['quality', 'high standards', 'best in class', 'world class', 'mastery'],
                'quality': ['excellence', 'high standards', 'craftsmanship', 'precision'],
                'accountability': ['ownership', 'responsibility', 'reliability', 'dependability'],
                'ownership': ['accountability', 'responsibility', 'empowerment', 'initiative'],
                'respect': ['dignity', 'empathy', 'compassion', 'kindness', 'humanity'],
                'empathy': ['respect', 'compassion', 'understanding', 'humanity', 'kindness'],
                'courage': ['boldness', 'bravery', 'risk-taking', 'fearlessness', 'bold thinking'],
                'growth': ['learning', 'development', 'growth mindset', 'continuous learning', 'self-improvement'],
                'learning': ['growth', 'curiosity', 'continuous learning', 'development', 'growth mindset'],
                'passion': ['enthusiasm', 'drive', 'dedication', 'commitment', 'energy'],
                'work-life balance': ['wellbeing', 'wellness', 'balance', 'flexibility', 'health'],
                'wellbeing': ['work-life balance', 'wellness', 'health', 'balance'],
                'autonomy': ['independence', 'freedom', 'empowerment', 'self-direction'],
                'empowerment': ['autonomy', 'ownership', 'trust', 'independence'],
                'impact': ['making a difference', 'purpose', 'meaningful work', 'social responsibility'],
                'purpose': ['impact', 'meaning', 'mission', 'making a difference'],
                'agility': ['adaptability', 'flexibility', 'speed', 'nimbleness', 'responsiveness'],
                'adaptability': ['agility', 'flexibility', 'resilience', 'change readiness']
            };

            function getValueSynonyms(valLower) {
                return VALUE_SYNONYMS[valLower] || [];
            }

            function wordsOf(s) { return s.replace(/[^a-z0-9\s]/g, '').split(/\s+/).filter(function(w) { return w.length > 2; }); }
            
            function fuzzyMatch(a, b) {
                if (a === b) return 1.0;
                // Synonym match
                var aSyns = getValueSynonyms(a);
                if (aSyns.indexOf(b) !== -1) return 0.90;
                var bSyns = getValueSynonyms(b);
                if (bSyns.indexOf(a) !== -1) return 0.90;
                // Cross-synonym: check if any synonym of a matches any synonym of b
                for (var i = 0; i < aSyns.length; i++) {
                    if (bSyns.indexOf(aSyns[i]) !== -1) return 0.80;
                }
                // Substring containment
                if (a.indexOf(b) >= 0 || b.indexOf(a) >= 0) return 0.85;
                // Word overlap
                var wa = wordsOf(a), wb = wordsOf(b);
                if (wa.length === 0 || wb.length === 0) return 0;
                var shared = 0;
                wa.forEach(function(w) { if (wb.indexOf(w) >= 0) shared++; });
                var overlap = shared / Math.max(wa.length, wb.length);
                return overlap >= 0.5 ? overlap * 0.8 : 0;
            }

            var aligned = [], yourPriority = [], theirPriority = [];
            var matchedCompany = new Set();
            var companyMatchScores = {}; // track best match score per company value

            userSelected.forEach(function(uv) {
                var bestScore = 0, bestMatch = '';
                companyLower.forEach(function(cv) {
                    var sc = fuzzyMatch(uv, cv);
                    if (sc > bestScore) { bestScore = sc; bestMatch = cv; }
                });
                if (bestScore >= 0.4) {
                    aligned.push({ name: uv, strength: companyPrimary.has(bestMatch) ? 'primary' : 'secondary', score: bestScore });
                    matchedCompany.add(bestMatch);
                    // Track best score per company value (multiple candidates can match same company value)
                    if (!companyMatchScores[bestMatch] || bestScore > companyMatchScores[bestMatch]) {
                        companyMatchScores[bestMatch] = bestScore;
                    }
                } else {
                    yourPriority.push({ name: uv });
                }
            });

            companyLower.forEach(function(cv) {
                if (!matchedCompany.has(cv)) {
                    theirPriority.push({ name: cv, strength: companyPrimary.has(cv) ? 'primary' : 'secondary' });
                }
            });

            // Score based on company values coverage (not candidate count)
            // How well does this candidate cover what the company cares about?
            var maxScore = 0;
            companyLower.forEach(function(cv) {
                maxScore += companyPrimary.has(cv) ? 20 : 10;
            });
            var rawScore = 0;
            Object.keys(companyMatchScores).forEach(function(cv) {
                var weight = companyPrimary.has(cv) ? 20 : 10;
                rawScore += weight * (companyMatchScores[cv] || 1);
            });
            var score = maxScore > 0 ? Math.max(0, Math.min(100, Math.round((rawScore / maxScore) * 100))) : 0;

            return {
                score: score,
                aligned: aligned,
                yourPriority: yourPriority,
                theirPriority: theirPriority,
                tensionRisk: [],
                companyStory: companyValObj.story || '',
                isInferred: companyValObj.inferred || false
            };
        }

        function _wbCompareRawJDMatch(rawJDText, candidateProfile) {
            var candidateSkills = JSON.parse(JSON.stringify(candidateProfile.skills || []));
            var parsed = parseJobLocally(rawJDText);
            var extractedSkills = (parsed.skills || []).map(function(s) {
                if (typeof s === 'string') return { name: s, requirement: 'Required', proficiency: 'Proficient' };
                return s;
            }).filter(function(s) { return s && s.name; });
            
            // Apply quality filter to raw JD extraction (same filter as WB skills)
            extractedSkills = _wbSkillQualityFilter(extractedSkills);

            var candidateMap = {};
            var candidateIndex = [];
            candidateSkills.forEach(function(s) {
                var lower = s.name.toLowerCase();
                candidateMap[lower] = s;
                candidateIndex.push({ lower: lower, skill: s, words: lower.split(/[\s\-\/&]+/).filter(function(w) { return w.length > 2; }) });
                var simplified = lower.replace(/\s*&\s*/g, ' ').replace(/\s+/g, ' ').trim();
                if (simplified !== lower) candidateMap[simplified] = s;
                var synonyms = getSkillSynonyms(lower);
                synonyms.forEach(function(syn) { if (!candidateMap[syn]) candidateMap[syn] = s; });
            });

            var matched = [], gaps = [];
            var matchedCandidateSkills = new Set();
            var totalWeight = 0, earnedWeight = 0;

            extractedSkills.forEach(function(jobSkill) {
                var requirement = jobSkill.requirement || jobSkill.level || 'Required';
                var reqWeight = requirement === 'Required' ? 3 : requirement === 'Preferred' ? 2 : 1;
                totalWeight += reqWeight;
                var jLower = jobSkill.name.toLowerCase();
                var jWords = jLower.split(/[\s\-\/&]+/).filter(function(w) { return w.length > 2; });
                var found = null, nameMatchQuality = 0;

                if (candidateMap[jLower]) { found = candidateMap[jLower]; nameMatchQuality = 1.0; }
                if (!found) {
                    for (var key in candidateMap) {
                        if (key.length > 4 && jLower === key) {
                            found = candidateMap[key]; nameMatchQuality = 1.0; break;
                        }
                        if (key.length > 4 && (jLower.indexOf(key) !== -1 || key.indexOf(jLower) !== -1)) {
                            found = candidateMap[key]; nameMatchQuality = 0.75; break;
                        }
                    }
                }
                if (!found && jWords.length >= 2) {
                    var bestOverlap = 0, bestSkill = null;
                    candidateIndex.forEach(function(entry) {
                        var overlap = 0;
                        jWords.forEach(function(jw) {
                            if (entry.words.some(function(uw) {
                                if (uw === jw) return true;
                                // Stem matching
                                var jwStem = _stemEquiv[jw];
                                var uwStem = _stemEquiv[uw];
                                if (jwStem && (jwStem === uw || jwStem === uwStem)) return true;
                                if (uwStem && uwStem === jw) return true;
                                return false;
                            })) overlap++;
                        });
                        var score = overlap / Math.max(jWords.length, 1);
                        if (score > bestOverlap && score >= 0.6) { bestOverlap = score; bestSkill = entry.skill; }
                    });
                    if (bestSkill) { found = bestSkill; nameMatchQuality = bestOverlap * 0.65; }
                }

                if (found && !matchedCandidateSkills.has(found.name.toLowerCase())) {
                    earnedWeight += reqWeight * nameMatchQuality;
                    matched.push({
                        jobSkill: jobSkill.name, userSkill: found.name, userLevel: found.level,
                        jobProficiency: 'Unknown', requirement: requirement,
                        nameMatch: nameMatchQuality, profMatch: 1.0, profGap: false
                    });
                    matchedCandidateSkills.add(found.name.toLowerCase());
                } else if (!found) {
                    gaps.push({ name: jobSkill.name, requirement: requirement, proficiency: 'Unknown' });
                }
            });

            var surplus = [];
            candidateSkills.forEach(function(s) {
                if (!matchedCandidateSkills.has(s.name.toLowerCase())) {
                    surplus.push({ name: s.name, level: s.level, category: s.category });
                }
            });

            var score = totalWeight > 0 ? Math.round((earnedWeight / totalWeight) * 100) : 0;

            var companyValObj = inferCompanyValuesFromJD(rawJDText);
            var valResult = null;
            if (candidateProfile.values && companyValObj) {
                valResult = _wbCompareFuzzyValues(candidateProfile.values, companyValObj);
            }

            return {
                score: Math.min(score, 100),
                matched: matched,
                gaps: gaps,
                surplus: surplus,
                skillsExtracted: extractedSkills.length,
                parsedTitle: parsed.title || '',
                parsedCompany: parsed.company || '',
                parsedSeniority: parsed.seniority || '',
                valuesScore: valResult ? valResult.score : 0,
                valuesAligned: valResult ? (valResult.aligned || []).length : 0,
                valuesInferred: companyValObj ? (companyValObj.primary || []).concat(companyValObj.secondary || []).length : 0,
                valuesDetail: valResult,
                companyValues: companyValObj
            };
        }

        function _wbSkillQualityFilter(skills) {
            var sentenceIndicators = /\b(the ability to|ability to|and the|or the|within a|such as|in order to|responsible for|as well as|including but|with a focus|ensure that|across the|deliver on|drive the|build and|lead and|manage and|develop and|partner with|work with|collaborate with|delivering|articulate|leverage)\b/i;
            // Common English words that leak through JD parsing but aren't skills
            var commonWordBlocklist = {
                'plan': 1, 'plans': 1, 'planning': 1, 'sing': 1, 'less': 1, 'more': 1,
                'work': 1, 'working': 1, 'make': 1, 'making': 1, 'use': 1, 'using': 1,
                'build': 1, 'building': 1, 'create': 1, 'creating': 1, 'drive': 1, 'driving': 1,
                'lead': 1, 'leading': 1, 'manage': 1, 'managing': 1, 'develop': 1, 'developing': 1,
                'support': 1, 'ensure': 1, 'provide': 1, 'focus': 1, 'help': 1, 'grow': 1,
                'growth': 1, 'role': 1, 'team': 1, 'teams': 1, 'business': 1, 'will': 1,
                'strong': 1, 'key': 1, 'new': 1, 'high': 1, 'level': 1, 'well': 1,
                'best': 1, 'good': 1, 'great': 1, 'able': 1, 'also': 1, 'must': 1,
                'need': 1, 'year': 1, 'years': 1, 'time': 1, 'full': 1, 'part': 1,
                'long': 1, 'term': 1, 'range': 1, 'apply': 1, 'share': 1, 'open': 1,
                'join': 1, 'save': 1, 'post': 1, 'posted': 1, 'date': 1, 'yes': 1,
                'content': 1, 'click': 1, 'accept': 1, 'skip': 1, 'main': 1, 'only': 1,
                'training': 1, 'modeling': 1, 'economics': 1, 'accounting': 1,
                'compensation': 1, 'adaptability': 1,
                // Personality traits / values, not skills
                'composure': 1, 'curiosity': 1, 'integrity': 1, 'empathy': 1,
                'humility': 1, 'courage': 1, 'patience': 1, 'resilience': 1,
                'grit': 1, 'tenacity': 1, 'passion': 1, 'enthusiasm': 1,
                // Fragment leaks
                'ashing': 1, 'tform': 1, 'monit': 1, 'staf': 1, 'hypot': 1,
                'analy': 1, 'forma': 1, 'techni': 1, 'specif': 1
            };
            // Terms that look like skills but are actually financial/business metrics
            var metricBlocklist = /^(gross margin|net margin|ebitda|revenue|profit|margin|quota|target|headcount|turnover|attrition|run rate|burn rate|cagr|arpu|arr|mrr|nps|csat|ltv|cac|roi)$/i;
            
            return skills.filter(function(s) {
                var name = (s.name || '').trim();
                if (name.length < 2 || name.length > 35) return false;
                var wordCount = name.split(/\s+/).length;
                if (wordCount > 5) return false;
                if (sentenceIndicators.test(name)) return false;
                if (/^(the|a|an|to|in|on|at|by|for|or|and|of)\s/i.test(name)) return false;
                // Admin blocklist
                if (typeof isSkillBlocklisted === 'function' && isSkillBlocklisted(name)) return false;
                // Metrics, not skills
                if (metricBlocklist.test(name)) return false;
                // Single words: must be at least 5 chars and not in common word blocklist
                if (wordCount === 1) {
                    if (name.length < 5) return false;
                    if (commonWordBlocklist[name.toLowerCase()]) return false;
                }
                return true;
            });
        }

        function _wbCompareStructuredMatch(workBlueprint, candidateProfile) {
            var candidateSkills = JSON.parse(JSON.stringify(candidateProfile.skills || []));
            var rawWbSkills = (workBlueprint.skills || []).map(function(s) {
                var bl = s.blueprintLevel || s.level || 'Proficient';
                return { name: s.name, requirement: s.requirement || 'Required', proficiency: bl, category: s.category || 'General' };
            });
            var wbSkills = _wbSkillQualityFilter(rawWbSkills);

            // O*NET enrichment blocklist — these generic abilities appear on 90%+ of occupations
            // and never appear as explicit candidate skills, so they inflate the denominator with zero upside
            var ENRICHMENT_BLOCKLIST = {
                'active listening': 1, 'reading comprehension': 1, 'speaking': 1, 'writing': 1,
                'monitoring': 1, 'social perceptiveness': 1, 'coordination': 1, 'time management': 1,
                'critical thinking': 1, 'judgment and decision making': 1, 'complex problem solving': 1,
                'active learning': 1, 'learning strategies': 1, 'oral comprehension': 1,
                'oral expression': 1, 'written comprehension': 1, 'written expression': 1,
                'speech recognition': 1, 'speech clarity': 1, 'deductive reasoning': 1,
                'inductive reasoning': 1, 'problem sensitivity': 1, 'near vision': 1,
                'information ordering': 1, 'fluency of ideas': 1, 'originality': 1,
                'category flexibility': 1, 'selective attention': 1, 'time sharing': 1,
                // Additional generic items that inflate denominator without adding match signal
                'service orientation': 1, 'systems evaluation': 1, 'persuasion': 1,
                'instructing': 1, 'operation monitoring': 1, 'operation and control': 1,
                'repairing': 1, 'equipment maintenance': 1, 'equipment selection': 1,
                'installation': 1, 'troubleshooting': 1, 'quality control analysis': 1,
                'english language': 1, 'clerical': 1, 'telecommunications': 1,
                'mathematics': 1, 'science': 1
            };

            if (wbSkills.length < 8 && workBlueprint.title) {
                var socResult = typeof resolveTitle === 'function' ? resolveTitle(workBlueprint.title) : null;
                if (socResult && window.onetCrosswalk) {
                    var occData = window.onetCrosswalk.occupations[socResult.soc];
                    if (occData) {
                        var existingNames = {};
                        wbSkills.forEach(function(s) { existingNames[s.name.toLowerCase()] = true; });
                        var seniority = workBlueprint.seniority || 'mid';
                        var seniorityDefaults = { entry: 'Foundational', mid: 'Proficient', senior: 'Advanced', director: 'Expert', executive: 'Expert' };
                        var defaultLevel = seniorityDefaults[seniority] || 'Proficient';
                        ['skills'].forEach(function(type) {
                            (occData[type] || []).forEach(function(oSkill) {
                                if (wbSkills.length >= WB_SKILL_CAP) return;
                                var oName = oSkill.name;
                                var oLower = oName.toLowerCase();
                                // Skip generic abilities that match everything
                                if (ENRICHMENT_BLOCKLIST[oLower]) return;
                                if (!existingNames[oLower]) {
                                    existingNames[oLower] = true;
                                    wbSkills.push({
                                        name: oName,
                                        requirement: (oSkill.importance || 50) >= 60 ? 'Required' : 'Preferred',
                                        proficiency: oSkill.blueprintLevel || defaultLevel,
                                        category: type,
                                        source: 'onet-enriched'
                                    });
                                }
                            });
                        });
                    }
                }
            }

            var candidateMap = {};
            var candidateIndex = [];
            candidateSkills.forEach(function(s) {
                var lower = s.name.toLowerCase();
                candidateMap[lower] = s;
                candidateIndex.push({ lower: lower, skill: s, words: lower.split(/[\s\-\/&]+/).filter(function(w) { return w.length > 2; }) });
                var simplified = lower.replace(/\s*&\s*/g, ' ').replace(/\s+/g, ' ').trim();
                if (simplified !== lower) candidateMap[simplified] = s;
                var synonyms = getSkillSynonyms(lower);
                synonyms.forEach(function(syn) { if (!candidateMap[syn]) candidateMap[syn] = s; });
            });

            var matched = [], gaps = [];
            var matchedCandidateSkills = new Set();
            var totalWeight = 0, earnedWeight = 0;

            wbSkills.forEach(function(jobSkill) {
                var requirement = jobSkill.requirement || 'Required';
                var reqWeight = requirement === 'Required' ? 3 : requirement === 'Preferred' ? 2 : 1;
                totalWeight += reqWeight;
                var jobProf = proficiencyValue(jobSkill.proficiency || 'Proficient');
                var jLower = jobSkill.name.toLowerCase();
                var jWords = jLower.split(/[\s\-\/&]+/).filter(function(w) { return w.length > 2; });
                var found = null, nameMatchQuality = 0;

                if (candidateMap[jLower]) { found = candidateMap[jLower]; nameMatchQuality = 1.0; }
                if (!found) {
                    var jobSynonyms = getSkillSynonyms(jLower);
                    for (var si = 0; si < jobSynonyms.length; si++) {
                        if (candidateMap[jobSynonyms[si]]) { found = candidateMap[jobSynonyms[si]]; nameMatchQuality = 0.95; break; }
                    }
                }
                if (!found) {
                    for (var key in candidateMap) {
                        if (key.length > 3 && (jLower.indexOf(key) !== -1 || key.indexOf(jLower) !== -1)) {
                            found = candidateMap[key]; nameMatchQuality = 0.85; break;
                        }
                    }
                }
                if (!found && jWords.length > 0) {
                    var bestOverlap = 0, bestSkill = null;
                    candidateIndex.forEach(function(entry) {
                        var overlap = 0;
                        jWords.forEach(function(jw) {
                            if (entry.words.some(function(uw) {
                                if (uw === jw) return true;
                                if (uw.length > 4 && (uw.indexOf(jw) !== -1 || jw.indexOf(uw) !== -1)) return true;
                                // Stem matching: planning↔plan, strategic↔strategy, etc.
                                var jwStem = _stemEquiv[jw];
                                var uwStem = _stemEquiv[uw];
                                if (jwStem && (jwStem === uw || jwStem === uwStem)) return true;
                                if (uwStem && uwStem === jw) return true;
                                return false;
                            })) overlap++;
                        });
                        var score = overlap / Math.max(jWords.length, 1);
                        if (score > bestOverlap && score >= 0.35) { bestOverlap = score; bestSkill = entry.skill; }
                    });
                    if (bestSkill) { found = bestSkill; nameMatchQuality = bestOverlap * 0.75; }
                }

                if (found) {
                    var userProf = proficiencyValue(found.level);
                    var profMatch = userProf >= jobProf ? 1.0 : userProf / jobProf;
                    var alreadyUsed = matchedCandidateSkills.has(found.name.toLowerCase());
                    if (alreadyUsed) {
                        nameMatchQuality = nameMatchQuality * 0.5;
                    }
                    earnedWeight += reqWeight * nameMatchQuality * profMatch;
                    matched.push({
                        jobSkill: jobSkill.name, userSkill: found.name, userLevel: found.level,
                        jobProficiency: jobSkill.proficiency || 'Proficient', requirement: requirement,
                        nameMatch: nameMatchQuality, profMatch: profMatch, profGap: userProf < jobProf,
                        shared: alreadyUsed
                    });
                    matchedCandidateSkills.add(found.name.toLowerCase());
                } else {
                    gaps.push({ name: jobSkill.name, requirement: requirement, proficiency: jobSkill.proficiency || 'Proficient' });
                }
            });

            var surplus = [];
            candidateSkills.forEach(function(s) {
                if (!matchedCandidateSkills.has(s.name.toLowerCase())) {
                    surplus.push({ name: s.name, level: s.level, category: s.category });
                }
            });

            var wbProfMeets = 0, wbProfGaps = 0;
            matched.forEach(function(m) { if (m.profGap) wbProfGaps++; else wbProfMeets++; });

            var candidateEvidence = 0;
            candidateSkills.forEach(function(s) {
                if (s.evidence && s.evidence.length > 0) candidateEvidence += s.evidence.length;
            });
            var matchedEvidence = 0;
            matched.forEach(function(m) {
                var cs = candidateSkills.find(function(s) { return s.name === m.userSkill; });
                if (cs && cs.evidence) matchedEvidence += cs.evidence.length;
            });

            var wbValues = (workBlueprint.values || []).map(function(v) {
                return { name: v.name || v, desc: v.desc || v.description || '' };
            });
            
            // ── Company Values Lookup ──
            // Priority: pre-resolved from ensureCompanyValues() → DB lookup → WB stored values
            var companyValObj = null;
            if (workBlueprint._resolvedCompanyValues) {
                companyValObj = workBlueprint._resolvedCompanyValues;
                console.log('[COMPARE] Company values (pre-resolved): ' + (companyValObj.primary || []).join(', '));
            } else if (workBlueprint.company && window.companyDataLoaded) {
                var lookedUp = getCompanyValues(workBlueprint.company, '');
                if (lookedUp && !lookedUp.inferred && lookedUp.primary && lookedUp.primary.length > 0) {
                    companyValObj = lookedUp;
                    console.log('[COMPARE] Company values from DB: ' + workBlueprint.company + ' → ' + (lookedUp.primary || []).join(', '));
                }
            }
            // Fallback: construct from WB stored values
            if (!companyValObj) {
                companyValObj = {
                    primary: wbValues.slice(0, Math.ceil(wbValues.length / 2)).map(function(v) { return v.name; }),
                    secondary: wbValues.slice(Math.ceil(wbValues.length / 2)).map(function(v) { return v.name; }),
                    tensions: [], story: '', inferred: false
                };
            }
            var valResult = null;
            if (wbValues.length > 0 && candidateProfile.values) {
                valResult = _wbCompareFuzzyValues(candidateProfile.values, companyValObj);
                if (valResult) {
                    console.log('[COMPARE] Values: company=' + (companyValObj.primary || []).join(', ') + ' | aligned=' + (valResult.aligned || []).map(function(a) { return a.name; }).join(', ') + ' | score=' + valResult.score + '%');
                }
            }

            var score = totalWeight > 0 ? Math.round((earnedWeight / totalWeight) * 100) : 0;
            
            // ── Structured Intelligence Bonus ──
            // The WB has structured data (proficiency levels, evidence, values) that raw JD can't provide.
            // Credit the WB for this additional intelligence dimension.
            var structuredBonus = 0;
            // Proficiency validation bonus: if matched skills meet required levels, that's worth something
            if (matched.length > 0) {
                var profRatio = wbProfMeets / Math.max(matched.length, 1);
                structuredBonus += Math.round(profRatio * 10); // up to +10 for 100% proficiency fit
            }
            // Evidence bonus: validated evidence points demonstrate real capability
            if (matchedEvidence > 0) {
                structuredBonus += Math.min(Math.round(matchedEvidence * 2), 8); // up to +8 for evidence
            }
            // Values alignment bonus
            if (valResult && valResult.score > 0) {
                structuredBonus += Math.min(Math.round(valResult.score / 15), 5); // up to +5 for values
            }
            score = Math.min(score + structuredBonus, 100);
            
            return {
                score: score,
                matched: matched,
                gaps: gaps,
                surplus: surplus,
                skillsUsed: wbSkills.length,
                skillsFiltered: rawWbSkills.length - wbSkills.length,
                structuredBonus: structuredBonus,
                profMeets: wbProfMeets,
                profGaps: wbProfGaps,
                evidencePoints: matchedEvidence,
                totalEvidence: candidateEvidence,
                valuesScore: valResult ? valResult.score : 0,
                valuesAligned: valResult ? (valResult.aligned || []).length : 0,
                valuesTotal: wbValues.length,
                valuesDetail: valResult,
                companyValues: companyValObj,
                wbValues: wbValues
            };
        }

        function _wbCompareRunBoth(rawJDText, wb, candidate) {
            var rawResult = _wbCompareRawJDMatch(rawJDText, candidate);
            var structResult = _wbCompareStructuredMatch(wb, candidate);
            console.log('[COMPARE] Raw JD: ' + rawResult.skillsExtracted + ' skills extracted, ' + rawResult.matched.length + ' matched, score=' + rawResult.score);
            console.log('[COMPARE] WB: ' + structResult.skillsUsed + ' skills (' + (structResult.skillsFiltered || 0) + ' filtered), ' + structResult.matched.length + ' matched, score=' + structResult.score + ' (bonus=' + (structResult.structuredBonus || 0) + ')');
            return { raw: rawResult, struct: structResult };
        }

        // ── Values Detail Section ──
        // Shows fully transparent values matching with every mapping visible
        function _wbCompareValuesDetail(structResult) {
            if (!structResult) return '';
            var valDetail = structResult.valuesDetail;
            var compVals = structResult.companyValues;
            var wbVals = structResult.wbValues || [];
            
            if (!compVals || !(compVals.primary || []).length) return '';
            
            var html = '<div style="margin-bottom:20px; padding:20px; background:var(--c-surface-2); border-radius:12px; border:1px solid var(--c-surface-3);">';
            
            // Header with score
            var score = structResult.valuesScore || 0;
            var scoreColor = score >= 60 ? '#10b981' : score >= 30 ? '#f59e0b' : '#ef4444';
            html += '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:16px;">'
                + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:1em; color:var(--c-heading);">'
                + bpIcon('heart', 16) + ' Values Alignment Detail</div>'
                + '<div style="display:flex; align-items:center; gap:8px;">'
                + '<div style="font-size:1.1em; font-weight:700; color:' + scoreColor + ';">' + score + '%</div>'
                + '<div style="font-size:0.72em; color:var(--c-muted);">alignment</div>'
                + '</div></div>';
            
            // Company Values Source
            var allCompany = (compVals.primary || []).concat(compVals.secondary || []);
            var sourceLabel = compVals._source === 'ai-discovered' ? 'AI-sourced' : compVals.inferred ? 'Inferred from JD' : 'Company database';
            var sourceIcon = compVals.inferred ? '\u26A0' : '\u2713';
            var sourceColor2 = compVals.inferred ? '#f59e0b' : '#10b981';
            
            html += '<div style="margin-bottom:14px;">'
                + '<div style="font-size:0.72em; text-transform:uppercase; letter-spacing:0.08em; color:var(--c-muted); font-weight:600; margin-bottom:6px;">'
                + 'Company Values <span style="color:' + sourceColor2 + '; font-size:0.9em;">(' + sourceIcon + ' ' + sourceLabel + ')</span></div>';
            
            // Primary values as prominent pills
            html += '<div style="display:flex; flex-wrap:wrap; gap:6px; margin-bottom:6px;">';
            (compVals.primary || []).forEach(function(v) {
                html += '<span style="font-size:0.82em; padding:4px 12px; border-radius:16px; font-weight:600; background:rgba(16,185,129,0.12); color:#10b981; border:1px solid rgba(16,185,129,0.2);">'
                    + escapeHtml(v) + '</span>';
            });
            html += '</div>';
            
            // Secondary values
            if ((compVals.secondary || []).length > 0) {
                html += '<div style="display:flex; flex-wrap:wrap; gap:4px;">';
                (compVals.secondary || []).forEach(function(v) {
                    html += '<span style="font-size:0.75em; padding:3px 10px; border-radius:12px; background:var(--c-surface-3); color:var(--c-muted); border:1px solid var(--c-surface-5);">'
                        + escapeHtml(v) + '</span>';
                });
                html += '</div>';
            }
            
            // Culture story
            if (compVals.story) {
                html += '<div style="font-size:0.75em; color:var(--c-muted); margin-top:6px; font-style:italic; line-height:1.4;">' + escapeHtml(compVals.story) + '</div>';
            }
            html += '</div>';
            
            // Alignment mapping detail
            if (valDetail) {
                var aligned = valDetail.aligned || [];
                var yourPriority = valDetail.yourPriority || [];
                var theirPriority = valDetail.theirPriority || [];
                
                // Build reverse lookup: for each aligned candidate value, find which company value matched
                var VALUE_SYN_QUICK = {
                    'trust': ['integrity', 'honesty', 'transparency', 'ethics', 'reliability', 'trustworthiness'],
                    'customer success': ['customer focus', 'customer first', 'client focus', 'customer obsession', 'customer centricity', 'service excellence'],
                    'innovation': ['creativity', 'continuous improvement', 'ingenuity', 'forward thinking', 'experimentation'],
                    'equality': ['diversity', 'inclusion', 'equity', 'fairness', 'belonging'],
                    'sustainability': ['social responsibility', 'environmental responsibility', 'community', 'impact', 'giving back'],
                    'collaboration': ['teamwork', 'partnership', 'together', 'ohana'],
                    'integrity': ['trust', 'honesty', 'transparency', 'ethics'],
                    'customer focus': ['customer success', 'customer obsession', 'customer first'],
                    'customer obsession': ['customer success', 'customer focus', 'customer first'],
                    'accountability': ['ownership', 'responsibility', 'reliability'],
                    'respect': ['dignity', 'empathy', 'compassion'],
                    'growth': ['learning', 'development', 'continuous learning'],
                    'excellence': ['quality', 'high standards', 'mastery'],
                    'ohana': ['collaboration', 'teamwork', 'family', 'community', 'belonging'],
                    'giving back': ['sustainability', 'social responsibility', 'community', 'philanthropy']
                };
                
                var alignedByCompany = {};
                aligned.forEach(function(a) {
                    var bestMatch = '';
                    var bestScore = 0;
                    allCompany.forEach(function(cv) {
                        var cvLower = cv.toLowerCase().trim();
                        var aLower = a.name.toLowerCase().trim();
                        var sc = 0;
                        if (aLower === cvLower) sc = 1.0;
                        else if (aLower.indexOf(cvLower) >= 0 || cvLower.indexOf(aLower) >= 0) sc = 0.85;
                        else {
                            var cvSyns = VALUE_SYN_QUICK[cvLower] || [];
                            var aSyns = VALUE_SYN_QUICK[aLower] || [];
                            if (cvSyns.indexOf(aLower) !== -1 || aSyns.indexOf(cvLower) !== -1) sc = 0.90;
                            else {
                                for (var i = 0; i < cvSyns.length; i++) {
                                    if (aSyns.indexOf(cvSyns[i]) !== -1) { sc = 0.80; break; }
                                }
                            }
                        }
                        if (sc > bestScore) { bestScore = sc; bestMatch = cv; }
                    });
                    if (!bestMatch) bestMatch = '(semantic)';
                    if (!alignedByCompany[bestMatch]) alignedByCompany[bestMatch] = [];
                    alignedByCompany[bestMatch].push({ name: a.name, score: a.score || bestScore, strength: a.strength });
                });
                
                // Aligned values — grouped by company value
                if (aligned.length > 0) {
                    html += '<div style="margin-bottom:14px;">'
                        + '<div style="font-size:0.72em; text-transform:uppercase; letter-spacing:0.08em; color:#10b981; font-weight:600; margin-bottom:6px;">'
                        + '\u2713 Aligned Values (' + aligned.length + ' candidate values \u2192 ' + Object.keys(alignedByCompany).length + ' company values)</div>';
                    
                    Object.keys(alignedByCompany).forEach(function(companyVal) {
                        var matches = alignedByCompany[companyVal];
                        var isPrimary = (compVals.primary || []).some(function(p) { return p === companyVal; });
                        html += '<div style="padding:8px 12px; margin-bottom:4px; background:rgba(16,185,129,0.04); border-radius:8px; border-left:3px solid ' + (isPrimary ? '#10b981' : 'var(--c-surface-5)') + ';">'
                            + '<div style="display:flex; justify-content:space-between; align-items:center;">'
                            + '<div>'
                            + '<span style="font-size:0.82em; font-weight:700; color:var(--c-heading);">' + escapeHtml(companyVal) + '</span>'
                            + '<span style="font-size:0.68em; color:var(--c-muted); margin-left:6px;">(' + (isPrimary ? 'core' : 'secondary') + ')</span>'
                            + '</div>'
                            + '<span style="font-size:0.7em; color:#10b981; font-weight:600;">\u2713 matched</span>'
                            + '</div>'
                            + '<div style="display:flex; flex-wrap:wrap; gap:4px; margin-top:4px;">';
                        matches.forEach(function(m) {
                            var quality = Math.round((m.score || 0.5) * 100);
                            var matchType = quality >= 95 ? 'exact' : quality >= 85 ? 'synonym' : quality >= 70 ? 'semantic' : 'related';
                            var typeColor = quality >= 95 ? '#10b981' : quality >= 85 ? '#10b981' : quality >= 70 ? '#f59e0b' : '#60a5fa';
                            html += '<span style="font-size:0.73em; padding:2px 8px; border-radius:10px; background:rgba(16,185,129,0.08); color:var(--c-body);">'
                                + escapeHtml(m.name.charAt(0).toUpperCase() + m.name.slice(1))
                                + ' <span style="color:' + typeColor + '; font-size:0.88em; font-weight:500;">(' + matchType + ')</span>'
                                + '</span>';
                        });
                        html += '</div></div>';
                    });
                    html += '</div>';
                }
                
                // Company values NOT matched
                if (theirPriority.length > 0) {
                    html += '<div style="margin-bottom:14px;">'
                        + '<div style="font-size:0.72em; text-transform:uppercase; letter-spacing:0.08em; color:#fbbf24; font-weight:600; margin-bottom:6px;">'
                        + '\u2717 Unmatched Company Values (' + theirPriority.length + ')</div>';
                    theirPriority.forEach(function(v) {
                        var isPrimary = v.strength === 'primary';
                        html += '<div style="padding:6px 12px; margin-bottom:3px; background:rgba(251,191,36,0.04); border-radius:6px; border-left:3px solid ' + (isPrimary ? '#fbbf24' : '#f59e0b') + '; display:flex; justify-content:space-between; align-items:center;">'
                            + '<span style="font-size:0.82em; color:var(--c-heading);">' + escapeHtml(v.name.charAt(0).toUpperCase() + v.name.slice(1)) + '</span>'
                            + '<span style="font-size:0.7em; color:' + (isPrimary ? '#fbbf24' : '#f59e0b') + ';">' + (isPrimary ? 'core value \u2014 gap' : 'secondary \u2014 gap') + '</span>'
                            + '</div>';
                    });
                    html += '</div>';
                }
                
                // Candidate's unique values (not matching company)
                if (yourPriority.length > 0) {
                    html += '<div style="margin-bottom:14px;">'
                        + '<div style="font-size:0.72em; text-transform:uppercase; letter-spacing:0.08em; color:#60a5fa; font-weight:600; margin-bottom:6px;">'
                        + bpIcon('user', 12) + ' Candidate\'s Independent Values (' + yourPriority.length + ')</div>'
                        + '<div style="font-size:0.72em; color:var(--c-muted); margin-bottom:6px;">Values this candidate prioritizes beyond company requirements. These represent independent character, not misalignment.</div>'
                        + '<div style="display:flex; flex-wrap:wrap; gap:4px;">';
                    yourPriority.forEach(function(v) {
                        html += '<span style="font-size:0.75em; padding:3px 10px; border-radius:12px; background:rgba(96,165,250,0.08); color:#60a5fa; border:1px solid rgba(96,165,250,0.15);">'
                            + escapeHtml(v.name.charAt(0).toUpperCase() + v.name.slice(1)) + '</span>';
                    });
                    html += '</div></div>';
                }
                
                // Score methodology — full transparency
                var totalCandidateValues = aligned.length + yourPriority.length;
                var companyCount = allCompany.length;
                var matchedCompanyCount = Object.keys(alignedByCompany).length;
                var maxPts = 0;
                allCompany.forEach(function(cv) {
                    maxPts += (compVals.primary || []).indexOf(cv) !== -1 ? 20 : 10;
                });
                var earnedPts = Math.round(score / 100 * maxPts);
                var synonymCount = aligned.filter(function(a) { return (a.score || 0) >= 0.80 && (a.score || 0) < 1.0; }).length;
                var exactCount = aligned.filter(function(a) { return (a.score || 0) >= 0.95; }).length;
                
                html += '<div style="padding:10px 12px; background:var(--c-surface-3); border-radius:8px; font-size:0.72em; color:var(--c-muted); line-height:1.6;">'
                    + '<strong style="color:var(--c-heading);">Scoring Methodology:</strong> '
                    + 'Measures how well this candidate covers the company\'s ' + companyCount + ' values. '
                    + matchedCompanyCount + ' of ' + companyCount + ' company values matched by ' + aligned.length + ' candidate values. '
                    + (exactCount > 0 ? exactCount + ' exact match' + (exactCount > 1 ? 'es' : '') + '. ' : '')
                    + (synonymCount > 0 ? synonymCount + ' synonym/semantic match' + (synonymCount > 1 ? 'es' : '') + '. ' : '')
                    + 'Core value = 20 pts, secondary = 10 pts, adjusted by match quality. '
                    + 'Earned ' + earnedPts + ' of ' + maxPts + ' possible. '
                    + 'Candidate\'s ' + yourPriority.length + ' independent values are noted but do not reduce the score.'
                    + '</div>';
            }
            
            html += '</div>';
            return html;
        }

        // ── Recommendations Engine ──
        // Generates actionable hiring and development recommendations from comparison data
        function _wbCompareRecommendations(rawResult, structResult) {
            if (!structResult) return '';
            
            var candidateStrengths = [];
            var devAreas = [];

            // 1. Analyze matched skills for strengths
            (structResult.matched || []).forEach(function(m) {
                var quality = m.nameMatch * m.profMatch;
                if (quality >= 0.95 && !m.profGap) {
                    candidateStrengths.push(m.userSkill + (m.userLevel ? ' (' + m.userLevel + ')' : ''));
                } else if (m.profGap) {
                    devAreas.push({
                        skill: m.jobSkill,
                        has: m.userLevel || 'Unknown',
                        needs: m.jobProficiency || 'Proficient',
                        type: 'proficiency'
                    });
                } else if (quality < 0.6) {
                    devAreas.push({
                        skill: m.jobSkill + ' (matched to ' + m.userSkill + ')',
                        has: 'Related',
                        needs: 'Direct experience',
                        type: 'adjacent'
                    });
                }
            });

            // 2. Classify gaps by actionability
            var criticalGaps = [];
            var developmentGaps = [];
            (structResult.gaps || []).forEach(function(g) {
                if (g.requirement === 'Required') {
                    criticalGaps.push(g);
                } else {
                    developmentGaps.push(g);
                }
            });

            // 3. JD vs WB intelligence delta analysis
            var jdOnly = (rawResult.matched || []).filter(function(rm) {
                return !(structResult.matched || []).some(function(sm) {
                    return sm.userSkill.toLowerCase() === rm.userSkill.toLowerCase();
                });
            });
            var wbOnly = (structResult.matched || []).filter(function(sm) {
                return !(rawResult.matched || []).some(function(rm) {
                    return rm.userSkill.toLowerCase() === sm.userSkill.toLowerCase();
                });
            });

            // Build HTML
            var html = '<div style="margin-top:24px; padding:20px; background:var(--c-surface-2); border-radius:12px; border:1px solid var(--c-surface-3);">';
            html += '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:1em; color:var(--c-heading); margin-bottom:16px;">'
                + bpIcon('lightbulb', 16) + ' Blueprint Intelligence\u2122 Analysis</div>';

            // Section: Intelligence Delta (structured as side-by-side tiles)
            if (wbOnly.length > 0 || jdOnly.length > 0) {
                html += '<div style="margin-bottom:16px;">'
                    + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:0.88em; color:var(--c-heading); margin-bottom:10px;">'
                    + bpIcon('search', 14) + ' Intelligence Delta</div>'
                    + '<div style="font-size:0.75em; color:var(--c-muted); margin-bottom:10px;">Skills discovered by one method but not the other. Differences reveal what each approach can and cannot see.</div>'
                    + '<div style="display:grid; grid-template-columns:1fr 1fr; gap:12px;">';

                // WB-only tile
                html += '<div style="padding:14px; background:rgba(16,185,129,0.04); border:1px solid rgba(16,185,129,0.15); border-radius:10px;">'
                    + '<div style="font-size:0.72em; text-transform:uppercase; letter-spacing:0.06em; color:#10b981; font-weight:700; margin-bottom:8px;">'
                    + '\u2728 Discovered by Blueprint Only (' + wbOnly.length + ')</div>';
                if (wbOnly.length > 0) {
                    wbOnly.forEach(function(m) {
                        var quality = Math.round(m.nameMatch * m.profMatch * 100);
                        html += '<div style="padding:6px 10px; margin-bottom:4px; background:rgba(16,185,129,0.06); border-radius:6px; border-left:2px solid #10b981;">'
                            + '<div style="font-size:0.82em; font-weight:600; color:var(--c-heading);">' + escapeHtml(m.jobSkill) + '</div>'
                            + '<div style="font-size:0.72em; color:var(--c-muted); margin-top:2px;">\u2192 ' + escapeHtml(m.userSkill) + (m.userLevel ? ' (' + m.userLevel + ')' : '') + ' <span style="color:#10b981;">' + quality + '%</span></div>'
                            + '</div>';
                    });
                    html += '<div style="font-size:0.7em; color:var(--c-muted); margin-top:6px; padding:4px 0; border-top:1px solid rgba(16,185,129,0.1); line-height:1.4;">Invisible to ATS keyword scanning. Requires synonym and ontology-aware matching.</div>';
                } else {
                    html += '<div style="font-size:0.78em; color:var(--c-muted); padding:8px 0;">No additional matches beyond JD.</div>';
                }
                html += '</div>';

                // JD-only tile
                html += '<div style="padding:14px; background:rgba(245,158,11,0.04); border:1px solid rgba(245,158,11,0.12); border-radius:10px;">'
                    + '<div style="font-size:0.72em; text-transform:uppercase; letter-spacing:0.06em; color:#f59e0b; font-weight:700; margin-bottom:8px;">'
                    + '\uD83D\uDCC4 Discovered by JD Parsing Only (' + jdOnly.length + ')</div>';
                if (jdOnly.length > 0) {
                    jdOnly.forEach(function(m) {
                        html += '<div style="padding:6px 10px; margin-bottom:4px; background:rgba(245,158,11,0.04); border-radius:6px; border-left:2px solid #f59e0b;">'
                            + '<div style="font-size:0.82em; font-weight:600; color:var(--c-heading);">' + escapeHtml(m.jobSkill) + '</div>'
                            + '<div style="font-size:0.72em; color:var(--c-muted); margin-top:2px;">\u2192 ' + escapeHtml(m.userSkill) + ' <span style="color:#f59e0b;">keyword match</span></div>'
                            + '</div>';
                    });
                    html += '<div style="font-size:0.7em; color:var(--c-muted); margin-top:6px; padding:4px 0; border-top:1px solid rgba(245,158,11,0.1); line-height:1.4;">Keyword-based extraction. No proficiency validation or evidence.</div>';
                } else {
                    html += '<div style="font-size:0.78em; color:var(--c-muted); padding:8px 0;">No matches the Blueprint missed.</div>';
                }
                html += '</div>';

                html += '</div></div>';
            }

            // Section: Development Focus Areas (if gaps exist)
            if (criticalGaps.length > 0 || developmentGaps.length > 0 || devAreas.length > 0) {
                html += '<div style="margin-bottom:16px; padding-top:14px; border-top:1px solid var(--c-surface-3);">'
                    + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:0.88em; color:var(--c-heading); margin-bottom:10px;">'
                    + bpIcon('trending-up', 14) + ' Development Focus Areas</div>';

                if (criticalGaps.length > 0) {
                    html += '<div style="font-size:0.72em; text-transform:uppercase; letter-spacing:0.06em; color:#fbbf24; font-weight:600; margin-bottom:6px;">Required Skills \u2014 Not Currently Matched</div>';
                    criticalGaps.forEach(function(g) {
                        var recText = _wbGapRecommendation(g.name, g.proficiency || 'Proficient');
                        html += '<div style="padding:10px 12px; margin-bottom:6px; background:rgba(251,191,36,0.04); border-radius:8px; border-left:3px solid #fbbf24;">'
                            + '<div style="display:flex; justify-content:space-between; align-items:center;">'
                            + '<span style="font-size:0.85em; font-weight:600; color:var(--c-heading);">' + escapeHtml(g.name) + '</span>'
                            + '<span style="font-size:0.7em; color:#fbbf24; font-weight:500;">' + (g.proficiency || 'Proficient') + ' required</span>'
                            + '</div>'
                            + '<div style="font-size:0.75em; color:var(--c-body); margin-top:4px; line-height:1.5;">' + recText + '</div>'
                            + '</div>';
                    });
                }

                if (developmentGaps.length > 0) {
                    html += '<div style="font-size:0.72em; text-transform:uppercase; letter-spacing:0.06em; color:#f59e0b; font-weight:600; margin:10px 0 6px;">Preferred Skills \u2014 Growth Opportunities</div>';
                    developmentGaps.forEach(function(g) {
                        var recText = _wbGapRecommendation(g.name, g.proficiency || 'Proficient');
                        html += '<div style="padding:10px 12px; margin-bottom:6px; background:rgba(245,158,11,0.04); border-radius:8px; border-left:3px solid #f59e0b;">'
                            + '<div style="display:flex; justify-content:space-between; align-items:center;">'
                            + '<span style="font-size:0.85em; font-weight:600; color:var(--c-heading);">' + escapeHtml(g.name) + '</span>'
                            + '<span style="font-size:0.7em; color:#f59e0b; font-weight:500;">' + (g.proficiency || 'Proficient') + ' preferred</span>'
                            + '</div>'
                            + '<div style="font-size:0.75em; color:var(--c-body); margin-top:4px; line-height:1.5;">' + recText + '</div>'
                            + '</div>';
                    });
                }

                if (devAreas.length > 0) {
                    html += '<div style="font-size:0.72em; text-transform:uppercase; letter-spacing:0.06em; color:#60a5fa; font-weight:600; margin:10px 0 6px;">Adjacent Skills \u2014 Strengthen Existing Capabilities</div>';
                    devAreas.forEach(function(d) {
                        html += '<div style="padding:8px 12px; margin-bottom:4px; background:rgba(96,165,250,0.04); border-radius:8px; border-left:3px solid #60a5fa;">'
                            + '<div style="font-size:0.82em; font-weight:600; color:var(--c-heading);">' + escapeHtml(d.skill) + '</div>'
                            + '<div style="font-size:0.75em; color:var(--c-body); margin-top:2px;">'
                            + (d.type === 'proficiency' ? 'Current: ' + d.has + ' \u2192 Needed: ' + d.needs : 'Related skill present. Direct experience recommended.')
                            + '</div></div>';
                    });
                }

                html += '</div>';
            }

            // Section: Signal Strength
            if (candidateStrengths.length > 0) {
                var strengthLevel = candidateStrengths.length >= 4 ? 'High' : candidateStrengths.length >= 2 ? 'Medium' : 'Low';
                var strengthColor = strengthLevel === 'High' ? '#10b981' : strengthLevel === 'Medium' ? '#f59e0b' : '#ef4444';
                html += '<div style="padding-top:14px; border-top:1px solid var(--c-surface-3);">'
                    + '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px;">'
                    + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:0.88em; color:var(--c-heading);">'
                    + bpIcon('activity', 14) + ' Signal Strength</div>'
                    + '<span style="font-size:0.78em; font-weight:700; color:' + strengthColor + '; padding:3px 12px; border-radius:12px; background:' + strengthColor + '18; border:1px solid ' + strengthColor + '30;">' + strengthLevel + '</span>'
                    + '</div>'
                    + '<div style="font-size:0.72em; color:var(--c-muted); margin-bottom:8px;">Skills where this candidate\'s profile data closely aligns with role requirements.</div>'
                    + '<div style="display:flex; flex-wrap:wrap; gap:6px;">';
                candidateStrengths.forEach(function(s) {
                    html += '<span style="font-size:0.78em; background:rgba(16,185,129,0.08); color:#10b981; padding:5px 12px; border-radius:16px; font-weight:500; border:1px solid rgba(16,185,129,0.15);">' + escapeHtml(s) + '</span>';
                });
                html += '</div></div>';
            }

            html += '</div>';
            return html;
        }

        // Gap-specific recommendation generator
        function _wbGapRecommendation(skillName, requiredLevel) {
            var lower = skillName.toLowerCase();
            var recs = {
                'ai agents': 'Emerging capability. Recommend structured AI/ML onboarding program, hands-on agentic framework projects (LangChain, CrewAI), and internal AI literacy certification.',
                'salesforce': 'Platform-specific. Recommend Salesforce Trailhead certification path (Admin or Business Analyst track). Typically 40\u201360 hours to base proficiency.',
                'management of personnel resources': 'Leadership competency. Look for evidence of direct report management, team building, or mentoring in interview. May be present but unlisted.',
                'financial modeling': 'Technical skill. Recommend Wall Street Prep or CFI courses for structured learning. Assess depth needed \u2014 strategic-level modeling vs. analyst-level detail.',
                'data analysis': 'Foundational skill. Recommend Google Data Analytics Certificate or internal analytics bootcamp.',
                'strategic planning': 'Core to role. Assess via case study interview. Consider Harvard Business School Online \u201cStrategy\u201d course.',
                'project management': 'Process skill. PMP or Agile certification path. Internal shadowing of experienced PMs.',
                'python': 'Technical skill. Recommend DataCamp or Codecademy Python track. 20\u201340 hours to working proficiency.',
                'leadership': 'Behavioral competency. Assess via structured behavioral interview. Consider executive coaching investment.',
                'change management': 'Process and behavioral. Prosci certification is industry standard. Consider Kotter\u2019s 8-step framework training.',
                'stakeholder management': 'Interpersonal skill. Typically developed through experience. Recommend assigning cross-functional project ownership.',
                'negotiation': 'Core business skill. Recommend Harvard PON or Scotwork training. High-impact investment.'
            };
            
            // Check for exact match
            if (recs[lower]) return recs[lower];
            
            // Check for partial match
            for (var key in recs) {
                if (lower.indexOf(key) !== -1 || key.indexOf(lower) !== -1) return recs[key];
            }

            // Generic recommendation based on level
            if (requiredLevel === 'Expert' || requiredLevel === 'Mastery') {
                return 'Advanced competency required. Recommend identifying internal subject matter experts for mentoring, targeted external training, and project-based development. Typical ramp: 6\u201312 months.';
            } else if (requiredLevel === 'Advanced') {
                return 'Intermediate-to-advanced competency needed. Recommend structured training program and progressive project assignments. Typical ramp: 3\u20136 months.';
            }
            return 'Foundational competency needed. Self-directed learning combined with on-the-job application. Typical ramp: 1\u20133 months.';
        }

        function _wbCompareGauge(score, label, color, sublabel) {
            var radius = 54, stroke = 10, circ = 2 * Math.PI * radius;
            var pct = Math.max(0, Math.min(100, score));
            var offset = circ - (pct / 100) * circ;
            var bgColor = 'rgba(255,255,255,0.08)';
            var html = '<div style="text-align:center;">'
                + '<svg width="130" height="130" viewBox="0 0 130 130">'
                + '<circle cx="65" cy="65" r="' + radius + '" fill="none" stroke="' + bgColor + '" stroke-width="' + stroke + '" />'
                + '<circle cx="65" cy="65" r="' + radius + '" fill="none" stroke="' + color + '" stroke-width="' + stroke + '" '
                + 'stroke-dasharray="' + circ + '" stroke-dashoffset="' + offset + '" stroke-linecap="round" '
                + 'transform="rotate(-90 65 65)" style="transition: stroke-dashoffset 1s ease;" />'
                + '<text x="65" y="58" text-anchor="middle" fill="' + color + '" font-size="28" font-weight="700" font-family="Outfit,sans-serif">' + pct + '%</text>'
                + '<text x="65" y="76" text-anchor="middle" fill="var(--c-muted)" font-size="10">' + label + '</text>';
            if (sublabel) html += '<text x="65" y="90" text-anchor="middle" fill="var(--c-muted)" font-size="9">' + sublabel + '</text>';
            html += '</svg></div>';
            return html;
        }

        function _wbRenderComparison(wb, rawResult, structResult, candidate) {
            var cp = (candidate && candidate.profile) || {};
            rawResult = rawResult || { score: 0, matched: [], gaps: [], skillsExtracted: 0 };
            structResult = structResult || { score: 0, matched: [], gaps: [], skillsUsed: 0, valuesScore: 0 };

            var beforeColor = '#6b7280';
            var afterColor = '#10b981';
            var scoreDelta = structResult.score - rawResult.score;
            var scoreDeltaLabel = scoreDelta > 0 ? '+' + scoreDelta + ' pts' : scoreDelta + ' pts';

            var html = '<div style="background:var(--c-surface-1); border:1px solid var(--c-surface-5); border-radius:14px; padding:28px; margin-top:20px;">';

            html += '<div style="text-align:center; margin-bottom:24px;">'
                + '<div style="font-family:Outfit,sans-serif; font-weight:800; font-size:1.4em; color:var(--c-heading-bold); margin-bottom:6px;">'
                + bpIcon('blueprint', 22) + ' Blueprint Advantage\u2122</div>'
                + '<div style="font-size:0.88em; color:var(--c-muted); line-height:1.5;">Same role. Same candidate. <strong>Dramatically different intelligence.</strong></div>'
                + '<div style="font-size:0.82em; color:var(--c-muted); margin-top:6px;">Candidate: <strong>' + escapeHtml(cp.name || 'Demo Candidate') + '</strong> \u2014 ' + escapeHtml(cp.currentTitle || '')
                + ' \u00B7 ' + ((candidate && candidate.skills) || []).length + ' skills \u00B7 ' + ((candidate && candidate.values) || []).filter(function(v){return v.selected;}).length + ' values</div>';
            if (rawResult.parsedTitle) {
                html += '<div style="font-size:0.78em; color:var(--c-muted); margin-top:2px;">Role: <strong>' + escapeHtml(wb.title || rawResult.parsedTitle) + '</strong>'
                    + (wb.company ? ' at ' + escapeHtml(wb.company) : '') + '</div>';
            }
            html += '</div>';

            html += '<div class="wb-compare-gauges" style="display:grid; grid-template-columns:1fr auto 1fr; gap:16px; margin-bottom:24px; align-items:start;">';

            html += '<div style="background:rgba(107,114,128,0.06); border:1px solid rgba(107,114,128,0.2); border-radius:12px; padding:20px;">'
                + '<div style="text-align:center; font-family:Outfit,sans-serif; font-weight:700; font-size:0.95em; color:' + beforeColor + '; margin-bottom:14px; text-transform:uppercase; letter-spacing:1px;">'
                + bpIcon('file',14) + ' Traditional JD</div>'
                + _wbCompareGauge(rawResult.score, 'Match Score', beforeColor, rawResult.skillsExtracted + ' skills extracted')
                + '<div style="display:grid; grid-template-columns:1fr 1fr; gap:6px; margin-top:14px;">'
                + '<div style="background:var(--c-surface-2); border-radius:8px; padding:8px; text-align:center;">'
                + '<div style="font-size:1.2em; font-weight:700; color:' + beforeColor + ';">' + rawResult.matched.length + '/' + rawResult.skillsExtracted + '</div>'
                + '<div style="font-size:0.7em; color:var(--c-muted);">Skills Matched</div></div>'
                + '<div style="background:var(--c-surface-2); border-radius:8px; padding:8px; text-align:center;">'
                + '<div style="font-size:1.2em; font-weight:700; color:' + beforeColor + ';">N/A</div>'
                + '<div style="font-size:0.7em; color:var(--c-muted);">Proficiency</div></div>'
                + '<div style="background:var(--c-surface-2); border-radius:8px; padding:8px; text-align:center;">'
                + '<div style="font-size:1.2em; font-weight:700; color:' + beforeColor + ';">' + (rawResult.valuesInferred || 0) + '</div>'
                + '<div style="font-size:0.7em; color:var(--c-muted);">Values Inferred</div></div>'
                + '<div style="background:var(--c-surface-2); border-radius:8px; padding:8px; text-align:center;">'
                + '<div style="font-size:1.2em; font-weight:700; color:' + beforeColor + ';">0</div>'
                + '<div style="font-size:0.7em; color:var(--c-muted);">Evidence</div></div>'
                + '</div>'
                + '<div style="margin-top:10px; font-size:0.75em; color:var(--c-muted); line-height:1.4; padding:8px; background:rgba(107,114,128,0.04); border-radius:6px;">'
                + 'Text parsing extracts ' + rawResult.skillsExtracted + ' skills via keyword heuristics. No proficiency data. Values guessed from text cues. No evidence validation.'
                + '</div>'
                + '</div>';

            html += '<div style="display:flex; flex-direction:column; align-items:center; justify-content:center; padding:20px 8px; min-height:200px;">';
            if (scoreDelta > 0) {
                html += '<div style="font-family:Outfit,sans-serif; font-weight:800; font-size:1.3em; color:' + afterColor + ';">' + scoreDeltaLabel + '</div>'
                    + '<div style="font-size:0.72em; color:var(--c-muted); text-align:center; margin-top:4px;">score<br>improvement</div>';
            }
            html += '<div style="font-size:1.8em; color:var(--c-muted); margin:12px 0;">\u2192</div>';
            html += '</div>';

            var profMeets = structResult.profMeets || 0;
            var profGaps = structResult.profGaps || 0;
            var profTotal = profMeets + profGaps;
            var profPct = profTotal > 0 ? Math.round((profMeets / profTotal) * 100) : 0;
            var evidencePoints = structResult.evidencePoints || 0;

            html += '<div style="background:rgba(16,185,129,0.06); border:1px solid rgba(16,185,129,0.25); border-radius:12px; padding:20px;">'
                + '<div style="text-align:center; font-family:Outfit,sans-serif; font-weight:700; font-size:0.95em; color:' + afterColor + '; margin-bottom:14px; text-transform:uppercase; letter-spacing:1px;">'
                + bpIcon('blueprint',14) + ' Work Blueprint\u2122</div>'
                + _wbCompareGauge(structResult.score, 'Intelligence Score', afterColor, structResult.skillsUsed + ' structured skills')
                + '<div style="display:grid; grid-template-columns:1fr 1fr; gap:6px; margin-top:14px;">'
                + '<div style="background:var(--c-surface-2); border-radius:8px; padding:8px; text-align:center;">'
                + '<div style="font-size:1.2em; font-weight:700; color:' + afterColor + ';">' + structResult.matched.length + '/' + structResult.skillsUsed + '</div>'
                + '<div style="font-size:0.7em; color:var(--c-muted);">Skills Matched</div></div>'
                + '<div style="background:var(--c-surface-2); border-radius:8px; padding:8px; text-align:center;">'
                + '<div style="font-size:1.2em; font-weight:700; color:' + afterColor + ';">' + (profTotal > 0 ? profPct + '%' : 'N/A') + '</div>'
                + '<div style="font-size:0.7em; color:var(--c-muted);">Proficiency Fit</div></div>'
                + '<div style="background:var(--c-surface-2); border-radius:8px; padding:8px; text-align:center;">'
                + '<div style="font-size:1.2em; font-weight:700; color:' + afterColor + ';">' + structResult.valuesScore + '%</div>'
                + '<div style="font-size:0.7em; color:var(--c-muted);">Values Aligned</div></div>'
                + '<div style="background:var(--c-surface-2); border-radius:8px; padding:8px; text-align:center;">'
                + '<div style="font-size:1.2em; font-weight:700; color:' + afterColor + ';">' + evidencePoints + '</div>'
                + '<div style="font-size:0.7em; color:var(--c-muted);">Evidence</div></div>'
                + '</div>'
                + '<div style="margin-top:10px; font-size:0.75em; color:var(--c-muted); line-height:1.4; padding:8px; background:rgba(16,185,129,0.04); border-radius:6px;">'
                + structResult.skillsUsed + ' structured skills with proficiency levels. ' + (structResult.valuesTotal || 0) + ' values mapped. '
                + 'Synonym + ontology matching. ' + evidencePoints + ' supporting data points.'
                + '</div>'
                + '</div>';

            html += '</div>';

            html += '<div style="background:linear-gradient(135deg, rgba(16,185,129,0.08), rgba(59,130,246,0.08)); border:1px solid rgba(16,185,129,0.2); border-radius:12px; padding:20px; margin-bottom:20px;">'
                + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:1.05em; color:var(--c-heading-bold); margin-bottom:16px;">'
                + bpIcon('trending-up',18) + ' Intelligence Comparison</div>';

            var intelligenceItems = [
                { label: 'Skill Discovery', ats: rawResult.skillsExtracted + ' extracted via text parsing', wb: structResult.skillsUsed + ' structured skills with requirement levels' },
                { label: 'Matching', ats: rawResult.matched.length + ' matched (keyword heuristics)', wb: structResult.matched.length + ' matched, ' + (structResult.gaps || []).length + ' gaps of ' + structResult.skillsUsed + ' total' },
                { label: 'Proficiency', ats: 'Not available \u2014 all levels treated equally', wb: profTotal > 0 ? profMeets + '/' + profTotal + ' meet required level (' + profPct + '%)' : 'Proficiency levels defined per skill' },
                { label: 'Values', ats: rawResult.valuesInferred > 0 ? rawResult.valuesInferred + ' inferred from text (' + (rawResult.valuesScore || 0) + '% match)' : 'Guessed from text keywords', wb: structResult.valuesScore > 0 ? structResult.valuesAligned + ' aligned (' + structResult.valuesScore + '% match)' : (structResult.valuesTotal || 0) + ' values mapped' },
                { label: 'Evidence', ats: 'Claims taken at face value', wb: evidencePoints > 0 ? evidencePoints + ' supporting data points' : 'Evidence tracking available' },
                { label: 'Gaps', ats: rawResult.gaps.length > 0 ? rawResult.gaps.length + ' gaps (text-derived)' : 'Limited gap visibility', wb: structResult.gaps.length + ' of ' + structResult.skillsUsed + ' required skills unmatched' }
            ];

            intelligenceItems.forEach(function(item) {
                html += '<div class="wb-compare-intel-row" style="display:grid; grid-template-columns:120px 1fr 1fr; gap:10px; padding:8px 0; border-bottom:1px solid var(--c-surface-3); font-size:0.8em;">'
                    + '<div style="font-weight:700; color:var(--c-heading);">' + item.label + '</div>'
                    + '<div style="color:' + beforeColor + '; padding:5px 8px; background:rgba(107,114,128,0.06); border-radius:6px;">'
                    + '<span style="opacity:0.6;">\u2717</span> ' + item.ats + '</div>'
                    + '<div style="color:' + afterColor + '; padding:5px 8px; background:rgba(16,185,129,0.06); border-radius:6px;">'
                    + '<span>\u2713</span> ' + item.wb + '</div></div>';
            });

            html += '</div>';

            html += '<div class="wb-compare-skills-grid" style="display:grid; grid-template-columns:1fr 1fr; gap:14px; margin-bottom:20px;">';
            
            // ── JD Skills Tile ──
            html += '<div style="padding:16px; background:rgba(107,114,128,0.04); border:1px solid var(--c-surface-3); border-radius:10px;">'
                + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:0.88em; color:' + beforeColor + '; margin-bottom:4px;">'
                + bpIcon('file-text', 14) + ' JD Text Parsing</div>'
                + '<div style="font-size:0.72em; color:var(--c-muted); margin-bottom:10px;">'
                + rawResult.skillsExtracted + ' skills extracted \u00B7 ' + rawResult.matched.length + ' matched to candidate</div>';
            if (rawResult.matched.length === 0 && rawResult.gaps.length === 0) {
                html += '<div style="font-size:0.82em; color:var(--c-muted); padding:12px; text-align:center;">No skills extracted from JD text.</div>';
            } else {
                rawResult.matched.slice(0, 12).forEach(function(m) {
                    html += '<div style="padding:8px 10px; margin-bottom:4px; background:rgba(107,114,128,0.06); border-radius:6px; border-left:3px solid ' + beforeColor + ';">'
                        + '<div style="display:flex; justify-content:space-between; align-items:center;">'
                        + '<span style="font-size:0.82em; color:var(--c-heading);">' + escapeHtml(m.jobSkill) + '</span>'
                        + '<span style="font-size:0.7em; color:' + beforeColor + '; font-weight:500;">\u2713 matched</span>'
                        + '</div>';
                    if (m.userSkill !== m.jobSkill) {
                        html += '<div style="font-size:0.72em; color:var(--c-muted); margin-top:2px;">\u2192 ' + escapeHtml(m.userSkill) + '</div>';
                    }
                    html += '</div>';
                });
                rawResult.gaps.slice(0, 5).forEach(function(g) {
                    html += '<div style="padding:8px 10px; margin-bottom:4px; background:rgba(239,68,68,0.04); border-radius:6px; border-left:3px solid rgba(239,68,68,0.3);">'
                        + '<div style="display:flex; justify-content:space-between; align-items:center;">'
                        + '<span style="font-size:0.82em; color:var(--c-muted);">' + escapeHtml(g.name) + '</span>'
                        + '<span style="font-size:0.7em; color:#ef4444;">\u2717 no match</span>'
                        + '</div></div>';
                });
                html += '<div style="font-size:0.7em; color:var(--c-muted); margin-top:8px; padding:4px 0; border-top:1px solid var(--c-surface-3);">Keyword extraction only. No proficiency data, no evidence validation.</div>';
            }
            html += '</div>';

            // ── WB Structured Skills Tile ──
            var wbMatched = structResult.matched || [];
            var wbGaps = structResult.gaps || [];
            var wbTotal = structResult.skillsUsed || (wbMatched.length + wbGaps.length);
            html += '<div style="padding:16px; background:rgba(16,185,129,0.04); border:1px solid rgba(16,185,129,0.15); border-radius:10px;">'
                + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:0.88em; color:' + afterColor + '; margin-bottom:4px;">'
                + bpIcon('blueprint', 14) + ' Blueprint Structured Matching</div>'
                + '<div style="font-size:0.72em; color:var(--c-muted); margin-bottom:10px;">'
                + '<span style="color:#10b981; font-weight:600;">' + wbMatched.length + ' matched</span>'
                + ' + <span style="color:#f59e0b; font-weight:600;">' + wbGaps.length + ' gaps</span>'
                + ' = ' + wbTotal + ' skills evaluated</div>';
            
            // Matched skills as cards
            if (wbMatched.length > 0) {
                wbMatched.slice(0, 12).forEach(function(m) {
                    var quality = Math.round(m.nameMatch * m.profMatch * 100);
                    var nameQ = Math.round((m.nameMatch || 0) * 100);
                    var qualityColor = quality >= 90 ? '#10b981' : quality >= 60 ? '#f59e0b' : '#ef4444';
                    var candidateLevel = m.userLevel || '';
                    var requiredLevel = m.jobProficiency || '';
                    var profOk = !m.profGap;
                    html += '<div style="padding:10px 12px; margin-bottom:5px; background:rgba(16,185,129,0.05); border-radius:8px; border-left:3px solid ' + qualityColor + ';">'
                        // Row 1: Job skill name + similarity score
                        + '<div style="display:flex; justify-content:space-between; align-items:center;">'
                        + '<div style="font-size:0.82em; font-weight:600; color:var(--c-heading);">' + escapeHtml(m.jobSkill) + '</div>'
                        + '<div style="font-size:0.72em; font-weight:700; color:' + qualityColor + '; padding:2px 8px; border-radius:6px; background:' + qualityColor + '15;">Similarity: ' + nameQ + '%</div>'
                        + '</div>'
                        // Row 2: Mapped candidate skill
                        + '<div style="font-size:0.72em; color:var(--c-muted); margin-top:2px;">\u2192 Mapped to: ' + escapeHtml(m.userSkill) + '</div>'
                        // Row 3: Proficiency comparison
                        + '<div style="display:flex; gap:8px; align-items:center; margin-top:5px; font-size:0.68em;">';
                    if (candidateLevel && requiredLevel) {
                        html += '<span style="padding:2px 8px; border-radius:6px; background:rgba(99,102,241,0.1); color:#818cf8; font-weight:500;">Required: ' + requiredLevel + '</span>'
                            + '<span style="color:var(--c-muted);">\u2192</span>'
                            + '<span style="padding:2px 8px; border-radius:6px; background:rgba(16,185,129,0.1); color:#10b981; font-weight:500;">Has: ' + candidateLevel + '</span>';
                        if (profOk) {
                            html += '<span style="color:#10b981; font-weight:600;">\u2713 Met</span>';
                        } else {
                            html += '<span style="padding:2px 8px; border-radius:6px; background:rgba(245,158,11,0.1); color:#f59e0b; font-weight:500;">\u26A0 Below required</span>';
                        }
                    } else if (candidateLevel) {
                        html += '<span style="padding:2px 8px; border-radius:6px; background:rgba(16,185,129,0.1); color:#10b981; font-weight:500;">Candidate: ' + candidateLevel + '</span>';
                    }
                    html += '</div></div>';
                });
            }
            
            // Gap skills as cards
            if (wbGaps.length > 0) {
                html += '<div style="margin-top:6px; padding-top:6px; border-top:1px dashed rgba(245,158,11,0.3);">';
                wbGaps.slice(0, 10).forEach(function(g) {
                    html += '<div style="padding:8px 10px; margin-bottom:4px; background:rgba(245,158,11,0.04); border-radius:6px; border-left:3px solid #f59e0b;">'
                        + '<div style="display:flex; justify-content:space-between; align-items:center;">'
                        + '<span style="font-size:0.82em; color:var(--c-heading);">' + escapeHtml(g.name) + '</span>'
                        + '<span style="font-size:0.68em; padding:2px 8px; border-radius:8px; background:rgba(245,158,11,0.1); color:#f59e0b; font-weight:500;">' + (g.requirement || 'Required') + ' \u00B7 ' + (g.proficiency || 'Proficient') + '</span>'
                        + '</div>'
                        + '<div style="font-size:0.7em; color:var(--c-muted); margin-top:2px;">Not found in candidate profile</div>'
                        + '</div>';
                });
                html += '</div>';
            }
            
            html += '<div style="font-size:0.7em; color:var(--c-muted); margin-top:8px; padding:4px 0; border-top:1px solid rgba(16,185,129,0.1);">Synonym + ontology matching with proficiency validation and evidence tracking.</div>';
            html += '</div>';
            html += '</div>';

            // ── Values Detail Section ──
            html += _wbCompareValuesDetail(structResult);

            // ── Recommendations Engine ──
            html += _wbCompareRecommendations(rawResult, structResult);

            html += '<div style="text-align:center; font-size:0.75em; color:var(--c-muted); line-height:1.5; padding-top:12px; border-top:1px solid var(--c-surface-3);">'
                + 'Live comparison powered by Blueprint\u2122\u2019s matching engine \u2014 real data, real algorithms, no simulations.'
                + '</div>';

            html += '</div>';
            return html;
        }

        var _wbCompareViewIdx = -1;
        async function wbRepoCompare(idx) {
            if (!_wbRepoCache || !_wbRepoCache[idx]) return;
            var wb = _wbRepoCache[idx];
            var rawJD = wb.sourceJD || wb._rawJD || '';

            if (!rawJD) {
                var pastePrompt = prompt('This blueprint has no source JD text.\nPaste the original job description to compare:');
                if (!pastePrompt || !pastePrompt.trim()) {
                    showToast('Comparison requires a job description to compare against.', 'warning');
                    return;
                }
                rawJD = pastePrompt.trim();
            }

            showToast('Running live comparison...', 'info', 4000);
            try {
                var candidate = await _wbLoadCompareCandidate();
                
                // Resolve company values before comparison
                if (wb.company) {
                    try {
                        var resolvedVals = await ensureCompanyValues(wb.company);
                        if (resolvedVals && resolvedVals.primary && resolvedVals.primary.length > 0) {
                            wb._resolvedCompanyValues = resolvedVals;
                        }
                    } catch (valErr) { console.warn('[VALUES] Repo compare lookup failed:', valErr.message); }
                }
                
                var both = _wbCompareRunBoth(rawJD, wb, candidate);
                var rawResult = both.raw;
                var structResult = both.struct;
                _wbCompareViewIdx = idx;
                var compHtml = _wbRenderComparison(wb, rawResult, structResult, candidate);
                var container = document.getElementById('wbCompareContainer');
                if (container) {
                    container.innerHTML = compHtml;
                    container.scrollIntoView({ behavior: 'smooth', block: 'start' });
                } else {
                    var el = document.getElementById('adminTabContent');
                    if (el) {
                        el.insertAdjacentHTML('beforeend', '<div id="wbCompareContainer">' + compHtml + '</div>');
                        document.getElementById('wbCompareContainer').scrollIntoView({ behavior: 'smooth', block: 'start' });
                    }
                }
                showToast('Comparison complete!', 'success');
            } catch (err) {
                console.warn('Comparison error:', err);
                showToast('Comparison failed: ' + err.message, 'error');
            }
        }
        window.wbRepoCompare = wbRepoCompare;

        var _wbCompWizStep = 1;
        var _wbCompWizData = { wb: null, rawJD: '', candidateId: '', candidate: null };

        function renderWBCompareWizard(el) {
            var html = '<div style="max-width:900px;">'
                + '<div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:18px;">'
                + '<div>'
                + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:1.3em; color:var(--c-heading-bold); text-transform:uppercase; letter-spacing:0.04em;">'
                + bpIcon('trending-up',22) + ' Blueprint Advantage\u2122 Compare</div>'
                + '<div style="font-size:0.85em; color:var(--c-muted); margin-top:4px;">See the difference structured intelligence makes \u2014 live matching, real data.</div>'
                + '</div>'
                + '</div>';

            var steps = ['Select Blueprint', 'Add Traditional JD', 'Select Candidate', 'Results'];
            html += '<div class="wb-comp-wiz-steps" style="display:flex; gap:4px; margin-bottom:24px;">';
            steps.forEach(function(s, i) {
                var n = i + 1;
                var active = n === _wbCompWizStep;
                var done = n < _wbCompWizStep;
                var bg = active ? 'var(--accent)' : done ? 'rgba(16,185,129,0.2)' : 'var(--c-surface-3)';
                var col = active ? '#fff' : done ? '#10b981' : 'var(--c-muted)';
                html += '<div style="flex:1; text-align:center; padding:10px 6px; background:' + bg + '; border-radius:8px; font-size:0.78em; font-weight:' + (active ? '700' : '500') + '; color:' + col + ';">'
                    + '<span style="display:inline-block; width:18px; height:18px; line-height:18px; border-radius:50%; background:' + (active ? '#fff' : done ? '#10b981' : 'var(--c-surface-5)') + '; color:' + (active ? 'var(--accent)' : done ? '#fff' : 'var(--c-muted)') + '; font-size:0.8em; font-weight:700; margin-right:4px;">' + (done ? '\u2713' : n) + '</span>'
                    + s + '</div>';
            });
            html += '</div>';

            html += '<div id="wbCompWizBody"></div>';
            
            // Saved Comparisons Repository (hide when viewing live results)
            if (_wbCompWizStep !== 4) {
                html += '<div style="margin-top:32px; padding-top:20px; border-top:1px solid var(--c-surface-3);">'
                    + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:1.05em; color:var(--c-heading-bold); margin-bottom:12px; text-transform:uppercase; letter-spacing:0.04em;">'
                    + bpIcon('archive', 18) + ' Saved Comparisons</div>'
                    + '<div id="wbCompRepoContainer"></div>'
                    + '</div>';
            }
            
            html += '</div>';
            el.innerHTML = html;
            _wbCompWizRenderStep();
            
            // Render repository
            var repoEl = document.getElementById('wbCompRepoContainer');
            if (repoEl) _wbCompRenderRepo(repoEl);
        }

        function _wbCompWizRenderStep() {
            var body = document.getElementById('wbCompWizBody');
            if (!body) return;
            if (_wbCompWizStep === 1) _wbCompWizStep1(body);
            else if (_wbCompWizStep === 2) _wbCompWizStep2(body);
            else if (_wbCompWizStep === 3) _wbCompWizStep3(body);
            else if (_wbCompWizStep === 4) _wbCompWizStep4(body);
        }

        function _wbCompWizStep1(body) {
            var html = '<div style="background:var(--c-surface-2); border:1px solid var(--c-surface-5); border-radius:12px; padding:24px;">'
                + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:1.05em; color:var(--c-heading-bold); margin-bottom:4px;">'
                + bpIcon('blueprint',18) + ' Select a Work Blueprint</div>'
                + '<div style="font-size:0.84em; color:var(--c-muted); margin-bottom:16px;">Choose a blueprint from your repository to use as the structured comparison.</div>';

            if (!fbUser) {
                html += '<div style="text-align:center; padding:30px; color:var(--c-muted);">' + bpIcon('shield',28) + '<p style="margin-top:8px;">Sign in to access your blueprints.</p></div></div>';
                body.innerHTML = html;
                return;
            }

            if (_wbRepoCache === null) {
                html += '<div style="text-align:center; padding:30px;">'
                    + '<div class="loading-spinner" style="width:24px; height:24px; border-width:3px; margin:0 auto 10px;"></div>'
                    + '<p style="font-size:0.85em; color:var(--c-muted);">Loading blueprints...</p></div></div>';
                body.innerHTML = html;
                fbDb.collection('users').doc(fbUser.uid).collection('work_blueprints').orderBy('savedAt', 'desc').get()
                    .then(function(snapshot) {
                        _wbRepoCache = [];
                        snapshot.forEach(function(doc) { var d = doc.data(); d.id = doc.id; _wbRepoCache.push(d); });
                        _wbCompWizRenderStep();
                    })
                    .catch(function(err) {
                        console.warn('Load blueprints error:', err);
                        _wbRepoCache = [];
                        _wbCompWizRenderStep();
                    });
                return;
            }

            if (_wbRepoCache.length === 0) {
                html += '<div style="text-align:center; padding:30px; color:var(--c-muted);">'
                    + '<p>No blueprints found. Create one with the <strong>Converter</strong> or <strong>Wizard</strong> first.</p></div></div>';
                body.innerHTML = html;
                return;
            }

            html += '<div style="display:flex; flex-direction:column; gap:6px; max-height:400px; overflow-y:auto;">';
            _wbRepoCache.forEach(function(bp, idx) {
                var selected = _wbCompWizData.wb && _wbCompWizData.wb._idx === idx;
                var border = selected ? '2px solid var(--accent)' : '1px solid var(--c-surface-5)';
                var bg = selected ? 'rgba(16,185,129,0.08)' : 'var(--c-surface-1)';
                html += '<div onclick="_wbCompWizSelectWB(' + idx + ')" style="background:' + bg + '; border:' + border + '; border-radius:10px; padding:12px 16px; cursor:pointer; transition:border-color 0.15s;">'
                    + '<div style="display:flex; justify-content:space-between; align-items:center;">'
                    + '<div>'
                    + '<div style="font-weight:600; color:var(--c-heading); font-size:0.92em;">' + escapeHtml(bp.title || 'Untitled') + '</div>'
                    + '<div style="font-size:0.78em; color:var(--c-muted);">'
                    + escapeHtml(bp.company || '') + (bp.industry ? ' \u00B7 ' + bp.industry : '') + (bp.seniority ? ' \u00B7 ' + bp.seniority : '')
                    + ' \u00B7 ' + (bp.skills || []).length + ' skills'
                    + '</div></div>'
                    + (selected ? '<span style="color:var(--accent); font-weight:700;">\u2713</span>' : '')
                    + '</div></div>';
            });
            html += '</div></div>';

            html += '<div style="display:flex; justify-content:flex-end; margin-top:16px;">'
                + '<button onclick="_wbCompWizNext()" ' + (_wbCompWizData.wb ? '' : 'disabled') + ' style="padding:10px 24px; background:' + (_wbCompWizData.wb ? 'var(--accent)' : 'var(--c-surface-3)') + '; color:' + (_wbCompWizData.wb ? '#fff' : 'var(--c-muted)') + '; border:none; border-radius:8px; cursor:pointer; font-weight:600; font-size:0.9em;">Next \u2192</button>'
                + '</div>';
            body.innerHTML = html;
        }

        function _wbCompWizSelectWB(idx) {
            var bp = _wbRepoCache[idx];
            bp._idx = idx;
            _wbCompWizData.wb = bp;
            if (bp.sourceJD || bp._rawJD) {
                _wbCompWizData.rawJD = bp.sourceJD || bp._rawJD;
            }
            _wbCompWizRenderStep();
        }
        window._wbCompWizSelectWB = _wbCompWizSelectWB;

        function _wbCompWizStep2(body) {
            var html = '<div style="background:var(--c-surface-2); border:1px solid var(--c-surface-5); border-radius:12px; padding:24px;">'
                + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:1.05em; color:var(--c-heading-bold); margin-bottom:4px;">'
                + bpIcon('file',18) + ' Add Traditional Job Description</div>'
                + '<div style="font-size:0.84em; color:var(--c-muted); margin-bottom:16px;">This raw JD text will be matched using keyword scanning \u2014 the way most ATS systems work today.</div>';

            if (_wbCompWizData.rawJD) {
                html += '<div style="margin-bottom:12px; padding:8px 12px; background:rgba(16,185,129,0.08); border-radius:8px; font-size:0.82em; color:#10b981;">'
                    + bpIcon('check',14) + ' JD text loaded (' + _wbCompWizData.rawJD.split(/\s+/).length + ' words). You can edit below or replace.</div>';
            }

            html += '<div style="display:flex; gap:8px; margin-bottom:12px;">'
                + '<input id="wbCompJDUrl" type="text" placeholder="Paste a job posting URL to fetch..." style="flex:1; padding:10px 14px; background:var(--c-surface-1); border:1px solid var(--c-surface-5); border-radius:8px; color:var(--c-heading); font-size:0.88em;" />'
                + '<button onclick="_wbCompWizFetchURL()" style="padding:10px 18px; background:#3b82f6; color:#fff; border:none; border-radius:8px; cursor:pointer; font-weight:600; font-size:0.85em; white-space:nowrap;">' + bpIcon('link',14) + ' Fetch</button>'
                + '</div>'
                + '<div id="wbCompFetchStatus" style="display:none; font-size:0.82em; color:var(--c-muted); margin-bottom:8px;"></div>'
                + '<textarea id="wbCompJDText" rows="12" placeholder="Or paste the full job description text here..." style="width:100%; padding:14px; background:var(--c-surface-1); border:1px solid var(--c-surface-5); border-radius:8px; color:var(--c-heading); font-size:0.85em; line-height:1.5; resize:vertical; font-family:inherit;">' + escapeHtml(_wbCompWizData.rawJD || '') + '</textarea>';

            html += '</div>';

            html += '<div style="display:flex; justify-content:space-between; margin-top:16px;">'
                + '<button onclick="_wbCompWizBack()" style="padding:10px 20px; background:var(--c-surface-3); color:var(--c-muted); border:1px solid var(--c-surface-5); border-radius:8px; cursor:pointer; font-weight:600; font-size:0.9em;">\u2190 Back</button>'
                + '<button onclick="_wbCompWizSaveJD()" style="padding:10px 24px; background:var(--accent); color:#fff; border:none; border-radius:8px; cursor:pointer; font-weight:600; font-size:0.9em;">Next \u2192</button>'
                + '</div>';
            body.innerHTML = html;
        }

        async function _wbCompWizFetchURL() {
            var urlInput = document.getElementById('wbCompJDUrl');
            var statusEl = document.getElementById('wbCompFetchStatus');
            if (!urlInput || !urlInput.value.trim()) {
                showToast('Enter a URL first.', 'warning');
                return;
            }
            var url = urlInput.value.trim();
            if (!url.match(/^https?:\/\//i)) url = 'https://' + url;
            statusEl.style.display = 'block';
            statusEl.innerHTML = '<div class="loading-spinner" style="width:14px; height:14px; border-width:2px; display:inline-block; vertical-align:middle; margin-right:6px;"></div> Fetching job posting...';
            try {
                var controller = new AbortController();
                var timeout = setTimeout(function() { controller.abort(); }, 15000);
                var resp = await fetch('/api/api-job-proxy?source=page&url=' + encodeURIComponent(url), { signal: controller.signal });
                clearTimeout(timeout);
                if (!resp.ok) throw new Error('Fetch failed (' + resp.status + ')');
                var html = await resp.text();
                var text = _jdcExtractTextFromHTML(html);
                if (text.length < 50) throw new Error('Could not extract enough text from page.');
                var ta = document.getElementById('wbCompJDText');
                if (ta) ta.value = text;
                statusEl.innerHTML = '<span style="color:#10b981;">' + bpIcon('check',14) + ' Fetched ' + text.split(/\s+/).length + ' words from URL.</span>';
                showToast('JD text fetched successfully!', 'success');
            } catch (err) {
                statusEl.innerHTML = '<span style="color:#ef4444;">' + bpIcon('alert',14) + ' ' + escapeHtml(err.message) + '</span>';
                showToast('URL fetch failed. Try pasting the text directly.', 'warning');
            }
        }
        window._wbCompWizFetchURL = _wbCompWizFetchURL;

        function _wbCompWizSaveJD() {
            var ta = document.getElementById('wbCompJDText');
            var text = ta ? ta.value.trim() : '';
            if (text.length < 30) {
                showToast('Please paste or fetch a job description (at least 30 characters).', 'warning');
                return;
            }
            _wbCompWizData.rawJD = text;
            _wbCompWizStep = 3;
            renderWBCompareWizard(document.getElementById('adminTabContent'));
        }
        window._wbCompWizSaveJD = _wbCompWizSaveJD;

        function _wbCompWizStep3(body) {
            var manifest = window.profilesManifest;
            var profiles = (manifest && manifest.profiles) ? manifest.profiles.filter(function(p) { return p.enabled; }) : [];

            var html = '<div style="background:var(--c-surface-2); border:1px solid var(--c-surface-5); border-radius:12px; padding:24px;">'
                + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:1.05em; color:var(--c-heading-bold); margin-bottom:4px;">'
                + bpIcon('users',18) + ' Select a Candidate Profile</div>'
                + '<div style="font-size:0.84em; color:var(--c-muted); margin-bottom:16px;">Choose a demo profile to match against both the traditional JD and the structured blueprint.</div>';

            var allProfiles = [{ id: 'comparison-candidate', name: 'Alex Morgan', title: 'VP of Business Strategy & Planning', path: 'profiles/demo/comparison-candidate.json', special: true }];
            profiles.forEach(function(p) { allProfiles.push(p); });

            html += '<div style="display:grid; grid-template-columns:repeat(auto-fill, minmax(240px, 1fr)); gap:8px; max-height:420px; overflow-y:auto;">';
            allProfiles.forEach(function(p) {
                var selected = _wbCompWizData.candidateId === p.id;
                var border = selected ? '2px solid var(--accent)' : '1px solid var(--c-surface-5)';
                var bg = selected ? 'rgba(16,185,129,0.08)' : 'var(--c-surface-1)';
                html += '<div onclick="_wbCompWizSelectCandidate(\'' + escapeHtml(p.id) + '\', \'' + escapeHtml(p.path) + '\')" style="background:' + bg + '; border:' + border + '; border-radius:10px; padding:12px 16px; cursor:pointer; transition:border-color 0.15s;">'
                    + '<div style="display:flex; justify-content:space-between; align-items:center;">'
                    + '<div>'
                    + '<div style="font-weight:600; color:var(--c-heading); font-size:0.92em;">' + escapeHtml(p.name) + (p.special ? ' <span style="font-size:0.7em; background:var(--accent); color:#fff; padding:1px 6px; border-radius:4px; font-weight:500;">DEFAULT</span>' : '') + '</div>'
                    + '<div style="font-size:0.78em; color:var(--c-muted);">' + escapeHtml(p.title || '') + '</div>'
                    + '</div>'
                    + (selected ? '<span style="color:var(--accent); font-weight:700;">\u2713</span>' : '')
                    + '</div></div>';
            });
            html += '</div></div>';

            html += '<div style="display:flex; justify-content:space-between; margin-top:16px;">'
                + '<button onclick="_wbCompWizBack()" style="padding:10px 20px; background:var(--c-surface-3); color:var(--c-muted); border:1px solid var(--c-surface-5); border-radius:8px; cursor:pointer; font-weight:600; font-size:0.9em;">\u2190 Back</button>'
                + '<button onclick="_wbCompWizRun()" ' + (_wbCompWizData.candidateId ? '' : 'disabled') + ' style="padding:10px 24px; background:' + (_wbCompWizData.candidateId ? 'var(--accent)' : 'var(--c-surface-3)') + '; color:' + (_wbCompWizData.candidateId ? '#fff' : 'var(--c-muted)') + '; border:none; border-radius:8px; cursor:pointer; font-weight:600; font-size:0.9em;">' + bpIcon('trending-up',14) + ' Run Comparison \u2192</button>'
                + '</div>';
            body.innerHTML = html;
        }

        function _wbCompWizSelectCandidate(id, path) {
            _wbCompWizData.candidateId = id;
            _wbCompWizData.candidatePath = path;
            _wbCompWizRenderStep();
        }
        window._wbCompWizSelectCandidate = _wbCompWizSelectCandidate;

        async function _wbCompWizRun() {
            if (!_wbCompWizData.candidateId || !_wbCompWizData.wb || !_wbCompWizData.rawJD) {
                showToast('Missing data. Complete all steps first.', 'warning');
                return;
            }
            _wbCompWizStep = 4;
            renderWBCompareWizard(document.getElementById('adminTabContent'));
            var body = document.getElementById('wbCompWizBody');
            if (body) {
                body.innerHTML = '<div style="text-align:center; padding:50px;">'
                    + '<div class="loading-spinner" style="width:32px; height:32px; border-width:3px; margin:0 auto 16px;"></div>'
                    + '<div style="font-family:Outfit,sans-serif; font-weight:600; color:var(--c-heading);">Running live comparison...</div>'
                    + '<div style="font-size:0.84em; color:var(--c-muted); margin-top:6px;">Matching candidate against both traditional JD and structured Work Blueprint.</div>'
                    + '</div>';
            }

            try {
                var candidate;
                if (_wbCompWizData.candidateId === 'comparison-candidate') {
                    candidate = await _wbLoadCompareCandidate();
                } else {
                    var resp = await fetch(_wbCompWizData.candidatePath + '?v=' + Date.now());
                    candidate = await resp.json();
                }
                _wbCompWizData.candidate = candidate;

                // Ensure company values are resolved (DB → API fallback) before comparison
                var wb = _wbCompWizData.wb;
                if (wb && wb.company) {
                    try {
                        var resolvedValues = await ensureCompanyValues(wb.company);
                        if (resolvedValues && resolvedValues.primary && resolvedValues.primary.length > 0) {
                            // Store resolved values on the WB so comparison engine picks them up
                            wb._resolvedCompanyValues = resolvedValues;
                        }
                    } catch (valErr) {
                        console.warn('[VALUES] ensureCompanyValues failed:', valErr.message);
                    }
                }

                var both = _wbCompareRunBoth(_wbCompWizData.rawJD, wb, candidate);
                var rawResult = both.raw;
                var structResult = both.struct;
                _wbCompWizData.rawResult = rawResult;
                _wbCompWizData.structResult = structResult;

                _wbCompWizStep4(body);
                showToast('Comparison complete!', 'success');
            } catch (err) {
                console.warn('Compare wizard error:', err);
                if (body) {
                    body.innerHTML = '<div style="text-align:center; padding:40px; color:#ef4444;">'
                        + bpIcon('alert',28) + '<p style="margin-top:12px;">Comparison failed: ' + escapeHtml(err.message) + '</p>'
                        + '<button onclick="_wbCompWizStep=3; _wbCompWizRenderStep();" style="margin-top:12px; padding:8px 20px; background:var(--c-surface-3); color:var(--c-heading); border:1px solid var(--c-surface-5); border-radius:8px; cursor:pointer;">\u2190 Go Back</button>'
                        + '</div>';
                }
                showToast('Comparison failed: ' + err.message, 'error');
            }
        }
        window._wbCompWizRun = _wbCompWizRun;

        function _wbCompWizStep4(body) {
            if (!body) body = document.getElementById('wbCompWizBody');
            if (!body) return;

            var wb = _wbCompWizData.wb;
            var rawResult = _wbCompWizData.rawResult;
            var structResult = _wbCompWizData.structResult;
            var candidate = _wbCompWizData.candidate;

            if (!rawResult || !structResult) {
                body.innerHTML = '<div style="text-align:center; padding:50px;">'
                    + '<div class="loading-spinner" style="width:32px; height:32px; border-width:3px; margin:0 auto 16px;"></div>'
                    + '<div style="font-family:Outfit,sans-serif; font-weight:600; color:var(--c-heading);">Running live comparison...</div>'
                    + '<div style="font-size:0.84em; color:var(--c-muted); margin-top:6px;">Matching candidate against both traditional JD and structured Work Blueprint.</div>'
                    + '</div>';
                return;
            }

            var html = '<div style="margin-bottom:16px; display:flex; justify-content:space-between; align-items:center;">'
                + '<div style="font-size:0.84em; color:var(--c-muted);">'
                + '<strong>Blueprint:</strong> ' + escapeHtml((wb || {}).title || 'Untitled')
                + ' &nbsp;\u00B7&nbsp; <strong>Candidate:</strong> ' + escapeHtml(((candidate || {}).profile || {}).name || _wbCompWizData.candidateId)
                + '</div>'
                + '<div style="display:flex; gap:8px;">'
                + '<button onclick="_wbCompSaveCurrent()" style="padding:6px 14px; background:linear-gradient(135deg, #10b981, #3b82f6); color:#fff; border:none; border-radius:6px; cursor:pointer; font-size:0.8em; font-weight:600;">' + bpIcon('save',12) + ' Save</button>'
                + '<button onclick="_wbCompShareCurrent()" style="padding:6px 14px; background:linear-gradient(135deg, #6366f1, #8b5cf6); color:#fff; border:none; border-radius:6px; cursor:pointer; font-size:0.8em; font-weight:600;">' + bpIcon('external',12) + ' Share</button>'
                + '<button onclick="_wbCompExportPDF()" style="padding:6px 14px; background:var(--c-surface-3); color:var(--c-heading); border:1px solid var(--c-surface-5); border-radius:6px; cursor:pointer; font-size:0.8em;">' + bpIcon('file-text',12) + ' PDF</button>'
                + '<button onclick="_wbCompWizStep=1; _wbCompWizData={wb:null,rawJD:\'\',candidateId:\'\',candidate:null}; renderWBCompareWizard(document.getElementById(\'adminTabContent\'));" style="padding:6px 14px; background:var(--c-surface-3); color:var(--c-muted); border:1px solid var(--c-surface-5); border-radius:6px; cursor:pointer; font-size:0.8em;">' + bpIcon('refresh',12) + ' New Comparison</button>'
                + '<button onclick="_wbCompWizStep=1; renderWBCompareWizard(document.getElementById(\'adminTabContent\'));" style="padding:6px 14px; background:#ef4444; color:#fff; border:none; border-radius:6px; cursor:pointer; font-size:0.8em; font-weight:600;">' + bpIcon('x',12) + ' Close</button>'
                + '</div></div>';

            html += _wbRenderComparison(wb, rawResult, structResult, candidate);
            body.innerHTML = html;
        }

        function _wbCompWizNext() {
            if (_wbCompWizStep === 1 && _wbCompWizData.wb) {
                _wbCompWizStep = 2;
                renderWBCompareWizard(document.getElementById('adminTabContent'));
            }
        }
        window._wbCompWizNext = _wbCompWizNext;

        function _wbCompWizBack() {
            if (_wbCompWizStep > 1) {
                _wbCompWizStep -= 1;
                renderWBCompareWizard(document.getElementById('adminTabContent'));
            }
        }
        window._wbCompWizBack = _wbCompWizBack;

        // ── Comparison Save/Load Infrastructure (Firestore-primary, localStorage fallback) ──

        // In-memory cache so repo renders instantly after first load
        var _wbCompCache = null;
        var _wbCompCacheLoaded = false;

        function _wbCompFSPath() {
            return fbDb && fbUser ? fbDb.collection('users').doc(fbUser.uid).collection('comparisons') : null;
        }

        // localStorage key kept for migration + offline fallback
        var _wbCompLSKey = 'bpSavedComparisons';

        function _wbCompGetLS() { return safeParse(safeGet(_wbCompLSKey), []); }

        // Migrate any existing localStorage comparisons into Firestore (runs once)
        function _wbCompMigrateLS() {
            var col = _wbCompFSPath();
            if (!col) return;
            var legacy = _wbCompGetLS();
            if (!legacy.length) return;
            console.log('[Comparisons] Migrating ' + legacy.length + ' localStorage comparisons to Firestore...');
            var batch = fbDb.batch();
            legacy.forEach(function(entry) {
                var safe = _wbCompSanitize(entry);
                batch.set(col.doc(safe.id), safe);
            });
            batch.commit().then(function() {
                safeRemove(_wbCompLSKey);
                console.log('[Comparisons] Migration complete.');
            }).catch(function(e) {
                console.warn('[Comparisons] Migration failed:', e.message);
            });
        }

        // Trim large arrays to keep docs under Firestore 1MB limit
        function _wbCompSanitize(entry) {
            var e = JSON.parse(JSON.stringify(entry));
            if (e.structResult) {
                if ((e.structResult.matched || []).length > 150) e.structResult.matched = e.structResult.matched.slice(0, 150);
                if ((e.structResult.gaps || []).length > 150) e.structResult.gaps = e.structResult.gaps.slice(0, 150);
            }
            if (e.rawResult) {
                if ((e.rawResult.matched || []).length > 150) e.rawResult.matched = e.rawResult.matched.slice(0, 150);
                if ((e.rawResult.gaps || []).length > 150) e.rawResult.gaps = e.rawResult.gaps.slice(0, 150);
            }
            return e;
        }

        // Load all comparisons — returns Promise<array>
        function _wbCompLoad() {
            if (_wbCompCacheLoaded) return Promise.resolve(_wbCompCache || []);
            var col = _wbCompFSPath();
            if (!col) {
                var ls = _wbCompGetLS();
                _wbCompCache = ls;
                _wbCompCacheLoaded = true;
                return Promise.resolve(ls);
            }
            return col.orderBy('savedAt', 'desc').limit(50).get().then(function(snap) {
                var arr = [];
                snap.forEach(function(doc) { arr.push(doc.data()); });
                _wbCompCache = arr;
                _wbCompCacheLoaded = true;
                // Migrate any legacy localStorage entries now that Firestore is confirmed working
                _wbCompMigrateLS();
                return arr;
            }).catch(function(e) {
                console.warn('[Comparisons] Firestore load failed, using localStorage:', e.message);
                var ls = _wbCompGetLS();
                _wbCompCache = ls;
                _wbCompCacheLoaded = true;
                return ls;
            });
        }

        function _wbCompSaveCurrent() {
            var d = _wbCompWizData;
            if (!d.wb || !d.rawResult || !d.structResult) { showToast('No comparison to save.', 'warning'); return; }
            var entry = {
                id: 'comp-' + Date.now(),
                savedAt: new Date().toISOString(),
                blueprintTitle: d.wb.title || 'Untitled',
                company: d.wb.company || '',
                candidateName: ((d.candidate || {}).profile || {}).name || d.candidateId || 'Unknown',
                candidateTitle: ((d.candidate || {}).profile || {}).title || '',
                jdScore: d.rawResult.score || 0,
                wbScore: d.structResult.score || 0,
                matched: (d.structResult.matched || []).length,
                total: d.structResult.skillsUsed || 0,
                gaps: (d.structResult.gaps || []).length,
                valuesScore: d.structResult.valuesScore || 0,
                profPct: d.structResult.profMeets > 0 ? Math.round(d.structResult.profMeets / (d.structResult.profMeets + (d.structResult.profGaps || 0)) * 100) : 0,
                wb: d.wb,
                rawJD: d.rawJD,
                rawResult: d.rawResult,
                structResult: d.structResult,
                candidate: d.candidate
            };
            var safe = _wbCompSanitize(entry);
            // Optimistic UI: update cache immediately
            _wbCompCache = [safe].concat(_wbCompCache || []).slice(0, 50);
            _wbCompCacheLoaded = true;
            showToast('Saving comparison...', 'info', 2000);
            var col = _wbCompFSPath();
            var persist = col
                ? col.doc(safe.id).set(safe).then(function() { showToast('Comparison saved!', 'success'); })
                : Promise.resolve(function() {
                    var ls = _wbCompGetLS();
                    ls.unshift(safe);
                    if (ls.length > 50) ls = ls.slice(0, 50);
                    safeSet(_wbCompLSKey, JSON.stringify(ls));
                    showToast('Comparison saved (offline).', 'success');
                  }());
            persist.catch(function(e) {
                console.warn('[Comparisons] Save failed:', e.message);
                showToast('Save failed — stored locally as fallback.', 'warning');
                var ls = _wbCompGetLS(); ls.unshift(safe); if (ls.length > 50) ls = ls.slice(0,50);
                safeSet(_wbCompLSKey, JSON.stringify(ls));
            });
            var el = document.getElementById('wbCompRepoContainer');
            if (el) _wbCompRenderRepo(el);
        }
        window._wbCompSaveCurrent = _wbCompSaveCurrent;

        function _wbCompDeleteSaved(id) {
            // Remove from cache immediately
            if (_wbCompCache) _wbCompCache = _wbCompCache.filter(function(s) { return s.id !== id; });
            var col = _wbCompFSPath();
            if (col) {
                col.doc(id).delete().catch(function(e) { console.warn('[Comparisons] Delete failed:', e.message); });
            } else {
                var ls = _wbCompGetLS().filter(function(s) { return s.id !== id; });
                safeSet(_wbCompLSKey, JSON.stringify(ls));
            }
            showToast('Comparison removed.', 'info');
            var el = document.getElementById('wbCompRepoContainer');
            if (el) _wbCompRenderRepo(el);
        }
        window._wbCompDeleteSaved = _wbCompDeleteSaved;
        
        // ── Comparison Repository ──
        function _wbCompRenderRepo(container) {
            if (!_wbCompCacheLoaded) {
                container.innerHTML = '<div style="text-align:center; padding:24px; color:var(--c-muted); font-size:0.85em;">'
                    + bpIcon('loader', 20) + '<div style="margin-top:8px;">Loading saved comparisons...</div></div>';
            }
            _wbCompLoad().then(function(saved) {
                if (saved.length === 0) {
                    container.innerHTML = '<div style="text-align:center; padding:30px; color:var(--c-muted); font-size:0.85em;">'
                        + bpIcon('archive', 24) + '<div style="margin-top:8px;">No saved comparisons yet. Run a comparison and click Save.</div></div>';
                    return;
                }
                var syncBadge = fbUser ? '<span style="font-size:0.68em; color:#10b981; margin-left:8px; padding:2px 7px; background:rgba(16,185,129,0.1); border-radius:10px;">' + bpIcon('cloud',10) + ' Synced</span>' : '';
                var html = '<div style="margin-bottom:10px; display:flex; align-items:center;">'
                    + '<span style="font-size:0.75em; color:var(--c-muted);">' + saved.length + ' saved comparison' + (saved.length !== 1 ? 's' : '') + syncBadge + '</span>'
                    + '</div>';
                html += '<div style="display:grid; grid-template-columns:repeat(auto-fill, minmax(320px, 1fr)); gap:12px;">';
                saved.forEach(function(s) {
                    var date = new Date(s.savedAt);
                    var dateStr = date.toLocaleDateString() + ' ' + date.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'});
                    var delta = s.wbScore - s.jdScore;
                    var deltaColor = delta > 0 ? '#10b981' : delta < 0 ? '#ef4444' : 'var(--c-muted)';
                    html += '<div style="background:var(--c-surface-2); border:1px solid var(--c-surface-3); border-radius:10px; padding:14px; cursor:pointer; transition:border-color 0.2s;" onmouseover="this.style.borderColor=\'#10b981\'" onmouseout="this.style.borderColor=\'var(--c-surface-3)\'" onclick="_wbCompOpenModal(\'' + s.id + '\')">'
                        + '<div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:8px;">'
                        + '<div>'
                        + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:0.88em; color:var(--c-heading);">' + escapeHtml(s.candidateName) + '</div>'
                        + '<div style="font-size:0.75em; color:var(--c-muted);">' + escapeHtml(s.candidateTitle) + '</div>'
                        + '</div>'
                        + '<button onclick="event.stopPropagation(); _wbCompDeleteSaved(\'' + s.id + '\')" style="background:none; border:none; color:var(--c-muted); cursor:pointer; padding:4px;" title="Remove">' + bpIcon('x',14) + '</button>'
                        + '</div>'
                        + '<div style="font-size:0.72em; color:var(--c-muted); margin-bottom:8px;">' + escapeHtml(s.blueprintTitle) + (s.company ? ' at ' + escapeHtml(s.company) : '') + '</div>'
                        + '<div style="display:grid; grid-template-columns:1fr 1fr 1fr; gap:6px; margin-bottom:8px;">'
                        + '<div style="text-align:center; padding:6px; background:var(--c-surface-3); border-radius:6px;">'
                        + '<div style="font-size:1em; font-weight:700; color:#10b981;">' + s.wbScore + '%</div>'
                        + '<div style="font-size:0.65em; color:var(--c-muted);">WB Score</div></div>'
                        + '<div style="text-align:center; padding:6px; background:var(--c-surface-3); border-radius:6px;">'
                        + '<div style="font-size:1em; font-weight:700; color:var(--c-muted);">' + s.jdScore + '%</div>'
                        + '<div style="font-size:0.65em; color:var(--c-muted);">JD Score</div></div>'
                        + '<div style="text-align:center; padding:6px; background:var(--c-surface-3); border-radius:6px;">'
                        + '<div style="font-size:1em; font-weight:700; color:' + deltaColor + ';">' + (delta > 0 ? '+' : '') + delta + '</div>'
                        + '<div style="font-size:0.65em; color:var(--c-muted);">Delta</div></div>'
                        + '</div>'
                        + '<div style="display:flex; justify-content:space-between; font-size:0.7em; color:var(--c-muted);">'
                        + '<span>' + s.matched + '/' + s.total + ' skills \u00B7 ' + s.gaps + ' gaps \u00B7 ' + s.valuesScore + '% values</span>'
                        + '<span>' + dateStr + '</span>'
                        + '</div>'
                        + '</div>';
                });
                html += '</div>';
                container.innerHTML = html;
            });
        }

        // ── Comparison Modal ──
        function _wbCompOpenModal(id) {
            var fromCache = (_wbCompCache || []).find(function(s) { return s.id === id; });
            var lookup = fromCache
                ? Promise.resolve(fromCache)
                : (_wbCompFSPath()
                    ? _wbCompFSPath().doc(id).get().then(function(d) { return d.exists ? d.data() : null; })
                    : Promise.resolve(null));
            lookup.then(function(entry) {
                if (!entry || !entry.wb || !entry.rawResult || !entry.structResult) {
                    showToast('Comparison data not available.', 'warning');
                    return;
                }
                var existing = document.getElementById('wbCompModal');
                if (existing) existing.remove();
                var overlay = document.createElement('div');
                overlay.id = 'wbCompModal';
                overlay.style.cssText = 'position:fixed; top:0; left:0; width:100vw; height:100vh; z-index:99999; background:#0f172a; overflow-y:auto; padding:20px 20px 60px;';
                var closeBar = '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:16px; padding:12px 16px; background:rgba(30,41,59,0.95); border-radius:10px; border:1px solid rgba(51,65,85,0.5); position:sticky; top:0; z-index:100; backdrop-filter:blur(8px);">'
                    + '<div style="font-family:Outfit,sans-serif; font-weight:700; color:#f1f5f9;">'
                    + bpIcon('trending-up', 16) + ' Saved Comparison \u2014 ' + escapeHtml(entry.candidateName) + '</div>'
                    + '<div style="display:flex; gap:8px;">'
                    + '<button onclick="_wbCompShareSaved(\'' + id + '\')" style="padding:8px 16px; background:linear-gradient(135deg,#6366f1,#8b5cf6); color:#fff; border:none; border-radius:8px; cursor:pointer; font-size:0.82em; font-weight:600;">' + bpIcon('external',12) + ' Share</button>'
                    + '<button onclick="_wbCompExportPDFFromSaved(\'' + id + '\')" style="padding:8px 16px; background:rgba(51,65,85,0.8); color:#e2e8f0; border:1px solid rgba(71,85,105,0.5); border-radius:8px; cursor:pointer; font-size:0.82em; font-weight:500;">' + bpIcon('file-text',12) + ' Export PDF</button>'
                    + '<button onclick="_wbCompCloseModal()" style="padding:8px 16px; background:#ef4444; color:#fff; border:none; border-radius:8px; cursor:pointer; font-size:0.82em; font-weight:600;">' + bpIcon('x',12) + ' Close</button>'
                    + '</div></div>';
                var content = _wbRenderComparison(entry.wb, entry.rawResult, entry.structResult, entry.candidate);
                overlay.innerHTML = '<div style="max-width:960px; margin:0 auto;">' + closeBar + content + '</div>';
                document.body.appendChild(overlay);
                document.body.style.overflow = 'hidden';
            });
        }
        window._wbCompOpenModal = _wbCompOpenModal;
        
        function _wbCompCloseModal() {
            var modal = document.getElementById('wbCompModal');
            if (modal) modal.remove();
            document.body.style.overflow = '';
        }
        window._wbCompCloseModal = _wbCompCloseModal;

        // ── Comparison Sharing ──
        // Writes a sanitized copy to shared_comparisons/{id} (public read by token).
        // URL: ?comp={id}&token={shareToken}  — handled at page load.
        function _wbCompShareCurrent() {
            var d = _wbCompWizData;
            if (!d.wb || !d.rawResult || !d.structResult) { showToast('No comparison to share.', 'warning'); return; }
            if (!fbDb) { showToast('Sign in required to generate share links.', 'warning'); return; }
            _wbCompDoShare(d.wb, d.rawResult, d.structResult, d.candidate, d.rawJD);
        }
        window._wbCompShareCurrent = _wbCompShareCurrent;

        function _wbCompShareSaved(id) {
            var fromCache = (_wbCompCache || []).find(function(s) { return s.id === id; });
            var lookup = fromCache
                ? Promise.resolve(fromCache)
                : (_wbCompFSPath()
                    ? _wbCompFSPath().doc(id).get().then(function(d) { return d.exists ? d.data() : null; })
                    : Promise.resolve(null));
            lookup.then(function(entry) {
                if (!entry) { showToast('Comparison not found.', 'warning'); return; }
                // If already shared, re-surface URL
                if (entry.shareToken && entry.shareId) {
                    var url = _wbCompBuildShareUrl(entry.shareId, entry.shareToken);
                    _wbCompCopyUrl(url);
                    return;
                }
                _wbCompDoShare(entry.wb, entry.rawResult, entry.structResult, entry.candidate, entry.rawJD, id);
            });
        }
        window._wbCompShareSaved = _wbCompShareSaved;

        function _wbCompBuildShareUrl(shareId, shareToken) {
            return window.location.origin + window.location.pathname + '?comp=' + shareId + '&token=' + shareToken;
        }

        function _wbCompCopyUrl(url) {
            if (navigator.clipboard) {
                navigator.clipboard.writeText(url).then(function() {
                    showToast('Share link copied!', 'success', 6000);
                });
            } else {
                var ta = document.createElement('textarea');
                ta.value = url;
                document.body.appendChild(ta);
                ta.select();
                document.execCommand('copy');
                ta.remove();
                showToast('Share link copied!', 'success', 6000);
            }
        }

        function _wbCompDoShare(wb, rawResult, structResult, candidate, rawJD, savedCompId) {
            showToast('Generating share link...', 'info', 3000);
            // Crypto IDs
            var idBytes = new Uint8Array(16);
            crypto.getRandomValues(idBytes);
            var shareId = 'comp-' + Date.now().toString(36) + Array.from(idBytes, function(b) { return b.toString(16).padStart(2,'0'); }).join('');
            var tokenBytes = new Uint8Array(16);
            crypto.getRandomValues(tokenBytes);
            var shareToken = Array.from(tokenBytes, function(b) { return b.toString(16).padStart(2,'0'); }).join('');

            var entry = _wbCompSanitize({
                id: shareId,
                shareToken: shareToken,
                sharedAt: new Date().toISOString(),
                sharedBy: fbUser ? fbUser.uid : 'anonymous',
                blueprintTitle: (wb || {}).title || 'Untitled',
                company: (wb || {}).company || '',
                candidateName: ((candidate || {}).profile || {}).name || 'Candidate',
                candidateTitle: ((candidate || {}).profile || {}).title || '',
                jdScore: (rawResult || {}).score || 0,
                wbScore: (structResult || {}).score || 0,
                wb: wb,
                rawJD: rawJD || '',
                rawResult: rawResult,
                structResult: structResult,
                candidate: candidate
            });

            fbDb.collection('shared_comparisons').doc(shareId).set(entry)
                .then(function() {
                    var url = _wbCompBuildShareUrl(shareId, shareToken);
                    _wbCompCopyUrl(url);
                    // Patch shareToken/shareId onto the saved comparison so re-share is instant
                    if (savedCompId && _wbCompFSPath()) {
                        _wbCompFSPath().doc(savedCompId).update({ shareId: shareId, shareToken: shareToken })
                            .catch(function() {});
                        if (_wbCompCache) {
                            var cached = _wbCompCache.find(function(s) { return s.id === savedCompId; });
                            if (cached) { cached.shareId = shareId; cached.shareToken = shareToken; }
                        }
                    }
                })
                .catch(function(e) {
                    console.error('[Comparisons] Share write failed:', e);
                    showToast('Share failed: ' + e.message, 'error');
                });
        }

        // ── Shared comparison viewer (URL: ?comp=...&token=...) ──
        function _wbCompCheckSharedUrl() {
            try {
                var params = new URLSearchParams(window.location.search);
                var compId = params.get('comp');
                var token  = params.get('token');
                if (!compId || !token) return;
                if (!fbDb) { showToast('Cannot load shared comparison: database unavailable.', 'warning'); return; }
                // Clean URL immediately
                if (window.history && window.history.replaceState) {
                    window.history.replaceState(null, '', window.location.pathname);
                }
                showToast('Loading shared comparison...', 'info', 3000);
                fbDb.collection('shared_comparisons').doc(compId).get().then(function(doc) {
                    if (!doc.exists) { showToast('Shared comparison not found or has been removed.', 'warning'); return; }
                    var data = doc.data();
                    if (!data.shareToken || data.shareToken !== token) {
                        showToast('Invalid share link.', 'error');
                        return;
                    }
                    if (!data.wb || !data.rawResult || !data.structResult) {
                        showToast('Comparison data incomplete.', 'warning');
                        return;
                    }
                    // Render in read-only modal
                    var existing = document.getElementById('wbCompModal');
                    if (existing) existing.remove();
                    var overlay = document.createElement('div');
                    overlay.id = 'wbCompModal';
                    overlay.style.cssText = 'position:fixed; top:0; left:0; width:100vw; height:100vh; z-index:99999; background:#0f172a; overflow-y:auto; padding:20px 20px 60px;';
                    var sharedAt = data.sharedAt ? new Date(data.sharedAt).toLocaleDateString() : '';
                    var closeBar = '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:16px; padding:12px 16px; background:rgba(30,41,59,0.95); border-radius:10px; border:1px solid rgba(51,65,85,0.5); position:sticky; top:0; z-index:100; backdrop-filter:blur(8px);">'
                        + '<div style="font-family:Outfit,sans-serif; font-weight:700; color:#f1f5f9;">'
                        + bpIcon('trending-up', 16) + ' Shared Comparison \u2014 ' + escapeHtml(data.candidateName)
                        + '<span style="font-size:0.68em; color:#64748b; margin-left:10px; font-weight:400;">Shared ' + sharedAt + ' \u00B7 Read-only</span>'
                        + '</div>'
                        + '<button onclick="_wbCompCloseModal()" style="padding:8px 16px; background:#ef4444; color:#fff; border:none; border-radius:8px; cursor:pointer; font-size:0.82em; font-weight:600;">' + bpIcon('x',12) + ' Close</button>'
                        + '</div>';
                    var content = _wbRenderComparison(data.wb, data.rawResult, data.structResult, data.candidate);
                    overlay.innerHTML = '<div style="max-width:960px; margin:0 auto;">' + closeBar + content + '</div>';
                    document.body.appendChild(overlay);
                    document.body.style.overflow = 'hidden';
                }).catch(function(e) {
                    showToast('Could not load comparison: ' + e.message, 'error');
                });
            } catch(e) { /* URLSearchParams not supported */ }
        }
        window._wbCompCheckSharedUrl = _wbCompCheckSharedUrl;

        // Close modal on Escape key
        document.addEventListener('keydown', function(e) {
            if (e.key === 'Escape' && document.getElementById('wbCompModal')) {
                _wbCompCloseModal();
            }
        });

