                + '<div style="font-family:Outfit,sans-serif; font-weight:700; font-size:1.05em; color:#f1f5f9; margin-bottom:4px;">' + bpIcon('file-text', 16) + ' Export PDF</div>'
                + '<div style="font-size:0.78em; color:#94a3b8; margin-bottom:16px;">Choose a theme for your export.</div>'
