                // Light option
                + '<div id="pdfThemeLight" style="cursor:pointer; border-radius:10px; border:2px solid #334155; padding:14px; text-align:center; transition:border-color 0.2s;" onmouseover="this.style.borderColor=\'#10b981\'" onmouseout="this.style.borderColor=\'#334155\'">'
                + '<div style="width:100%; height:48px; background:#f8fafc; border-radius:6px; margin-bottom:8px; display:flex; align-items:center; justify-content:center;">'
                + '<div style="width:30px; height:6px; background:#10b981; border-radius:3px; margin:2px;"></div>'
