                + '</div>'
                // Dark option
                + '<div id="pdfThemeDark" style="cursor:pointer; border-radius:10px; border:2px solid #334155; padding:14px; text-align:center; transition:border-color 0.2s;" onmouseover="this.style.borderColor=\'#10b981\'" onmouseout="this.style.borderColor=\'#334155\'">'
                + '<div style="width:100%; height:48px; background:#0f172a; border-radius:6px; margin-bottom:8px; border:1px solid #1e293b; display:flex; align-items:center; justify-content:center;">'
                + '<div style="width:30px; height:6px; background:#10b981; border-radius:3px; margin:2px;"></div>'
                + '<div style="width:20px; height:6px; background:#475569; border-radius:3px; margin:2px;"></div>'
                + '</div>'
                + '<div style="font-size:0.82em; font-weight:600; color:#f1f5f9;">Dark</div>'
