            document.body.appendChild(popup);
            
            document.getElementById('pdfThemeLight').onclick = function() { popup.remove(); callback('light'); };
            document.getElementById('pdfThemeDark').onclick = function() { popup.remove(); callback('dark'); };
            document.getElementById('pdfThemeCancel').onclick = function() { popup.remove(); };
