        function _wbCompBuildPDF(wb, rawResult, structResult, candidate, theme) {
            showToast('Generating PDF...', 'info', 5000);
            
            // Load html2canvas if not present
            var needsH2C = typeof html2canvas === 'undefined';
            var needsJsPDF = typeof window.jspdf === 'undefined';
            var loaded = 0;
            var total = (needsH2C ? 1 : 0) + (needsJsPDF ? 1 : 0);
            
            function tryRender() {
                loaded++;
                if (loaded >= total) _wbCompRenderPDF(wb, rawResult, structResult, candidate, theme);
            }
            
            if (total === 0) {
                _wbCompRenderPDF(wb, rawResult, structResult, candidate, theme);
                return;
            }
            
            if (needsH2C) {
                var s1 = document.createElement('script');
                s1.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';
                s1.onload = tryRender;
                s1.onerror = function() { showToast('Failed to load PDF library.', 'error'); };
                document.head.appendChild(s1);
            }
            if (needsJsPDF) {
                var s2 = document.createElement('script');
                s2.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';
                s2.onload = tryRender;
                s2.onerror = function() { showToast('Failed to load PDF library.', 'error'); };
                document.head.appendChild(s2);
            }
        }
        
        function _wbCompRenderPDF(wb, rawResult, structResult, candidate, theme) {
            var cName = ((candidate || {}).profile || {}).name || 'Candidate';
            var isLight = theme === 'light';
            
            // Theme colors
            var bg = isLight ? '#ffffff' : '#0f172a';
            var surface2 = isLight ? '#f1f5f9' : '#1e293b';
            var surface3 = isLight ? '#e2e8f0' : '#334155';
            var surface5 = isLight ? '#cbd5e1' : '#475569';
            var heading = isLight ? '#0f172a' : '#f1f5f9';
            var headingBold = isLight ? '#0f172a' : '#ffffff';
            var body = isLight ? '#334155' : '#cbd5e1';
            var muted = isLight ? '#64748b' : '#94a3b8';
            var accent = '#10b981';
            
            // 1. Create off-screen container
            var container = document.createElement('div');
            container.id = 'pdfRenderTarget';
            container.style.cssText = 'position:fixed; left:-9999px; top:0; width:900px; padding:24px; background:' + bg + '; color:' + body + '; z-index:-1; font-family:Inter,system-ui,sans-serif; font-size:14px;';
            
            // Set CSS variables for the rendered HTML
            container.style.setProperty('--c-bg', bg);
            container.style.setProperty('--c-surface-2', surface2);
            container.style.setProperty('--c-surface-3', surface3);
            container.style.setProperty('--c-surface-5', surface5);
            container.style.setProperty('--c-heading', heading);
            container.style.setProperty('--c-heading-bold', headingBold);
            container.style.setProperty('--c-body', body);
            container.style.setProperty('--c-muted', muted);
            container.style.setProperty('--accent', accent);
            
            // 2. Render the comparison HTML
            var compHtml = _wbRenderComparison(wb, rawResult, structResult, candidate);
            
            // Add a branded header
            var headerHtml = '<div style="text-align:center; margin-bottom:20px; padding-bottom:16px; border-bottom:1px solid ' + (isLight ? '#e2e8f0' : 'rgba(255,255,255,0.1)') + ';">'
                + '<div style="font-family:Outfit,sans-serif; font-weight:800; font-size:1.3em; color:' + headingBold + '; letter-spacing:0.04em;">BLUEPRINT ADVANTAGE\u2122 COMPARISON</div>'
                + '<div style="font-size:0.82em; color:' + muted + '; margin-top:4px;">Generated ' + new Date().toLocaleDateString() + ' \u00B7 This analysis reflects data-driven pattern matching, not a hiring recommendation.</div>'
                + '</div>';
            
            // Add a footer
            var footerHtml = '<div style="text-align:center; margin-top:20px; padding-top:12px; border-top:1px solid ' + (isLight ? '#e2e8f0' : 'rgba(255,255,255,0.1)') + '; font-size:0.72em; color:' + muted + ';">'
                + 'Blueprint\u2122 v' + (window.BP_VERSION || '4.45.22') + ' \u00B7 Powered by structured intelligence'
                + '</div>';
            
            container.innerHTML = headerHtml + compHtml + footerHtml;
            document.body.appendChild(container);
            
            // 3. Wait for render, then capture
            setTimeout(function() {
                html2canvas(container, {
                    scale: 2,
                    useCORS: true,
                    backgroundColor: bg,
                    width: 900,
                    windowWidth: 900,
                    logging: false
                }).then(function(canvas) {
                    // 4. Paginate into A4 PDF
                    var jsPDF = window.jspdf.jsPDF;
                    var imgWidth = 210; // A4 width in mm
                    var pageHeight = 297; // A4 height in mm
                    var margin = 5;
                    var usableWidth = imgWidth - 2 * margin;
                    var usableHeight = pageHeight - 2 * margin;
                    
                    var canvasWidth = canvas.width;
                    var canvasHeight = canvas.height;
                    var ratio = usableWidth / (canvasWidth / 2); // /2 because scale:2
                    var scaledHeight = (canvasHeight / 2) * ratio;
                    
                    var doc = new jsPDF('portrait', 'mm', 'a4');
                    
                    if (scaledHeight <= usableHeight) {
                        // Fits on one page
                        var imgData = canvas.toDataURL('image/png');
                        doc.addImage(imgData, 'PNG', margin, margin, usableWidth, scaledHeight);
                    } else {
                        // Multi-page: slice the canvas
                        var pageCanvasHeight = Math.floor(canvasHeight * (usableHeight / scaledHeight));
                        var totalPages = Math.ceil(canvasHeight / pageCanvasHeight);
                        
                        for (var p = 0; p < totalPages; p++) {
                            if (p > 0) doc.addPage();
                            
                            var srcY = p * pageCanvasHeight;
                            var srcH = Math.min(pageCanvasHeight, canvasHeight - srcY);
                            var destH = usableHeight * (srcH / pageCanvasHeight);
                            
                            // Create a slice canvas
                            var sliceCanvas = document.createElement('canvas');
                            sliceCanvas.width = canvasWidth;
                            sliceCanvas.height = srcH;
                            var ctx = sliceCanvas.getContext('2d');
                            ctx.drawImage(canvas, 0, srcY, canvasWidth, srcH, 0, 0, canvasWidth, srcH);
                            
                            var sliceData = sliceCanvas.toDataURL('image/png');
                            doc.addImage(sliceData, 'PNG', margin, margin, usableWidth, destH);
                        }
                    }
                    
                    // 5. Save and clean up
                    var filename = (cName + '-' + (wb.title || 'comparison')).replace(/[^a-zA-Z0-9]+/g, '-').toLowerCase() + '.pdf';
                    doc.save(filename);
                    showToast('PDF exported: ' + filename, 'success');
                    
                    // Clean up
                    container.remove();
                }).catch(function(err) {
                    console.error('[PDF] html2canvas error:', err);
                    showToast('PDF generation failed. Try again.', 'error');
                    container.remove();
                });
            }, 300); // Brief delay for CSS/fonts to render
        }

        function wbRepoExport(mode) {
            if (_wbRepoViewIdx < 0 || !_wbRepoCache[_wbRepoViewIdx]) return;
            var bp = _wbRepoCache[_wbRepoViewIdx];
            if (mode === 'json') {
                var exportData = _jdcStripHiddenComp(_jdcPrepareExport(bp));
                var blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
                var url = URL.createObjectURL(blob);
                var a = document.createElement('a');
                a.href = url; a.download = (bp.title || 'work-blueprint').replace(/[^a-zA-Z0-9]+/g, '-') + '.json';
                document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
                showToast('JSON exported.', 'success');
                logAnalyticsEvent('wb_exported_json', { title: bp.title || '' });
            } else if (mode === 'pdf' && typeof exportWorkBlueprintPDF === 'function') {
                _jdcResult = bp;
                exportWorkBlueprintPDF();
                logAnalyticsEvent('wb_exported_pdf', { title: bp.title || '' });
            } else if (mode === 'word' && typeof exportWorkBlueprintWord === 'function') {
                _jdcResult = bp;
                exportWorkBlueprintWord();
                logAnalyticsEvent('wb_exported_word', { title: bp.title || '' });
            } else {
                showToast('Export not available for this format.', 'warning');
            }
        }
        window.wbRepoExport = wbRepoExport;

        function wbRepoLoadInConverter(idx) {
            if (!_wbRepoCache || !_wbRepoCache[idx]) return;
            _jdcResult = _wbRepoCache[idx];
            _jdcCompMode = 'without';
            _jdcInputMode = 'paste';
            _jdcEditMode = true;
            _jdcFromRepo = true;
            if (!_jdcResult.skills) _jdcResult.skills = [];
            if (!_jdcResult.values) _jdcResult.values = [];
            if (!_jdcResult.certifications) _jdcResult.certifications = [];
            if (!_jdcResult.qualifications) _jdcResult.qualifications = [];
            if (!_jdcResult.yearsRequired) _jdcResult.yearsRequired = [];
            if (!_jdcResult.education) _jdcResult.education = [];
            adminSubTab = 'jdconverter';
            renderAdminTabContent();
            showToast('Editing: ' + (_jdcResult.title || 'Untitled'), 'success');
        }
        window.wbRepoLoadInConverter = wbRepoLoadInConverter;

        var _wbRepoEditIdx = -1;
        function wbRepoEditModal(idx) {
            if (!_wbRepoCache || !_wbRepoCache[idx]) return;
            _wbRepoEditIdx = idx;
            _jdcResult = JSON.parse(JSON.stringify(_wbRepoCache[idx]));
            if (!_jdcResult.skills) _jdcResult.skills = [];
            if (!_jdcResult.values) _jdcResult.values = [];
            if (!_jdcResult.certifications) _jdcResult.certifications = [];
            if (!_jdcResult.qualifications) _jdcResult.qualifications = [];
            if (!_jdcResult.yearsRequired) _jdcResult.yearsRequired = [];
            if (!_jdcResult.education) _jdcResult.education = [];
            if (!_jdcResult.customFields) _jdcResult.customFields = [];
            _wbRepoRenderEditModal();
        }
        window.wbRepoEditModal = wbRepoEditModal;

        function _wbRepoRenderEditModal() {
            var container = document.getElementById('adminTabContent');
            if (!container) return;
            var formHtml = '<div id="wbRepoEditOverlay" style="max-width:900px;">'
                + renderJDCEditForm(_jdcResult, {
                    saveFn: 'wbRepoEditSave()',
                    cancelFn: 'wbRepoEditCancel()',
                    refreshFn: '_wbRepoModalRefresh()',
                    saveLabel: 'Save',
                    showBottomRow: false
                })
                + '</div>';
            container.innerHTML = formHtml;
        }

        function _wbRepoModalRefresh() {
            _wbRepoRenderEditModal();
        }
        window._wbRepoModalRefresh = _wbRepoModalRefresh;

        function wbRepoEditSave() {
            _jdcSyncFormToState();
            if (!_jdcResult || !fbUser) return;
            if (_jdcSaving) return;
            _jdcSaving = true;
            var d = _jdcPrepareExport();
            d.savedAt = firebase.firestore.FieldValue.serverTimestamp();
            d.savedBy = fbUser.uid;
            d.id = d.id || _wbRepoCache[_wbRepoEditIdx].id;
            showToast('Saving...', 'info', 2000);
            fbDb.collection('users').doc(fbUser.uid).collection('work_blueprints').doc(d.id).set(d, { merge: true })
                .then(function() {
                    _jdcSaving = false;
                    showToast('Work Blueprint saved.', 'success');
                    logAnalyticsEvent('wb_edited', { title: d.title || '', company: d.company || '', source: 'repo_modal' });
                    wbRepoEditCancel();
                    _wbRepoCache = null;
                    renderAdminWBRepo(document.getElementById('adminTabContent'));
                })
                .catch(function(err) {
                    _jdcSaving = false;
                    console.warn('Save blueprint error:', err);
                    showToast('Failed to save: ' + err.message, 'error');
                });
        }
        window.wbRepoEditSave = wbRepoEditSave;

