        // ===== WAITLIST MODAL =====
        function showWaitlist(source) {
            var overlay = document.getElementById('waitlistOverlay');
            if (!overlay) return;
            
            // If already waitlisted, show confirmation view
            if (appMode === 'waitlisted') {
                var _wfv = document.getElementById('waitlistFormView'); if (_wfv) _wfv.style.display = 'none';
                var _wcv = document.getElementById('waitlistConfirmView'); if (_wcv) _wcv.style.display = 'block';
                var _wpm = document.getElementById('wlPositionMsg'); if (_wpm) _wpm.textContent = 'You\u2019re #' + (waitlistPosition || '?') + ' on the waitlist.';
                var _wpb = document.getElementById('wlPositionBadge'); if (_wpb) _wpb.textContent = '\u25C8 Position #' + (waitlistPosition || '?');
            } else {
                var _wfv2 = document.getElementById('waitlistFormView'); if (_wfv2) _wfv2.style.display = 'block';
                var _wcv2 = document.getElementById('waitlistConfirmView'); if (_wcv2) _wcv2.style.display = 'none';
            }
            
            overlay.classList.add('active');
            var nameInput = document.getElementById('wlName');
            if (nameInput && !nameInput.value) setTimeout(function() { nameInput.focus(); }, 200);
        }
        window.showWaitlist = showWaitlist;
        
        function closeWaitlist() {
            var overlay = document.getElementById('waitlistOverlay');
            if (overlay) overlay.classList.remove('active');
        }
        window.closeWaitlist = closeWaitlist;
        
        var _wlLastSubmit = 0;
        function submitWaitlist() {
            var now = Date.now();
            if (now - _wlLastSubmit < 30000) {
                showToast('Please wait before submitting again.', 'warning');
                return;
            }
            var name = (document.getElementById('wlName').value || '').trim();
            var email = (document.getElementById('wlEmail').value || '').trim();
            var type = document.getElementById('wlType').value;
            
            if (!name || !email) {
                showToast('Please enter your name and email.', 'warning');
                return;
            }
            if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
                showToast('Please enter a valid email address.', 'warning');
                return;
            }
            _wlLastSubmit = now;
            
            var btn = document.getElementById('wlSubmitBtn');
            btn.disabled = true;
            btn.textContent = 'Joining...';
            
            // Use timestamp-based position (admin sees real order via createdAt)
            var position = Date.now() % 1000;
            if (position < 10) position += 10;
            
            // Write-only — no read needed (rules allow unauthenticated create)
            if (fbDb) {
                fbDb.collection('waitlist').doc(email.toLowerCase().replace(/[^a-z0-9]/g, '_')).set({
                    name: name,
                    email: email.toLowerCase(),
                    type: type || 'individual',
                    status: 'waiting',
                    position: position,
                    source: 'app',
                    createdAt: firebase.firestore.FieldValue.serverTimestamp()
                }).then(function() {
                    onWaitlistSuccess(name, email, position);
                }).catch(function(err) {
                    console.warn('Firestore waitlist error, using localStorage:', err);
                    onWaitlistSuccess(name, email, position);
                });
            } else {
                onWaitlistSuccess(name, email, position);
            }
        }
        window.submitWaitlist = submitWaitlist;
        
        function onWaitlistSuccess(name, email, position) {
            waitlistPosition = position;
            waitlistEmail = email;
            appMode = 'waitlisted';
            
            // Persist
            safeSet('blueprint_waitlist', JSON.stringify({
                name: name,
                email: email,
                status: 'waiting',
                position: position,
                joinedAt: new Date().toISOString()
            }));
            
            // Update UI
            var _wfv3 = document.getElementById('waitlistFormView'); if (_wfv3) _wfv3.style.display = 'none';
            var _wcv3 = document.getElementById('waitlistConfirmView'); if (_wcv3) _wcv3.style.display = 'block';
            var _wpm2 = document.getElementById('wlPositionMsg'); if (_wpm2) _wpm2.textContent = 'You\u2019re #' + position + ' on the waitlist. We\u2019ll notify you when it\u2019s your turn.';
            var _wpb2 = document.getElementById('wlPositionBadge'); if (_wpb2) _wpb2.textContent = '\u25C8 Position #' + position;
            
            var btn = document.getElementById('wlSubmitBtn');
            if (btn) { btn.disabled = false; btn.textContent = 'Join the Waitlist'; }
            
            // Update readonly banner with profile name
            var banner = document.getElementById('readonlyBanner');
            if (banner) {
                var pName = (userData.profile && userData.profile.name) || 'Sample Profile';
                banner.innerHTML = bpIcon('lock', 14) + ' <strong>Viewing: ' + escapeHtml(pName) + '</strong> \u00B7 Sample profile. You\u2019re #' + position + ' on the waitlist.';
            }
            
            showToast('Welcome, ' + escapeHtml(name) + '! You\u2019re #' + position + ' on the waitlist.', 'success');
        }
        
        // Check if waitlisted user has been invited (on app load)
        // Note: requires admin read access — only works when user is signed in as admin
        // For regular waitlisted users, invite status is checked via localStorage update
        function checkWaitlistInviteStatus() {
            if (appMode !== 'waitlisted' || !waitlistEmail || !fbDb) return;
            
            var docId = waitlistEmail.toLowerCase().replace(/[^a-z0-9]/g, '_');
            fbDb.collection('waitlist').doc(docId).get().then(function(doc) {
                if (doc.exists) {
                    var data = doc.data();
                    if (data.status === 'invited') {
                        appMode = 'invited';
                        safeSet('blueprint_waitlist', JSON.stringify({
                            name: data.name,
                            email: data.email,
                            status: 'invited',
                            position: data.position
                        }));
                        
                        showToast('You\u2019ve been invited! Full access is now unlocked.', 'success');
                        var banner = document.getElementById('readonlyBanner');
                        if (banner) banner.style.display = 'none';
                        renderWelcomePage();
                    }
                }
            }).catch(function(e) { /* Expected for non-admin users */ });
        }
        
