                var labelToggles2 = document.getElementById('networkLabelToggles');
                if (labelToggles2) labelToggles2.style.display = 'none';
                // Lazy-init card view if needed (e.g. after profile switch)
                if (!window.cardViewInitialized) {
                    initCardView();
                    window.cardViewInitialized = true;
                }
                // Hide filter button/panel in card view (removed for cleaner UX)
