                // Hide network filter pill in card view
                var nfPill2 = document.getElementById('networkFilterPill');
                if (nfPill2) nfPill2.style.display = 'none';
                // Remove network overlay elements (fixed-position tiles from job match)
                var _jit = document.getElementById('jobInfoTile'); if (_jit) _jit.remove();
                var _ml = document.getElementById('matchLegend'); if (_ml) _ml.remove();
                var _vap = document.getElementById('valuesAlignmentPanel'); if (_vap) _vap.remove();
                var _ric = document.getElementById('roleInfoCard'); if (_ric) _ric.style.display = 'none';
                var _mnb = document.getElementById('mobileNetworkBadge'); if (_mnb) _mnb.remove();
                var _jsd = document.getElementById('jobSelectorDropdown'); if (_jsd) _jsd.remove();
