            // Try to extract company from common patterns
            var companyMatch = jdText.match(/(?:company|employer|organization|at)\s*[:|\-]?\s*([A-Z][A-Za-z0-9\s&.,]+)/);
            if (companyMatch) company = companyMatch[1].trim().substring(0, 60);
